-- Poems batch 393
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-772','渔家傲','苏轼','宋','宋词','song-ci','渔家傲','[]','临水纵横回晚鞚。',72,'宋词/ci.song.1000.json','["临水纵横回晚鞚。", "归来转觉情怀动。", "梅笛烟中闻几弄。", "秋阴重。", "西山雪淡云凝冻。", "美酒一杯谁与共。", "尊前舞雪狂歌送。", "腰跨金鱼旌旆拥。", "将何用。", "只堪妆点浮生梦。"]'),
('song-ci-773','江城子','苏轼','宋','宋词','song-ci','江城子','[]','腻红匀脸衬檀唇。',86,'宋词/ci.song.1000.json','["腻红匀脸衬檀唇。", "晚妆新。", "暗伤春。", "手拈花枝，谁会两眉颦。", "连理带头双□□，留待与、个中人。", "淡烟笼月绣帘阴。", "画堂深。", "夜沈沈。", "谁道□□，□系得人心。", "一自绿窗偷见后，便憔悴、到如今。"]'),
('song-ci-774','祝英台近','苏轼','宋','宋词','song-ci','祝英台近','[]','挂轻帆，飞急桨，还过钓台路。',95,'宋词/ci.song.1000.json','["挂轻帆，飞急桨，还过钓台路。", "酒病无聊，敧枕听鸣橹。", "断肠簇簇云山，重重烟树，回首望、孤城何处。", "闲离阻。", "谁念萦损襄王，何曾梦云雨。", "旧恨前欢，心事两无据。", "要知欲见无由，痴心犹自，倩人道、一声传语。"]'),
('song-ci-775','雨中花慢','苏轼','宋','宋词','song-ci','雨中花慢','[]','邃院重帘何处，惹得多情，愁对风光。',119,'宋词/ci.song.1000.json','["邃院重帘何处，惹得多情，愁对风光。", "睡起酒阑花谢，蝶乱蜂忙。", "今夜何人，吹笙北岭，待月西厢。", "空怅望处，一株红杏，斜倚低墙。", "羞颜易变，傍人先觉，到处被著猜防。", "谁信道，些儿恩爱，无限凄凉。", "好事若无间阻，幽欢却是寻常。", "一般滋味，就中香美，除是偷尝。"]'),
('song-ci-776','雨中花慢','苏轼','宋','宋词','song-ci','雨中花慢','[]','嫩脸羞蛾，因甚化作行云，却返巫阳。',120,'宋词/ci.song.1000.json','["嫩脸羞蛾，因甚化作行云，却返巫阳。", "但有寒灯孤枕，皓月空床。", "长记当初，乍谐云雨，便学鸾凰。", "又岂料、正好三春桃李，一夜风霜。", "丹青□画，无言无笑，看了漫结愁肠。", "襟袖上，犹存残黛，渐减馀香。", "一自醉中忘了，奈何酒后思量。", "算应付你，枕前珠泪，万点千行。"]'),
('song-ci-777','念奴娇','苏轼','宋','宋词','song-ci','念奴娇','[]','凭高眺远，见长空万里，云无留迹。',120,'宋词/ci.song.1000.json','["凭高眺远，见长空万里，云无留迹。", "桂魄飞来光射处，冷浸一天秋碧。", "玉宇琼楼，乘鸾来去，人在清凉国。", "江山如画，望中烟树历历。", "我醉拍手狂歌，举杯邀月，对影成三客。", "起舞徘徊风露下，今夕不知何夕。", "便欲乘风，翻然归去，何用骑鹏翼。", "水晶宫里，一声吹断横笛。"]'),
('song-ci-778','水龙吟','苏轼','宋','宋词','song-ci','水龙吟','["\u957f\u6c5f"]','小沟东接长江，柳堤苇岸连云际。',126,'宋词/ci.song.1000.json','["小沟东接长江，柳堤苇岸连云际。", "烟村潇洒，人闲一哄，渔樵早市。", "永昼端居，寸阴虚度，了成何事。", "但丝莼玉藕，珠粳锦鲤，相留恋，又经岁。", "因念浮丘旧侣，惯瑶池、羽觞沈醉。", "青鸾歌舞，铢衣摇曳，壶中天地。", "飘堕人间，步虚声断，寒露风细。", "抱素琴，独向银蟾影里，此怀难寄。"]'),
('song-ci-779','水龙吟','苏轼','宋','宋词','song-ci','水龙吟','[]','露寒烟冷蒹葭老，天外征鸿寥唳。',126,'宋词/ci.song.1000.json','["露寒烟冷蒹葭老，天外征鸿寥唳。", "银河秋晚，长门灯悄，一声初至。", "应念潇湘，岸遥人静，水多菰米。", "□望极平田，徘徊欲下，依前被、风惊起。", "须信衡阳万里。", "有谁家、锦书遥寄。", "万重云外，斜行横阵，才疏又缀。", "仙掌月明，石头城下，影摇寒水。", "念征衣未捣，佳人拂杵，有盈盈泪。"]'),
('song-ci-780','渔父・渔歌子','苏轼','宋','宋词','song-ci','渔父・渔歌子','[]','渔父饮，谁家去。',30,'宋词/ci.song.1000.json','["渔父饮，谁家去。", "鱼蟹一时分付。", "酒无多少醉为期，彼此不论钱数。"]'),
('song-ci-781','渔父・渔歌子','苏轼','宋','宋词','song-ci','渔父・渔歌子','[]','渔父醉，蓑衣舞。',30,'宋词/ci.song.1000.json','["渔父醉，蓑衣舞。", "醉里却寻归路。", "轻舟短棹任斜横，醒后不知何处。"]'),
('song-ci-782','渔父・渔歌子','苏轼','宋','宋词','song-ci','渔父・渔歌子','[]','渔父醒，春江午。',30,'宋词/ci.song.1000.json','["渔父醒，春江午。", "梦断落花飞絮。", "酒醒还醉醉还醒，一笑人间今古。"]'),
('song-ci-783','渔父・渔歌子','苏轼','宋','宋词','song-ci','渔父・渔歌子','[]','渔父笑，轻鸥举。',30,'宋词/ci.song.1000.json','["渔父笑，轻鸥举。", "漠漠一江风雨。", "江边骑马是官人，借我孤舟南渡。"]'),
('song-ci-784','醉翁操','苏轼','宋','宋词','song-ci','醉翁操','[]','琅然。',111,'宋词/ci.song.1000.json','["琅然。", "清圜。", "谁弹。", "响空山。", "无言。", "惟翁醉中知其天。", "月明风露娟娟。", "人未眠。", "荷蒉过山前。", "曰有心也哉此贤。", "醉翁啸咏，声和流泉。", "醉翁去后，空有朝吟夜怨。", "山有时而童巅。", "水有时而回川。", "思翁无岁年。", "翁今为飞仙。", "此意在人间。", "拭听徽外三两弦。"]'),
('song-ci-785','导引','苏轼','宋','宋词','song-ci','导引','[]','帝城父老，三岁望尧心。',59,'宋词/ci.song.1000.json','["帝城父老，三岁望尧心。", "天远玉楼深。", "龙颜仿佛笙箫远，肠断属车音。", "离宫春色琐瑶林。", "云阙海沈沈。", "遗民犹唱当时曲，秋雁起汾阴。"]'),
('song-ci-786','导引','苏轼','宋','宋词','song-ci','导引','[]','经文纬武，十有九年中。',59,'宋词/ci.song.1000.json','["经文纬武，十有九年中。", "遗烈震羌戎。", "渭桥夹道千君长，犹是建元功。", "西瞻温洛与神崧。", "莲宇照琼宫。", "人间俯仰成今古，流泽自无穷。"]'),
('song-ci-787','瑶池燕','苏轼','宋','宋词','song-ci','瑶池燕','[]','飞花成阵。',65,'宋词/ci.song.1000.json','["飞花成阵。", "春心困。", "寸寸。", "别肠多少愁闷。", "无人问。", "偷啼自搵。", "残妆粉。", "抱瑶琴、寻出新韵。", "玉纤趁。", "南风来解幽愠。", "低云鬟、眉峰敛晕。", "娇和恨。"]'),
('song-ci-788','千秋岁','苏轼','宋','宋词','song-ci','千秋岁','[]','岛边天外。',87,'宋词/ci.song.1000.json','["岛边天外。", "未老身先退。", "珠泪溅，丹衷碎。", "声摇苍玉佩。", "色重黄金带。", "一万里。", "斜阳正与长安对。", "道远谁云会。", "罪大天能盖。", "君命重，臣节在。", "新恩犹可觊。", "旧学终难改。", "吾已矣。", "乘桴且恁浮於海。"]'),
('song-ci-789','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','["\u897f\u6e56"]','凭谁妙笔。',52,'宋词/ci.song.1000.json','["凭谁妙笔。", "横扫素缣三百尺。", "天下应无。", "此是钱塘湖上图。", "一般奇绝。", "云淡天高秋夜月。", "费尽丹青。", "只这些儿画不成。"]'),
('song-ci-790','失调名','苏轼','宋','宋词','song-ci','失调名','[]','高安更过几重山。',8,'宋词/ci.song.1000.json','["高安更过几重山。"]'),
('song-ci-791','失调名','苏轼','宋','宋词','song-ci','失调名','[]','过湖携手屡沾襟。',8,'宋词/ci.song.1000.json','["过湖携手屡沾襟。"]'),
('song-ci-792','失调名','苏轼','宋','宋词','song-ci','失调名','[]','谁教幽梦里，插他花。',10,'宋词/ci.song.1000.json','["谁教幽梦里，插他花。"]'),
('song-ci-793','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','湿云不动溪桥冷。',52,'宋词/ci.song.1000.json','["湿云不动溪桥冷。", "嫩寒初透东风影。", "桥下水声长。", "一枝和月香。", "人怜花似旧。", "花比人应瘦。", "莫凭小栏干。", "夜深花正寒。"]'),
('song-ci-794','踏青游','苏轼','宋','宋词','song-ci','踏青游','[]','□火初晴，绿遍禁池芳草。',101,'宋词/ci.song.1000.json','["□火初晴，绿遍禁池芳草。", "斗锦绣、火城驰道。", "踏青游，拾翠惜，袜罗弓小。", "莲步袅。", "腰支佩兰轻妙。", "行过上林春好。", "今困天涯，何限旧情相恼。", "念摇落、玉京寒早。", "任刘郎、目断蓬山难到。", "仙梦杳。", "良宵又过了。", "楼台万家清晓。"]'),
('song-ci-795','阮郎归','苏轼','宋','宋词','song-ci','阮郎归','[]','歌停檀板舞停鸾。',56,'宋词/ci.song.1000.json','["歌停檀板舞停鸾。", "高阳饮兴阑。", "兽烟喷尽玉壶乾。", "香分小凤团。", "雪浪浅，露珠圆。", "捧瓯春笋寒。", "绛纱笼下跃金鞍。", "归时人倚栏。"]'),
('song-ci-796','西江月','苏轼','宋','宋词','song-ci','西江月','[]','马趁香微路远，沙笼月淡烟斜。',58,'宋词/ci.song.1000.json','["马趁香微路远，沙笼月淡烟斜。", "渡波清彻映妍华。", "倒绿枝寒凤挂。", "挂凤寒枝绿倒，华妍映彻清波。", "渡斜烟淡月笼沙。", "远路微香趁马。"]'),
('song-ci-797','失调名','苏轼','宋','宋词','song-ci','失调名','[]','拼沈醉、金荷须满。',25,'宋词/ci.song.1000.json','["拼沈醉、金荷须满。", "怕年年此际，催归禁篽，侍黄柑宴。"]'),
('song-ci-798','踏莎行','苏轼','宋','宋词','song-ci','踏莎行','[]','山秀芙蓉，溪明罨画。',68,'宋词/ci.song.1000.json','["山秀芙蓉，溪明罨画。", "真游洞穴沧波下。", "临风慨想斩蛟灵，长桥千载犹横跨。", "解佩投簪，求田问舍。", "黄鸡白酒渔樵社。", "元龙非复少时豪，耳根洗尽功名话。"]'),
('song-ci-799','踏莎行','苏轼','宋','宋词','song-ci','踏莎行','[]','这个秃奴，修行忒煞。',68,'宋词/ci.song.1000.json','["这个秃奴，修行忒煞。", "云山顶上空持戒。", "一从迷恋玉楼人，鹑衣百结浑无奈。", "毒手伤人，花容粉碎。", "空空色色今何在。", "臂间刺道苦相思，这回还了相思债。"]'),
('song-ci-800','失调名','苏轼','宋','宋词','song-ci','失调名','[]','寂寂珠帘蛛网满。',8,'宋词/ci.song.1000.json','["寂寂珠帘蛛网满。"]'),
('song-ci-801','定风波','苏轼','宋','宋词','song-ci','定风波','[]','闲卧藤床观社柳。',8,'宋词/ci.song.1000.json','["闲卧藤床观社柳。"]'),
('song-ci-802','定风波','苏轼','宋','宋词','song-ci','定风波','[]','子瞻书困点新茶。',8,'宋词/ci.song.1000.json','["子瞻书困点新茶。"]'),
('song-ci-803','失调名','苏轼','宋','宋词','song-ci','失调名','[]','唤起离情，慵推孤枕。',10,'宋词/ci.song.1000.json','["唤起离情，慵推孤枕。"]'),
('song-ci-804','失调名','苏轼','宋','宋词','song-ci','失调名','[]','山头望，波光泼眼。',9,'宋词/ci.song.1000.json','["山头望，波光泼眼。"]'),
('song-ci-805','水调歌・水调','苏轼','宋','宋词','song-ci','水调歌・水调','[]','我歌月徘徊，我舞影凌乱。',12,'宋词/ci.song.1000.json','["我歌月徘徊，我舞影凌乱。"]'),
('song-ci-806','失调名','苏轼','宋','宋词','song-ci','失调名','[]','揭起裙儿，一阵油盐酱醋香。',13,'宋词/ci.song.1000.json','["揭起裙儿，一阵油盐酱醋香。"]'),
('song-ci-807','鹧鸪天','苏轼','宋','宋词','song-ci','鹧鸪天','[]','罗带双垂画不成。',64,'宋词/ci.song.1000.json','["罗带双垂画不成。", "殢人娇态最轻盈。", "酥胸斜抱天边月，玉手轻弹水面冰。", "无限事，许多情。", "四弦丝竹苦丁宁。", "饶君拨尽相思调，待听梧桐叶落声。"]'),
('song-ci-808','西江月','苏轼','宋','宋词','song-ci','西江月','[]','碧雾轻笼两凤，寒烟淡拂双鸦。',58,'宋词/ci.song.1000.json','["碧雾轻笼两凤，寒烟淡拂双鸦。", "为谁流睇不归家。", "错认门前过马。", "有意偷回笑眼，无言强整衣纱。", "刘郎一见武陵花。", "从此春心荡也。"]'),
('song-ci-809','夜行船','赵','宋','宋词','song-ci','夜行船','[]','今夜阴云初霁。',65,'宋词/ci.song.1000.json','["今夜阴云初霁。", "画帘外、月华如水。", "露霭晴空，风吹高树，满院中秋意。", "皎皎蟾光当此际。", "怎奈何、不成况味。", "莫近檐间，休来窗上，且放离人睡。"]'),
('song-ci-810','河传','郭讵','宋','宋词','song-ci','河传','[]','大官无闷。',67,'宋词/ci.song.1000.json','["大官无闷。", "刚被傍人、竟来相问。", "又难为□□敷臣。", "且只将、甘草论。", "朴消大戟并银粉。", "疏风紧。", "甘草闲相混。", "及至下来，转杀他人。", "尔甘草、有一分。"]'),
('song-ci-811','水龙吟','李之仪','宋','宋词','song-ci','水龙吟','[]','晚来轻拂，游云尽卷，霁色寒相射。',127,'宋词/ci.song.1000.json','["晚来轻拂，游云尽卷，霁色寒相射。", "银潢半掩，秋毫欲数，分明不夜。", "玉琯传声，羽衣催舞，此欢难借。", "凛清辉，但觉圆光照影，冰壶莹、真无价。", "闻道水晶宫殿，蕙炉薰、珠帘高挂。", "琼枝半倚，瑶觞更劝，莺娇燕姹。", "目断魂飞，翠萦红绕，空吟小砑。", "想归来醉里，鸾篦凤朵，倩何人卸。"]'),
('song-ci-812','蓦山溪','李之仪','宋','宋词','song-ci','蓦山溪','[]','神仙院宇，记得春归后。',102,'宋词/ci.song.1000.json','["神仙院宇，记得春归后。", "蜂蝶不胜闲，惹残香、萦纡深透。", "玉徽指稳，别是一般情，方永昼。", "因谁瘦。", "都为天然秀。", "桐阴未减，独自携芳酎。", "再弄想前欢，拊金樽、何时似旧。", "凭谁说与，潘鬓转添霜，飞陇首。", "云将皱。", "应念相思久。"]'),
('song-ci-813','蓦山溪','李之仪','宋','宋词','song-ci','蓦山溪','[]','金柔火老，欲避几无地。',102,'宋词/ci.song.1000.json','["金柔火老，欲避几无地。", "谁借一檐风，锁幽香、愔愔清邃。", "瑶阶珠砌，如膜遇金篦，流水外，落花前，岂是人能致。", "擘鳞泛玉，笑语皆真类。", "惆怅月边人，驾云軿、何方适意。", "么弦咽处，空感旧时声，兰易歇，恨偏长，魂断成何事。"]'),
('song-ci-814','蓦山溪','李之仪','宋','宋词','song-ci','蓦山溪','[]','蛾眉亭上，今日交冬至。',102,'宋词/ci.song.1000.json','["蛾眉亭上，今日交冬至。", "已报一阳生，更佳雪、因时呈瑞。", "匀飞密舞，都是散天花，山不见，水如山，浑在冰壶里。", "平生选胜，到此非容易。", "弄月与燃犀，漫劳神、徒能惊世。", "争如此际，天意巧相符，须痛饮，庆难逢，莫诉厌厌醉。"]'),
('song-ci-815','蓦山溪','李之仪','宋','宋词','song-ci','蓦山溪','[]','晚来寒甚，密雪穿庭户。',102,'宋词/ci.song.1000.json','["晚来寒甚，密雪穿庭户。", "如在广寒宫，惊满目、瑶林琼树。", "佳人乘兴，应是得欢多，泛新声，催金盏，别有留心处。", "争知这里，没个人言语。", "拨尽火边灰，搅愁肠、飞花舞絮。", "凭谁子细，说与此时情，欢暂歇，酒微醺，还解相思否。"]'),
('song-ci-816','满庭芳','李之仪','宋','宋词','song-ci','满庭芳','[]','一到江南，三逢此夜，举头羞见婵娟。',118,'宋词/ci.song.1000.json','["一到江南，三逢此夜，举头羞见婵娟。", "黯然怀抱，特地遣谁宽。", "分外清光泼眼，迷滉漾、无计拘拦。", "天如洗，星河尽掩，全胜异时看。", "佳人，还忆否，年时此际，相见方难。", "谩红绫偷寄，孤被添寒。", "何事佳期再睹，翻怅望、重叠关山。", "归来呵，休教独自，肠断对团圆。"]'),
('song-ci-817','满庭芳','李之仪','宋','宋词','song-ci','满庭芳','[]','花陌千条，珠帘十里，梦中还是扬州。',118,'宋词/ci.song.1000.json','["花陌千条，珠帘十里，梦中还是扬州。", "月斜河汉，曾记醉歌楼。", "谁赋红绫小砑，因飞絮、天与风流。", "春常在，仙源路隔，空自泛渔舟。", "新秋。", "初雨过，龙团细碾，雪乳浮瓯。", "问殷勤何处，特地相留。", "应念长门赋罢，消渴甚、无物堪酬。", "情无尽，金扉玉榜，何日许重游。"]'),
('song-ci-818','玉蝴蝶','李之仪','宋','宋词','song-ci','玉蝴蝶','[]','坐久灯花开尽，暗惊风叶，初报霜寒。',123,'宋词/ci.song.1000.json','["坐久灯花开尽，暗惊风叶，初报霜寒。", "冉冉年华催暮，颜色非丹。", "搅回肠、蛩吟似织，留恨意、月彩如摊。", "惨无欢。", "篆烟萦素，空转雕盘。", "何难。", "别来几日，信沈鱼鸟，情满关山。", "耳边依约，常记巧语绵蛮。", "聚愁窠、蜂房未密，倾泪眼、海水犹悭。", "奄更阑。", "渐移银汉，低泛帘颜。"]'),
('song-ci-819','早梅芳・喜迁莺','李之仪','宋','宋词','song-ci','早梅芳・喜迁莺','[]','雪初销，斗觉寒将变。',100,'宋词/ci.song.1000.json','["雪初销，斗觉寒将变。", "已报梅梢暖。", "日边霜外，迤逦枝条自柔软。", "嫩苞匀点缀，绿萼轻裁剪。", "隐深心，未许清香散。", "渐融和，开欲遍。", "密处疑无间。", "天然标韵，不与群花斗深浅。", "夕阳波似动，曲水风犹懒。", "最销魂，弄影无人见。"]'),
('song-ci-820','谢池春','李之仪','宋','宋词','song-ci','谢池春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','残寒销尽，疏雨过、清明后。',112,'宋词/ci.song.1000.json','["残寒销尽，疏雨过、清明后。", "花径敛馀红，风沼萦新皱。", "乳燕穿庭户，飞絮沾襟袖。", "正佳时，仍晚昼。", "著人滋味，真个浓如酒。", "频移带眼，空只恁、厌厌瘦。", "不见又思量，见了还依旧。", "为问频相见，何似长相守。", "天不老，人未偶。", "且将此恨，分付庭前柳。"]'),
('song-ci-821','怨三三','李之仪','宋','宋词','song-ci','怨三三','[]','清溪一派泻揉蓝。',61,'宋词/ci.song.1000.json','["清溪一派泻揉蓝。", "岸草毵毵。", "记得黄鹂语画檐。", "唤狂里、醉重三。", "春风不动垂帘。", "似三五、初圆素蟾。", "镇泪眼廉纤。", "何时歌舞，再和池南。"]'),
('song-ci-822','春光好','李之仪','宋','宋词','song-ci','春光好','[]','霜压晓，月收阴。',50,'宋词/ci.song.1000.json','["霜压晓，月收阴。", "斗寒深。", "看尽烛花金鸭冷，卷残衾。", "卯酒从谁细酌，馀香无计重寻。", "空把夜来相见梦，写文琴。"]'),
('song-ci-823','千秋岁','李之仪','宋','宋词','song-ci','千秋岁','[]','深帘静昼。',87,'宋词/ci.song.1000.json','["深帘静昼。", "绰约闺房秀。", "叩衣楚制飞文绣。", "凝脂肤理腻，削玉腰围瘦。", "闲舞袖。", "回身昵语凭肩久。", "眉压横波皱。", "歌断青青柳。", "钗遽擘，壶频叩。", "鬓凄清镜雪，泪涨芳樽酒。", "难再偶。", "沈沈梦峡雪归后。"]'),
('song-ci-824','千秋岁','李之仪','宋','宋词','song-ci','千秋岁','[]','柔肠寸折。',87,'宋词/ci.song.1000.json','["柔肠寸折。", "解袂留清血。", "蓝桥动是经年别。", "掩门春絮乱，敧枕秋蛩咽。", "檀篆灭。", "鸳衾半拥空床月。", "妆镜分来缺。", "尘污菱花洁。", "嘶骑远，鸣机歇。", "密封书锦字，巧绾香囊结。", "芳信绝。", "东风半落梅梢雪。"]'),
('song-ci-825','千秋岁','李之仪','宋','宋词','song-ci','千秋岁','[]','万红暄昼。',87,'宋词/ci.song.1000.json','["万红暄昼。", "占尽人间秀。", "怎生图画如何绣。", "宜推萧史伴，消得东阳瘦。", "垂窄袖。", "花前镇忆相携久。", "泪裛回纹皱。", "好在章台柳。", "洞户隔，凭谁叩。", "寄声虽有雁，会面难同酒。", "无计偶。", "萧萧暮雨黄昏后。"]'),
('song-ci-826','千秋岁','李之仪','宋','宋词','song-ci','千秋岁','[]','休嗟磨折。',87,'宋词/ci.song.1000.json','["休嗟磨折。", "看取罗巾血。", "殷勤且话经年别。", "庭花番怅望，檐雨同呜咽。", "明半灭。", "灯光夜夜多如月。", "无复伤离缺。", "共保冰霜洁。", "不断梦，从今歇。", "收回书上絮，解尽眉头结。", "犹未绝。", "金徽泛处应能雪。"]'),
('song-ci-827','千秋岁','李之仪','宋','宋词','song-ci','千秋岁','[]','中秋才过，又是重阳到。',87,'宋词/ci.song.1000.json','["中秋才过，又是重阳到。", "露乍冷，寒将报。", "绿香摧渚芰，黄密攒庭草。", "人未老。", "蓝桥漫促霜砧捣。", "照影兰缸晕，破户银蟾小。", "樽在眼，从谁倒。", "强铺同处被，愁却欢时帽。", "须信道。", "狂心未歇情难老。"]'),
('song-ci-828','千秋岁','李之仪','宋','宋词','song-ci','千秋岁','[]','深秋庭院，残暑全消退。',87,'宋词/ci.song.1000.json','["深秋庭院，残暑全消退。", "天幕迥，云容碎。", "地偏人罕到，风惨寒微带。", "初睡起，翩翩戏蝶飞成对。", "叹息谁能会。", "犹记逢倾盖。", "情暂遣，心常在。", "沈沈音信断，冉冉光阴改。", "红日晚，仙山路隔空云海。"]'),
('song-ci-829','临江仙','李之仪','宋','宋词','song-ci','临江仙','[]','知有阆风花解语，从来只许传闻。',70,'宋词/ci.song.1000.json','["知有阆风花解语，从来只许传闻。", "光明休咏汉宫新。", "拥身疑有月，衬步恨无云。", "莫把金樽容易劝，坐来几度销魂。", "不知仙骨在何人。", "好将千岁日，占断四时春。"]'),
('song-ci-830','临江仙','李之仪','宋','宋词','song-ci','临江仙','[]','九十日春都过了，寻常偶到江皋。',70,'宋词/ci.song.1000.json','["九十日春都过了，寻常偶到江皋。", "水容山态两相饶。", "草平天一色，风暖燕双高。", "酒病厌厌何计那，飞红更送无聊。", "莺声又似耳边娇。", "难回巫峡梦，空恨武陵桃。"]'),
('song-ci-831','江神子・江城子','李之仪','宋','宋词','song-ci','江神子・江城子','[]','恼人天气雪消时。',86,'宋词/ci.song.1000.json','["恼人天气雪消时。", "落梅飞。", "日初迟。", "小阁幽窗，时节听黄鹂。", "新洗头来娇困甚，才试著，夹罗衣。", "木梨花拂淡燕脂。", "翠云敧。", "敛双眉。", "月浅星深，天淡玉绳低。", "不道有人肠断也，浑不语，醉如痴。"]'),
('song-ci-832','江神子・江城子','李之仪','宋','宋词','song-ci','江神子・江城子','[]','今宵莫惜醉颜红。',86,'宋词/ci.song.1000.json','["今宵莫惜醉颜红。", "十分中。", "且从容。", "须信欢情，回首似旋风。", "流落天涯头白也，难得是，再相逢。", "十年南北感征鸿。", "恨应同。", "苦重重。", "休把愁怀，容易便书空。", "只有琴樽堪寄老，除此外，尽蒿蓬。"]'),
('song-ci-833','江神子・江城子','李之仪','宋','宋词','song-ci','江神子・江城子','[]','阑干掐遍等新红。',86,'宋词/ci.song.1000.json','["阑干掐遍等新红。", "酒频中。", "恨匆匆。", "投得花开，还报夜来风。", "惆怅春光留不住，又何似，莫相逢。", "月窗何处想归鸿。", "与谁同。", "意千重。", "婉思柔情，一旦总成空。", "仿佛么弦犹在耳，应为我，首如蓬。"]'),
('song-ci-834','清平乐','李之仪','宋','宋词','song-ci','清平乐','[]','西江霜后，万点暄晴昼。',54,'宋词/ci.song.1000.json','["西江霜后，万点暄晴昼。", "璀璨寄来光欲溜。", "正值文君病酒。", "画屏斜倚窗纱。", "睡痕犹带朝霞。", "为问清香绝韵，何如解语梅花。"]'),
('song-ci-835','清平乐','李之仪','宋','宋词','song-ci','清平乐','[]','萧萧风叶。',54,'宋词/ci.song.1000.json','["萧萧风叶。", "似与更声接。", "欲寄明珰非为怯。", "梦断兰舟桂楫。", "学书只写鸳鸯。", "却应无奈愁肠。", "安得一双飞去，春风芳草池塘。"]'),
('song-ci-836','清平乐','李之仪','宋','宋词','song-ci','清平乐','[]','殷勤仙友。',54,'宋词/ci.song.1000.json','["殷勤仙友。", "劝我千年酒。", "一曲履霜谁与奏。", "邂逅麻姑妙手。", "坐来休叹尘劳。", "相逢难似今朝。", "不待亲移玉指，自然痒处都消。"]'),
('song-ci-837','清平乐','李之仪','宋','宋词','song-ci','清平乐','[]','当时命友。',54,'宋词/ci.song.1000.json','["当时命友。", "曾借邻家酒。", "旧曲不知何处奏。", "梦断空思纤手。", "却应去路非遥。", "今朝还有明朝。", "谩道人能化石，须知石被人消。"]'),
('song-ci-838','清平乐','李之仪','宋','宋词','song-ci','清平乐','[]','仙家庭院。',54,'宋词/ci.song.1000.json','["仙家庭院。", "红日看看晚。", "一朵梅花挨枕畔。", "玉指几回拈看。", "拥衾不比寻常。", "天涯无限思量。", "看了又还重嗅，分明不为清香。"]'),
('song-ci-839','浪淘沙','李之仪','宋','宋词','song-ci','浪淘沙','[]','霞卷与云舒。',64,'宋词/ci.song.1000.json','["霞卷与云舒。", "月淡星疏。", "摩徽转轸不曾虚。", "弹到当时留意处，谁是相如。", "魂断酒家垆。", "路隔云衢。", "舞鸾镜里早妆初。", "拟学画眉张内史，略借功夫。"]'),
('song-ci-840','卜算子','李之仪','宋','宋词','song-ci','卜算子','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u957f\u6c5f"]','我住长江头，君住长江尾。',53,'宋词/ci.song.1000.json','["我住长江头，君住长江尾。", "日日思君不见君，共饮长江水。", "此水几时休，此恨何时已。", "只愿君心似我心，定不负相思意。"]'),
('song-ci-841','忆秦娥','李之仪','宋','宋词','song-ci','忆秦娥','[]','清溪咽。',56,'宋词/ci.song.1000.json','["清溪咽。", "霜风洗出山头月。", "山头月。", "迎得云归，还送云别。", "不知今是何时节。", "凌歊望断音尘绝。", "音尘绝。", "帆来帆去，天际双阙。"]'),
('song-ci-842','蝶恋花','李之仪','宋','宋词','song-ci','蝶恋花','[]','天淡云闲晴昼永。',70,'宋词/ci.song.1000.json','["天淡云闲晴昼永。", "庭户深沈，满地梧桐影。", "骨冷魂清如梦醒。", "梦回犹是前时景。", "取次杯盘催酩酊。", "醉帽频敧，又被风吹正。", "踏月归来人已静。", "恍疑身在蓬莱顶。"]'),
('song-ci-843','蝶恋花','李之仪','宋','宋词','song-ci','蝶恋花','[]','玉骨冰肌天所赋。',70,'宋词/ci.song.1000.json','["玉骨冰肌天所赋。", "似与神仙，来作烟霞侣。", "枕畔拈来亲手付。", "书窗终日常相顾。", "几度离披留不住。", "依旧清香，只欠能言语。", "再送神仙须爱护。", "他时却待亲来取。"]'),
('song-ci-844','蝶恋花','李之仪','宋','宋词','song-ci','蝶恋花','[]','万事都归一梦了。',70,'宋词/ci.song.1000.json','["万事都归一梦了。", "曾向邯郸，枕上教知道。", "百岁年光谁得到。", "其间忧患知多少。", "无事且频开口笑。", "纵酒狂歌，销遣闲烦恼。", "金谷繁华春正好。", "玉山一任樽前倒。"]'),
('song-ci-845','蝶恋花','李之仪','宋','宋词','song-ci','蝶恋花','[]','为爱梅花如粉面。',70,'宋词/ci.song.1000.json','["为爱梅花如粉面。", "天与功夫，不似人间见。", "几度拈来亲比看。", "功夫却是花枝浅。", "觅得归来临几砚。", "尽日相看，默默情无限。", "更不嗅时须百遍。", "分明销得人肠断。"]'),
('song-ci-846','浣溪沙','李之仪','宋','宋词','song-ci','浣溪沙','[]','剪水开头碧玉条。',48,'宋词/ci.song.1000.json','["剪水开头碧玉条。", "能令江汉客魂销。", "只应香信是春潮。", "戴了又羞缘我老，折来同嗅许谁招。", "凭将此意问妖娆。"]'),
('song-ci-847','浣溪沙','李之仪','宋','宋词','song-ci','浣溪沙','[]','玉室金堂不动尘。',48,'宋词/ci.song.1000.json','["玉室金堂不动尘。", "林梢绿遍已无春。", "清和佳思一番新。", "道骨仙风云外侣，烟鬟雾鬓月边人。", "何妨沈醉到黄昏。"]'),
('song-ci-848','浣溪沙','李之仪','宋','宋词','song-ci','浣溪沙','[]','依旧琅玕不染尘。',48,'宋词/ci.song.1000.json','["依旧琅玕不染尘。", "霜风吹断笑时春。", "一簪华发为谁新。", "白雪幽兰犹有韵，鹊桥星渚可无人。", "金莲移处任尘昏。"]'),
('song-ci-849','浣溪沙','李之仪','宋','宋词','song-ci','浣溪沙','[]','昨日霜风入绛帷。',48,'宋词/ci.song.1000.json','["昨日霜风入绛帷。", "曲房深院绣帘垂。", "屏风几曲画生枝。", "酒韵渐浓欢渐密，罗衣初试漏初迟。", "已凉天气未寒时。"]'),
('song-ci-850','西江月','李之仪','宋','宋词','song-ci','西江月','["\u6d1e\u5ead\u6e56"]','昨夜十分霜重，晓来千里书传。',58,'宋词/ci.song.1000.json','["昨夜十分霜重，晓来千里书传。", "吴山秀处洞庭边。", "不夜星垂初遍。", "好事寄来禅侣，多情将送琴仙。", "为怜佳果称婵娟。", "一笑聊回媚眼。"]'),
('song-ci-851','西江月','李之仪','宋','宋词','song-ci','西江月','[]','醉透香浓斗帐，灯深月浅回廊。',58,'宋词/ci.song.1000.json','["醉透香浓斗帐，灯深月浅回廊。", "当时背面两伥伥。", "何况临风怀想。", "舞柳经春祗瘦，游丝到地能长。", "鸳鸯半调已无肠。", "忍把么弦再上。"]'),
('song-ci-852','西江月','李之仪','宋','宋词','song-ci','西江月','[]','念念欲归未得，迢迢此去何求。',58,'宋词/ci.song.1000.json','["念念欲归未得，迢迢此去何求。", "都缘一点在心头。", "忘了霜朝雪后。", "要见有时有梦，相思无处无愁。", "小窗若得再绸缪。", "应记如今时候。"]'),
('song-ci-853','鹊桥仙','李之仪','宋','宋词','song-ci','鹊桥仙','[]','风清月莹，天然标韵，自是闺房之秀。',68,'宋词/ci.song.1000.json','["风清月莹，天然标韵，自是闺房之秀。", "情多无那不能禁，常是为、而今时候。", "绿云低拢，红潮微上，画幕梅寒初透。", "一般偏更恼人深，时更把、眉儿轻皱。"]'),
('song-ci-854','西江月','李之仪','宋','宋词','song-ci','西江月','[]','宿云收尽，纤尘不警，万里银河低挂。',68,'宋词/ci.song.1000.json','["宿云收尽，纤尘不警，万里银河低挂。", "清冥风露不胜寒，无计学、双鸾并驾。", "玉徽声断，宝钗香远，空赋红绫小砑。", "庾郎知有几多愁，怎奈向、月明今夜。"]'),
('song-ci-855','踏莎行','李之仪','宋','宋词','song-ci','踏莎行','[]','绿遍东山，寒归西渡。',68,'宋词/ci.song.1000.json','["绿遍东山，寒归西渡。", "分明认得春来处。", "风轻雨细更愁人，高唐何在空朝暮。", "离恨相寻，酒狂无素。", "柳条又折年时数。", "一番情味有谁知，断魂还送征帆去。"]'),
('song-ci-856','踏莎行','李之仪','宋','宋词','song-ci','踏莎行','[]','还是归来，依前问渡。',68,'宋词/ci.song.1000.json','["还是归来，依前问渡。", "好风引到经行处。", "几声啼鸟又催耕，草长柳暗春将暮。", "潦倒无成，疏慵有素。", "且陪野老酬天数。", "多情惟有面前山，不随潮水来还去。"]'),
('song-ci-857','鹧鸪天','李之仪','宋','宋词','song-ci','鹧鸪天','[]','节是重阳却斗寒。',64,'宋词/ci.song.1000.json','["节是重阳却斗寒。", "可堪风雨累寻欢。", "虽辜早菊同高柳，聊楫残蕉共小栏。", "浮蚁嫩，炷烟盘。", "恨无莺唱舞催鸾。", "空惊绝韵天边落，不许韶颜梦里看。"]'),
('song-ci-858','鹧鸪天','李之仪','宋','宋词','song-ci','鹧鸪天','[]','浓丽妖妍不是妆。',64,'宋词/ci.song.1000.json','["浓丽妖妍不是妆。", "十分风艳夺韶光。", "牡丹开就应难比，繁富犹疑过海棠。", "须仔细，更端相。", "烂霞梳晕带朝阳。", "千金未足酬真赏，一度相看一断肠。"]'),
('song-ci-859','鹧鸪天','李之仪','宋','宋词','song-ci','鹧鸪天','[]','避暑佳人不著妆。',64,'宋词/ci.song.1000.json','["避暑佳人不著妆。", "水晶冠子薄罗裳。", "摩绵扑粉飞琼屑，滤蜜调冰结绛霜。", "随定我，小兰堂。", "金盆盛水绕牙床。", "时时浸手心头熨，受尽无人知处凉。"]'),
('song-ci-860','鹧鸪天','李之仪','宋','宋词','song-ci','鹧鸪天','[]','收尽微风不见江。',64,'宋词/ci.song.1000.json','["收尽微风不见江。", "分明天水共澄光。", "由来好处输闲地，堪叹人生有底忙。", "心既远，味偏长。", "须知粗布胜无裳。", "从今认得归田乐，何必桃源是故乡。"]'),
('song-ci-861','朝中措','李之仪','宋','宋词','song-ci','朝中措','[]','腊穷天际傍危栏。',57,'宋词/ci.song.1000.json','["腊穷天际傍危栏。", "密雪舞初残。", "表里江山如画，分明不似人间。", "功名何在，文章漫与，空叹流年。", "独恨归来已晚，半生孤负渔竿。"]'),
('song-ci-862','朝中措','李之仪','宋','宋词','song-ci','朝中措','[]','暮山环翠绕层栏。',57,'宋词/ci.song.1000.json','["暮山环翠绕层栏。", "时节岁将残。", "远雁不传家信，空能嘹唳人间。", "客程无尽，归心易感，谁与忘年。", "早晚临流凝望，饥帆催卸风竿。"]'),
('song-ci-863','朝中措','李之仪','宋','宋词','song-ci','朝中措','[]','翰林豪放绝勾栏。',57,'宋词/ci.song.1000.json','["翰林豪放绝勾栏。", "风月敢雕残。", "一旦荆溪仙子，笔头唤聚时间。", "锦袍如在，云山顿改，宛似当年。", "应笑溧阳衰尉，鲇鱼依旧悬竿。"]'),
('song-ci-864','阮郎归','李之仪','宋','宋词','song-ci','阮郎归','[]','朱唇玉羽下蓬莱。',56,'宋词/ci.song.1000.json','["朱唇玉羽下蓬莱。", "佳时近早梅。", "惜花情味久安排。", "枝头开未开。", "魂欲断，恨难裁。", "香心休见猜。", "果知何逊是仙才。", "何妨入梦来。"]'),
('song-ci-865','采桑子','李之仪','宋','宋词','song-ci','采桑子','[]','相逢未几还相别，此恨难同。',52,'宋词/ci.song.1000.json','["相逢未几还相别，此恨难同。", "细雨濛濛。", "一片离愁醉眼中。", "明朝去路云宵外，欲见无从。", "满袂仙风。", "空托双凫作信鸿。"]'),
('song-ci-866','如梦令','李之仪','宋','宋词','song-ci','如梦令','[]','回首芜城旧苑。',40,'宋词/ci.song.1000.json','["回首芜城旧苑。", "还是翠深红浅。", "春意已无多，斜日满帘飞燕。", "不见。", "不见。", "门掩落花庭院。"]'),
('song-ci-867','临江仙','李之仪','宋','宋词','song-ci','临江仙','[]','偶向凌歊台上望，春光已过三分。',70,'宋词/ci.song.1000.json','["偶向凌歊台上望，春光已过三分。", "江山重叠倍销魂。", "风花飞有态，烟絮醉无痕。", "已是年来伤感甚，那堪旧恨仍存。", "清愁满眼共谁论。", "却应台下草，不解忆王孙。"]'),
('song-ci-868','临江仙','李之仪','宋','宋词','song-ci','临江仙','[]','难得今朝风日好，春光佳思平分。',70,'宋词/ci.song.1000.json','["难得今朝风日好，春光佳思平分。", "虽然公子暗招魂。", "其如抬眼看，都是旧时痕。", "酒到强寻欢日路，坐来谁为温存。", "落花流水不堪论。", "何时弦上意，重为拂桐孙。"]'),
('song-ci-869','丑奴儿・采桑子','李之仪','宋','宋词','song-ci','丑奴儿・采桑子','[]','春风似有灯前约，先报佳期。',52,'宋词/ci.song.1000.json','["春风似有灯前约，先报佳期。", "点缀相宜。", "天气犹寒蝶未知。", "嫩黄染就蜂鬓巧，香压团枝。", "淡注仙衣。", "方士临门未起时。"]'),
('song-ci-870','青玉案','李之仪','宋','宋词','song-ci','青玉案','[]','小篷又泛曾行路。',80,'宋词/ci.song.1000.json','["小篷又泛曾行路。", "这身世、如何去。", "去了还来知几度。", "多情山色，有情江水，笑我归无处。", "夕阳杳杳还催暮。", "练净空吟谢郎句。", "拭祷波神应见许。", "帆开风转，事谐心遂，直到明年雨。"]'),
('song-ci-871','更漏子','李之仪','宋','宋词','song-ci','更漏子','[]','暑方烦，人似愠。',58,'宋词/ci.song.1000.json','["暑方烦，人似愠。", "怅望林泉幽峻。", "情会处，景偏长。", "心清闻妙香。", "宝幢低，金锁碎。", "竹影桐印窗外。", "新事旧，旧愁新。", "空嗟不见人。"]'),
('song-ci-872','渔家傲','李之仪','宋','宋词','song-ci','渔家傲','[]','洗尽秋容天似莹。',72,'宋词/ci.song.1000.json','["洗尽秋容天似莹。", "星稀月淡人初静。", "策杖萦纡寻远径。", "披昏暝。", "堤边犊母闲相并。", "遥想去舟魂欲凝。", "一番佳思从谁咏。", "憔悴归来如独醒。", "知何境。", "沈沈但觉烟村迥。"]'),
('song-ci-873','南乡子','李之仪','宋','宋词','song-ci','南乡子','[]','春后雨馀天。',66,'宋词/ci.song.1000.json','["春后雨馀天。", "娅姹黄鹂胜品弦。", "榴叶千灯初报暑，阶前。", "只有茶瓯味最便。", "身世几蹁跹。", "自觉年来更可怜。", "欲问此情何所似，缘延。", "看取窗间坠柳绵。"]'),
('song-ci-874','南乡子','李之仪','宋','宋词','song-ci','南乡子','[]','绿水满池塘。',66,'宋词/ci.song.1000.json','["绿水满池塘。", "点水蜻蜓避燕忙。", "杏子压枝黄半熟，邻墙。", "风送荷花几阵香。", "角簟衬牙床。", "汗透鲛绡昼影长。", "点滴芭蕉疏雨过，微凉。", "画角悠悠送夕阳。"]'),
('song-ci-875','南乡子','李之仪','宋','宋词','song-ci','南乡子','[]','睡起绕回塘。',66,'宋词/ci.song.1000.json','["睡起绕回塘。", "不见衔泥燕子忙。", "前日花梢都绿遍，西墙。", "犹有轻风递暗香。", "步懒恰寻床。", "卧看游丝到地长。", "自恨无聊常病酒，凄凉。", "岂有才情似沈阳。"]'),
('song-ci-876','南乡子','李之仪','宋','宋词','song-ci','南乡子','[]','小雨湿黄昏。',66,'宋词/ci.song.1000.json','["小雨湿黄昏。", "重午佳辰独掩门。", "巢燕引雏浑去尽，销魂。", "空向梁间觅宿痕。", "客舍宛如村。", "好事无人载一樽。", "唯有莺声知此恨，殷勤。", "恰似当时枕上闻。"]'),
('song-ci-877','南乡子','李之仪','宋','宋词','song-ci','南乡子','[]','泪眼转天昏。',66,'宋词/ci.song.1000.json','["泪眼转天昏。", "去路迢迢隔九门。", "角黍满盘无意举，凝魂。", "不为当时泽畔痕。", "肠断武陵村。", "骨冷难同月下樽。", "强泛菖蒲酬令节，空勤。", "风叶萧萧不忍闻。"]'),
('song-ci-878','蓦山溪','李之仪','宋','宋词','song-ci','蓦山溪','[]','青楼薄幸，已分终难偶。',102,'宋词/ci.song.1000.json','["青楼薄幸，已分终难偶。", "寻遍绮罗间，悄无个、眼中翘秀。", "江南春晓，花发乱莺飞，情渐透。", "休辞瘦。", "果有人相候。", "醉乡路稳，常是身偏后。", "谁谓正欢时，把相思、番成红豆。", "千言万语，毕竟总成虚，章台柳。", "青青否。", "魂梦空搔首。"]'),
('song-ci-879','减字木兰花','李之仪','宋','宋词','song-ci','减字木兰花','[]','乱魂无据。',52,'宋词/ci.song.1000.json','["乱魂无据。", "黯黯只寻来处路。", "灯尽花残。", "不觉长更又向阑。", "几回枕上。", "那件不曾留梦想。", "变尽星星。", "一滴秋霖是一茎。"]'),
('song-ci-880','减字木兰花','李之仪','宋','宋词','song-ci','减字木兰花','[]','堤长春晚。',52,'宋词/ci.song.1000.json','["堤长春晚。", "冉冉浑如云外见。", "欲语无门。", "略许莺声隔岸闻。", "锦屏绣幌。", "犹待归来留一饷。", "何事迟迟。", "直恐游丝惹住伊。"]'),
('song-ci-881','减字木兰花','李之仪','宋','宋词','song-ci','减字木兰花','[]','触涂是碍。',52,'宋词/ci.song.1000.json','["触涂是碍。", "一任浮沈何必改。", "有个人人。", "自说居尘不染尘。", "谩夸千手。", "千物执持都是有。", "气候融怡。", "还取青天白日时。"]'),
('song-ci-882','减字木兰花','李之仪','宋','宋词','song-ci','减字木兰花','[]','莫非魔境。',52,'宋词/ci.song.1000.json','["莫非魔境。", "强向中间谈独醒。", "一叶才飞。", "便觉年华太半归。", "醉云可矣。", "认著依前还不是。", "虚过今春。", "有愧斜川得意人。"]'),
('song-ci-883','减字木兰花','李之仪','宋','宋词','song-ci','减字木兰花','[]','揉花催柳。',52,'宋词/ci.song.1000.json','["揉花催柳。", "一夜阴风几破牖。", "平晓无云。", "依旧光明一片春。", "掀衣起走。", "欲助喜欢须是酒。", "惆怅空樽。", "拟就王孙借十分。"]'),
('song-ci-884','天门谣','李之仪','宋','宋词','song-ci','天门谣','[]','天堑休论险。',56,'宋词/ci.song.1000.json','["天堑休论险。", "尽远目、与天俱占。", "山水敛。", "称霜晴披览。", "正风静云闲、平潋滟。", "想见高吟名不滥。", "频扣槛。", "杳杳落、沙鸥数点。"]'),
('song-ci-885','好事近','李之仪','宋','宋词','song-ci','好事近','[]','相见两无言，愁恨又还千叠。',53,'宋词/ci.song.1000.json','["相见两无言，愁恨又还千叠。", "别有恼人深处，在懵腾双睫。", "七弦虽妙不须弹，惟愿醉香颊。", "只恐近来情绪，似风前秋叶。"]'),
('song-ci-886','减字木兰花','李之仪','宋','宋词','song-ci','减字木兰花','[]','春到雨初晴，正是小楼时节。',53,'宋词/ci.song.1000.json','["春到雨初晴，正是小楼时节。", "柳眼向人微笑，傍阑干堪折。", "暮山浓淡锁烟霏，梅杏半明灭。", "玉斝莫辞沈醉，待归时斜月。"]'),
('song-ci-887','减字木兰花','李之仪','宋','宋词','song-ci','减字木兰花','[]','上尽玉梯云，还见一番佳节。',53,'宋词/ci.song.1000.json','["上尽玉梯云，还见一番佳节。", "惆怅旧时行处，把青青轻折。", "倚阑人醉欲黄昏，飞鸟望中灭。", "天面碧琉璃上，印弯弯新月。"]'),
('song-ci-888','浣溪沙','李之仪','宋','宋词','song-ci','浣溪沙','[]','龟坼沟塍草压堤。',48,'宋词/ci.song.1000.json','["龟坼沟塍草压堤。", "三农终日望云霓。", "一番甘雨报佳时。", "闻道醉乡新占断，更开诗社互排巇。", "此时空恨隔云泥。"]'),
('song-ci-889','浣溪沙','李之仪','宋','宋词','song-ci','浣溪沙','[]','雨暗轩窗昼易昏。',48,'宋词/ci.song.1000.json','["雨暗轩窗昼易昏。", "强敧纤手浴金盆。", "却因凉思谢飞蚊。", "酒量羡君如鹄举，寒乡怜我似鸱蹲。", "由来同是一乾坤。"]'),
('song-ci-890','浣溪沙','李之仪','宋','宋词','song-ci','浣溪沙','[]','声名自昔犹时鸟，日月何尝避覆盆。',48,'宋词/ci.song.1000.json','["声名自昔犹时鸟，日月何尝避覆盆。", "是非都付鬓边蚊。", "邂逅风雷终有用，低回囊槛要深蹲。", "酒中聊复比乾坤。"]'),
('song-ci-891','菩萨蛮','李之仪','宋','宋词','song-ci','菩萨蛮','[]','五云深处蓬山杳。',52,'宋词/ci.song.1000.json','["五云深处蓬山杳。", "寒轻雾重银蟾小。", "枕上挹馀香。", "春风归路长。", "雁来书不到。", "人静重门悄。", "一阵落花风。", "云山千万重。"]'),
('song-ci-892','菩萨蛮','李之仪','宋','宋词','song-ci','菩萨蛮','[]','青梅又是花时节。',52,'宋词/ci.song.1000.json','["青梅又是花时节。", "粉墙闲把青梅折。", "玉镫偶逢君。", "春情如乱云。", "藕丝牵不断。", "谁信朱颜换。", "莫厌十分斟。", "酒深情更深。"]'),
('song-ci-893','雨中花令','李之仪','宋','宋词','song-ci','雨中花令','[]','休把身心撋就。',58,'宋词/ci.song.1000.json','["休把身心撋就。", "著便醉人如酒。", "富贵功名虽有味，毕竟因谁守。", "看取刀头切藕。", "厚薄都随他手。", "趁取日中归去好，□莫待、黄昏后。"]'),
('song-ci-894','雨中花令','李之仪','宋','宋词','song-ci','雨中花令','[]','点缀叶间如绣。',60,'宋词/ci.song.1000.json','["点缀叶间如绣。", "开傍小春时候。", "莫把幽兰容易比，都占尽、人间秀。", "信是眼前稀有。", "消得千锺美酒。", "只有些儿堪恨处，管不似、人长久。"]'),
('song-ci-895','留春令','李之仪','宋','宋词','song-ci','留春令','[]','梦断难寻，酒醒犹困，那堪春暮。',61,'宋词/ci.song.1000.json','["梦断难寻，酒醒犹困，那堪春暮。", "香阁深沈，红窗翠暗，莫羡颠狂絮。", "绿满当时携手路，懒见同欢处。", "何时却得，低帏昵枕，尽诉情千缕。"]'),
('song-ci-896','踏莎行','李之仪','宋','宋词','song-ci','踏莎行','[]','紫燕衔泥，黄莺唤友。',68,'宋词/ci.song.1000.json','["紫燕衔泥，黄莺唤友。", "可人春色暄晴昼。", "王孙一去杳无音，断肠最是黄昏后。", "宝髻慵梳，玉钗斜溜。", "凭阑目断空回首。", "薄情何事不归来，谩教折尽庭前柳。"]'),
('song-ci-897','踏莎行','李之仪','宋','宋词','song-ci','踏莎行','[]','一别芳容，五经寒暑。',68,'宋词/ci.song.1000.json','["一别芳容，五经寒暑。", "回文欲寄无鳞羽。", "多情犹自梦中来，向人粉泪流如雨。", "梦破南窗，愁肠万缕。", "那听角动城头鼓。", "人生弹指事成空，断魂惆怅无寻处。"]'),
('song-ci-898','南乡子','李之仪','宋','宋词','song-ci','南乡子','[]','夜雨滴空阶。',66,'宋词/ci.song.1000.json','["夜雨滴空阶。", "想见尊前赋咏才。", "更觉鸣蛙如鼓吹，安排。", "惆怅流光去不回。", "万事已成灰。", "只这些儿尚满怀。", "刚被北风吹晓角，相催。", "不许时间入梦来。"]'),
('song-ci-899','万年欢','李之仪','宋','宋词','song-ci','万年欢','[]','暖律才中，正莺喉竞巧，燕语新成。',121,'宋词/ci.song.1000.json','["暖律才中，正莺喉竞巧，燕语新成。", "万绿阴浓，全无一点芳尘。", "门巷朝来报喜，庆佳期、此日光荣。", "开华宴、交酌琼酥，共祝鹤算椿龄。", "须知最难得处，双双凤翼，一对和鸣。", "造化无私，谁教特地多情。", "惟愿疏封大国，彩笺上、频易佳名。", "从此去、贤子才孙，岁岁长捧瑶觥。"]'),
('song-ci-900','朝中措','李之仪','宋','宋词','song-ci','朝中措','[]','新开湖水浸遥天。',57,'宋词/ci.song.1000.json','["新开湖水浸遥天。", "风叶响珊珊。", "记得昔游情味，浩歌不怕朝寒。", "故人一去，高名万古，长对孱颜。", "惟有落霞孤骛，晚年依旧争还。"]'),
('song-ci-901','朝中措','李之仪','宋','宋词','song-ci','朝中措','[]','败荷枯苇夕阳天。',57,'宋词/ci.song.1000.json','["败荷枯苇夕阳天。", "时节渐阑珊。", "独泛扁舟归去，老来不耐霜寒。", "平生志气，消磨尽也，留得苍颜。", "寄语山中糜鹿，断云相次东还。"]'),
('song-ci-902','临江仙','李之仪','宋','宋词','song-ci','临江仙','[]','初破晓寒无限思，融融腊意全迷。',68,'宋词/ci.song.1000.json','["初破晓寒无限思，融融腊意全迷。", "春工从此被人知。", "不随蜂蝶，长伴玉蟾低。", "缥缈云间应好在，盈盈泪湿征衣。", "背人偷拗向东枝。", "清香满袖，犹记画堂西。"]'),
('song-ci-903','临江仙','李之仪','宋','宋词','song-ci','临江仙','[]','病里不知春早晚，惊心绿暗红稀。',68,'宋词/ci.song.1000.json','["病里不知春早晚，惊心绿暗红稀。", "起来初拭薄罗衣。", "多情海燕，还傍旧梁飞。", "瘦损休文谁记得，空将销臂频围。", "眼前都是去年时。", "不堪追想，魂断画楼西。"]'),
('song-ci-904','蝶恋花','李之仪','宋','宋词','song-ci','蝶恋花','[]','帘外飞花湖上语。',70,'宋词/ci.song.1000.json','["帘外飞花湖上语。", "不恨花飞，只恨人难住。", "多谢雨来留得住。", "看看却恐晴催去。", "寸寸离肠须会取。", "今日宁宁，明日从谁诉。", "怎得此身如去路。", "迢迢长在君行处。"]'),
('song-ci-905','失调名','蔡确','宋','宋词','song-ci','失调名','[]','骊山宫中看乞巧，太液池边收曝衣。',16,'宋词/ci.song.1000.json','["骊山宫中看乞巧，太液池边收曝衣。"]'),
('song-ci-906','惜黄花','许将','宋','宋词','song-ci','惜黄花','[]','雁声晚断。',88,'宋词/ci.song.1000.json','["雁声晚断。", "寒宵云卷。", "正一枝开，风前看，月下见。", "花占千花上，香笑千香浅。", "化工与、最先裁翦。", "谁把瑶林，闲抛江岸。", "恁素英浓，芳心细，意何限。", "不恨宫妆色，不怨吹羌管。", "恨天远、恨春来晚。"]'),
('song-ci-907','临江仙','许将','宋','宋词','song-ci','临江仙','[]','圣主临轩亲策试，集英佳气葱葱。',70,'宋词/ci.song.1000.json','["圣主临轩亲策试，集英佳气葱葱。", "鸣鞘声震未央宫。", "卷帘龙影动，挥翰御烟浓。", "上第归来何事好，迎人花面争红。", "蓝袍香散六街风。", "一鞭春色里，骄损玉花骢。"]'),
('song-ci-908','临江仙','郑无党','宋','宋词','song-ci','临江仙','[]','不比寻常三五夜，万家齐望清辉。',70,'宋词/ci.song.1000.json','["不比寻常三五夜，万家齐望清辉。", "烂银盘透碧琉璃。", "莫辞终夕看，动是隔年期。", "试问嫦娥还记否，玉人曾折高枝。", "明年此夜再圆时。", "合开东府宴，身在凤凰池。"]'),
('song-ci-909','无愁可解','陈','宋','宋词','song-ci','无愁可解','[]','光景百年，看便一世。',132,'宋词/ci.song.1000.json','["光景百年，看便一世。", "生来不识愁味。", "问愁何处来，更开解个甚底。", "万事从来风过耳。", "何用不著心里。", "你唤做、展却眉头，便是达者，也则恐未。", "此理。", "本不通言，何曾道、欢游胜如名利。", "道即浑是错，不道如何即是。", "这里元无我与你。", "甚唤做、物情之外。", "若须待醉了、方开解时，问无酒、怎生醉。"]'),
('song-ci-910','调啸・调笑令','苏辙','宋','宋词','song-ci','调啸・调笑令','[]','渔父。',43,'宋词/ci.song.1000.json','["渔父。", "渔父。", "水上微风细雨。", "青蓑黄箬裳衣。", "红酒白鱼暮归。", "暮归、暮归、归暮。", "长笛一声何处。"]'),
('song-ci-911','调啸・调笑令','苏辙','宋','宋词','song-ci','调啸・调笑令','[]','归雁。',43,'宋词/ci.song.1000.json','["归雁。", "归雁。", "饮啄江南南岸。", "将飞却下盘桓。", "塞北春来苦寒。", "苦寒。", "苦寒。", "寒苦。", "藻荇欲生且住。"]'),
('song-ci-912','水调歌头','苏辙','宋','宋词','song-ci','水调歌头','[]','离别一何久，七度过中秋。',114,'宋词/ci.song.1000.json','["离别一何久，七度过中秋。", "去年东武今夕，明月不胜愁。", "岂意彭城山下，同泛清河古汴，船上载凉州。", "鼓吹助清赏，鸿雁起汀洲。", "坐中客，翠羽帔，紫绮裘。", "素娥无赖，西去曾不为人留。", "今夜清尊对客，明夜孤帆水驿，依旧照离忧。", "但恐同王粲，相对永登楼。"]'),
('song-ci-913','渔家傲','苏辙','宋','宋词','song-ci','渔家傲','[]','七十馀年真一梦。',72,'宋词/ci.song.1000.json','["七十馀年真一梦。", "朝来寿斝儿孙奉。", "忧患已空无复痛。", "心不动。", "此间自有千钧重。", "早岁文章供世用。", "中年禅味疑天纵。", "石塔成时无一缝。", "谁与共。", "人间天上随他送。"]'),
('song-ci-914','沁园春','陈睦','宋','宋词','song-ci','沁园春','[]','小雪初晴，画舫明月，强饮未眠。',141,'宋词/ci.song.1000.json','["小雪初晴，画舫明月，强饮未眠。", "念翠鬟双耸，舞衣半卷，琵琶催拍，促管危弦。", "密意虽具，欢期难偶，遣我离情愁绪牵。", "追思处，奈溪桥道窄，无计留连。", "天天。", "莫是前缘。", "自别后、深诚谁为传。", "想玉篦偷付，珠囊暗解，两心长在，须合金钿。", "浅淡精神，温柔情性，记我疏狂应痛怜。", "空肠断，奈衾寒漏永，终夜如年。"]'),
('song-ci-915','清平乐','陈睦','宋','宋词','song-ci','清平乐','[]','鬓云斜坠。',54,'宋词/ci.song.1000.json','["鬓云斜坠。", "莲步弯弯细。", "笑脸双蛾生多媚。", "百步兰麝香喷。", "从前万种愁烦。", "枕边未可明言。", "好是蓝桥再渡，玉篦还胜金钿。"]'),
('song-ci-916','玉楼春','马成','宋','宋词','song-ci','玉楼春','["\u897f\u6e56"]','来时吴会犹残暑。',64,'宋词/ci.song.1000.json','["来时吴会犹残暑。", "去日武林春已暮。", "欲知遗爱感人深，洒泪多於江上雨。", "欢情未举眉先聚。", "别酒多斟君莫诉。", "从今宁忍看西湖，抬眼尽成肠断处。"]'),
('song-ci-917','满江红','李婴','宋','宋词','song-ci','满江红','[]','荆楚风烟，寂寞近、中秋时候。',117,'宋词/ci.song.1000.json','["荆楚风烟，寂寞近、中秋时候。", "露下冷、兰英将谢，苇花初秀。", "归燕殷勤辞巷陌，鸣蛩凄楚来窗牖。", "又谁念、江边有神仙，飘零久。", "横琴膝，携筇手。", "旷望眼，闲吟口。", "任纷纷万事，到头何有。", "君不见、凌烟冠剑客，何人气貌长依旧。", "归去来、一曲为君吟，为君寿。"]'),
('song-ci-918','菩萨蛮','王齐愈','宋','宋词','song-ci','菩萨蛮','[]','玉肌香衬冰丝縠。',52,'宋词/ci.song.1000.json','["玉肌香衬冰丝縠。", "縠丝冰衬香肌玉。", "纤指拂眉尖。", "尖眉拂指纤。", "巧裁罗袜小。", "小袜罗裁巧。", "移步看尘飞。", "飞尘看步移。"]'),
('song-ci-919','菩萨蛮','王齐愈','宋','宋词','song-ci','菩萨蛮','[]','吼雷催雨飞沙走。',52,'宋词/ci.song.1000.json','["吼雷催雨飞沙走。", "走沙飞雨催雷吼。", "波涨泻倾河。", "河倾泻涨波。", "幌纱凉气爽。", "爽气凉纱幌。", "幽梦觉仙游。", "游仙觉梦幽。"]'),
('song-ci-920','菩萨蛮','王齐愈','宋','宋词','song-ci','菩萨蛮','[]','兽喷香缕飞长昼。',52,'宋词/ci.song.1000.json','["兽喷香缕飞长昼。", "昼长飞缕香喷兽。", "迎日喜葵倾。", "倾葵喜日迎。", "卷帘双舞燕。", "燕舞双帘卷。", "清簟枕钗横。", "横钗枕簟清。"]'),
('song-ci-921','菩萨蛮','王齐愈','宋','宋词','song-ci','菩萨蛮','[]','远香风递莲湖满。',52,'宋词/ci.song.1000.json','["远香风递莲湖满。", "满湖莲递风香远。", "光鉴试新妆。", "妆新试鉴光。", "棹穿花处好。", "好处花穿棹。", "明月咏歌清。", "清歌咏月明。"]'),
('song-ci-922','菩萨蛮','王齐愈','宋','宋词','song-ci','菩萨蛮','[]','酒中愁说人留久。',52,'宋词/ci.song.1000.json','["酒中愁说人留久。", "久留人说愁中酒。", "归梦要迟迟。", "迟迟要梦归。", "旧衣香染袖。", "袖染香衣旧。", "封短托飞鸿。", "鸿飞托短封。"]'),
('song-ci-923','菩萨蛮','王齐愈','宋','宋词','song-ci','菩萨蛮','[]','老人愁叹惊年早。',52,'宋词/ci.song.1000.json','["老人愁叹惊年早。", "早年惊叹愁人老。", "霜点鬓苍苍。", "苍苍鬓点霜。", "酒杯停欲久。", "久欲停杯酒。", "杯酒唤眉开。", "开眉唤酒杯。"]'),
('song-ci-924','菩萨蛮','王齐愈','宋','宋词','song-ci','菩萨蛮','[]','暑烦人困初时午。',52,'宋词/ci.song.1000.json','["暑烦人困初时午。", "午时初困人烦暑。", "新诗得酒因。", "因酒得诗新。", "缕金歌眉举。", "举眉歌金缕。", "人妒月圆频。", "频圆月妒人。"]'),
('song-ci-925','虞美人','王齐愈','宋','宋词','song-ci','虞美人','[]','黄金柳嫩摇丝软。',66,'宋词/ci.song.1000.json','["黄金柳嫩摇丝软。", "永日堂堂掩。", "卷帘飞燕未归来。", "客去醉眠敧枕、殢残杯。", "眉山浅拂青螺黛。", "整整垂双带。", "水沈香熨窄衫轻。", "莹玉碧溪春溜、眼波横。"]'),
('song-ci-926','望江南・忆江南','王齐叟','宋','宋词','song-ci','望江南・忆江南','[]','居下位，常恐被人谗。',32,'宋词/ci.song.1000.json','["居下位，常恐被人谗。", "只是曾填青玉案，何曾敢作望江南。", "请问马都监。"]'),
('song-ci-927','失调名','王齐叟','宋','宋词','song-ci','失调名','[]','蹙绣圈金，槃囊密约，未赴意先警。',98,'宋词/ci.song.1000.json','["蹙绣圈金，槃囊密约，未赴意先警。", "欲罢还休，临行又怯，倚定画栏痴等。", "帘风渐冷。", "先自虑、春宵不永。", "更那堪、斗转星移，尚在有无之境。", "绿云满压蝤蛴领。", "惭愧也、满怀香拥。", "此际有谁知证。", "但楼前明月，窗间花影。"]'),
('song-ci-928','点绛唇','舒氏','宋','宋词','song-ci','点绛唇','[]','独自临池，闷来强把阑干凭。',50,'宋词/ci.song.1000.json','["独自临池，闷来强把阑干凭。", "旧愁新恨。", "耗却年时兴。", "鹭散鱼潜，烟敛风初定。", "波心静。", "照人如镜。", "少个年时影。"]'),
('song-ci-929','满庭芳','琴操','宋','宋词','song-ci','满庭芳','[]','山抹微云，天连衰草，画角声断斜阳。',118,'宋词/ci.song.1000.json','["山抹微云，天连衰草，画角声断斜阳。", "暂停征辔，聊共饮离觞。", "多少蓬莱旧侣，频回首、烟霭茫茫。", "孤村里，寒鸦万点，流水绕红墙。", "魂伤。", "当此际，轻分罗带，暗解香囊。", "谩赢得，青楼薄幸名狂。", "此去何时见也，襟袖上、空有馀香。", "伤心处，高城望断，灯火已昏黄。"]'),
('song-ci-930','卜算子','琴操','宋','宋词','song-ci','卜算子','[]','欲整别离情，怯对尊中酒。',54,'宋词/ci.song.1000.json','["欲整别离情，怯对尊中酒。", "野梵幽幽石上飘，搴落楼头柳。", "不系黄金绶。", "粉黛愁成垢。", "春风三月有时阑，遮不尽、梨花丑。"]'),
('song-ci-931','临江仙','舒亶','宋','宋词','song-ci','临江仙','[]','折柳门前鹦鹉绿，河梁小驻归船。',70,'宋词/ci.song.1000.json','["折柳门前鹦鹉绿，河梁小驻归船。", "不堪华发对离筵。", "孤村啼鴂日，深院落花天。", "文采弟兄真叠玉，赤宵去路谁先。", "明朝便恐各风烟。", "江山如有恨，桃李自无言。"]'),
('song-ci-932','点绛唇','舒亶','宋','宋词','song-ci','点绛唇','[]','紫雾香浓，岁华风转花随辇。',50,'宋词/ci.song.1000.json','["紫雾香浓，岁华风转花随辇。", "洞天云暖。", "一片笙歌远。", "水殿龙舟，忆侍瑶池宴。", "闲庭院。", "梦回春半。", "雪鬓无人见。"]'),
('song-ci-933','散天花','舒亶','宋','宋词','song-ci','散天花','[]','云断长空叶落秋。',72,'宋词/ci.song.1000.json','["云断长空叶落秋。", "寒江烟浪静，月随舟。", "西风偏解送离愁。", "声声南去雁，下汀洲。", "无奈多情去复留。", "骊歌齐唱罢，泪争流。", "悠悠别恨几时休。", "不堪残酒醒，凭危楼。"]'),
('song-ci-934','醉花阴','舒亶','宋','宋词','song-ci','醉花阴','[]','露芽初破云腴细。',62,'宋词/ci.song.1000.json','["露芽初破云腴细。", "玉纤纤亲试。", "香雪透金瓶，无限仙风，月下人微醉。", "相如消渴无佳思。", "了知君此意。", "不信老卢郎，花底春寒，赢得空无睡。"]'),
('song-ci-935','醉花阴','舒亶','宋','宋词','song-ci','醉花阴','[]','月幌风帘香一阵。',62,'宋词/ci.song.1000.json','["月幌风帘香一阵。", "正千山雪尽。", "冷对酒尊傍，无语含情，别是江南信。", "寿阳妆罢人微困。", "更玉钗斜衬。", "拟插一枝归，只恐风流，羞上潘郎鬓。"]'),
('song-ci-936','虞美人','舒亶','宋','宋词','song-ci','虞美人','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','芙蓉落尽天涵水。',66,'宋词/ci.song.1000.json','["芙蓉落尽天涵水。", "日暮沧波起。", "背飞双燕帖云寒。", "独向小楼东畔、倚阑看。", "浮生只合尊前老。", "雪满长安道。", "故人早晚上高台。", "赠我江南春色、一枝梅。"]'),
('song-ci-937','虞美人','舒亶','宋','宋词','song-ci','虞美人','[]','酒边陡觉罗衣暖。',66,'宋词/ci.song.1000.json','["酒边陡觉罗衣暖。", "独倚黄昏看。", "寒鸦两两下楼东。", "著处暗云垂地、一重重。", "红炉欢坐谁能醉。", "多少看花意。", "谢娘也拟殢春风。", "便道无端柳絮、逼帘栊。"]'),
('song-ci-938','虞美人','舒亶','宋','宋词','song-ci','虞美人','[]','重帘小阁香云暖。',66,'宋词/ci.song.1000.json','["重帘小阁香云暖。", "黛拂梳妆浅。", "玉箫一曲杜韦娘。", "谁是苏州刺史、断人肠。", "醉归旋拨红炉火。", "却倚屏山坐。", "银缸明灭月横斜。", "还是画楼角送、小梅花。"]'),
('song-ci-939','丑奴儿・采桑子','舒亶','宋','宋词','song-ci','丑奴儿・采桑子','[]','一池秋水疏星动，寒影横斜。',52,'宋词/ci.song.1000.json','["一池秋水疏星动，寒影横斜。", "满坐风花。", "红烛纷纷透绛纱。", "江湖散诞扁舟里，到处如家。", "且尽流霞。", "莫管年来两鬓华。"]'),
('song-ci-940','一落索','舒亶','宋','宋词','song-ci','一落索','[]','正是看花天气。',56,'宋词/ci.song.1000.json','["正是看花天气。", "为春一醉。", "醉来却不带花归，诮不解、看花意。", "试问此花明媚。", "将花谁比。", "只应花好似年年，花不似、人憔悴。"]'),
('song-ci-941','一落索','舒亶','宋','宋词','song-ci','一落索','[]','叶底枝头红小。',56,'宋词/ci.song.1000.json','["叶底枝头红小。", "天然窈窕。", "后园桃李谩成蹊，问占得、春多少。", "不管雪消霜晓。", "朱颜长好。", "年年若许醉花间，待拼了、花间老。"]'),
('song-ci-942','满庭芳','舒亶','宋','宋词','song-ci','满庭芳','[]','寒日穿帘，澄江凭槛，练光浮动馀霞。',118,'宋词/ci.song.1000.json','["寒日穿帘，澄江凭槛，练光浮动馀霞。", "蓼汀芦岸，黄叶衬孤花。", "天外征帆隐隐，残云共、流水无涯。", "登临处，琼枝潋滟，风帽醉敧斜。", "丰年，时节好，玉香田舍，酒满渔家。", "算浮世劳生，事事输他。", "便恁从今酩酊，休更问、白雪笼纱。", "还须仗，神仙妙手，传向画图夸。"]'),
('song-ci-943','满庭芳','舒亶','宋','宋词','song-ci','满庭芳','[]','红叶飘零，寒烟疏淡，楼台半在云间。',118,'宋词/ci.song.1000.json','["红叶飘零，寒烟疏淡，楼台半在云间。", "望中风景，图画也应难。", "又是重阳过了，东篱下、黄菊阑珊。", "陶潜病，风流载酒，秋意与人闲。", "霞冠。", "敧倒处，瑶台唱罢，如梦中还。", "但醉里赢得，满眼青山。", "华发看看满也，留不住、当日朱颜。", "平生事，从头话了，独自却凭栏。"]'),
('song-ci-944','满庭芳','舒亶','宋','宋词','song-ci','满庭芳','["\u897f\u6e56"]','阊阖天门，芙蓉春殿，几年目断鸡翘。',118,'宋词/ci.song.1000.json','["阊阖天门，芙蓉春殿，几年目断鸡翘。", "短蓬秋鬓，端幸倚琼瑶。", "南圃花边小院，西湖畔、云低双桥。", "归时节，红香露冷，月影上芭蕉。", "明朝。", "那可望，旗亭烟草，柳渡寒潮。", "但万户千门，恨客歌樵。", "戏彩光浮衮绣，听鸣珂、响逼云宵。", "应回首，绮裘醉客，还是独吹箫。"]'),
('song-ci-945','卜算子','舒亶','宋','宋词','song-ci','卜算子','[]','池台小雨乾，门巷香轮少。',52,'宋词/ci.song.1000.json','["池台小雨乾，门巷香轮少。", "谁把青钱衬落红，满地无人扫。", "何时斗草归，几度寻花了。", "留得佳人莲步痕，宫样鞋儿小。"]'),
('song-ci-946','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','三年江上风吹泪。',52,'宋词/ci.song.1000.json','["三年江上风吹泪。", "夭桃艳杏无春意。", "今日欲开眉。", "那堪更别离。", "莫折长亭柳。", "折尽愁依旧。", "只有醉如狂。", "人生空断肠。"]'),
('song-ci-947','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','柳桥花坞南城陌。',52,'宋词/ci.song.1000.json','["柳桥花坞南城陌。", "朱颜绿发长安路。", "雨后小池台。", "寻常载酒来。", "马头今日路。", "却望城西去。", "斜日下汀洲。", "断云和泪流。"]'),
('song-ci-948','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','画船槌鼓催君去。',52,'宋词/ci.song.1000.json','["画船槌鼓催君去。", "高楼把酒留君住。", "去住若为情。", "西江潮欲平。", "江潮容易得。", "只是人南北。", "今日此尊空。", "知君何日同。"]'),
('song-ci-949','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','画檐细雨偏红烛。',52,'宋词/ci.song.1000.json','["画檐细雨偏红烛。", "疏星冷落排寒玉。", "赌得碧云篇。", "金波更涉船。", "樽前当日客。", "行色垂杨陌。", "天阔水悠悠。", "含情独倚楼。"]'),
('song-ci-950','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','杜鹃啼破江南月。',52,'宋词/ci.song.1000.json','["杜鹃啼破江南月。", "香风扑面吹红雪。", "赋就缕金笺。", "黄昏醉上船。", "年华爽短鬓。", "事往情何尽。", "明日各天涯。", "来春空好花。"]'),
('song-ci-951','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','朱帘乍卷层烟起。',52,'宋词/ci.song.1000.json','["朱帘乍卷层烟起。", "露华深浅初疑洗。", "困倚玉阑风。", "绮罗知几重。", "向人如有意。", "不醉何时醉。", "便得一枝红。", "犹胜两鬓空。"]'),
('song-ci-952','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','小池山额垂螺碧。',52,'宋词/ci.song.1000.json','["小池山额垂螺碧。", "绿红香里眠鸂鶒。", "波面翠云开。", "仙槎天上来。", "吹将红日落。", "懊恼严城角。", "风月此时情。", "知君华发生。"]'),
('song-ci-953','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','一回别后一回老。',52,'宋词/ci.song.1000.json','["一回别后一回老。", "别离易得相逢少。", "莫问故园花。", "长安君是家。", "短亭秋日晚。", "草色随人远。", "欲醉又还醒。", "江楼暮角声。"]'),
('song-ci-954','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','樽前休话人生事。',52,'宋词/ci.song.1000.json','["樽前休话人生事。", "人生只合樽前醉。", "金盏大如船。", "江城风雪天。", "绮窗灯自语。", "一夜芭蕉雨。", "玉漏为谁长。", "枕衾残酒香。"]'),
('song-ci-955','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','楼前流水西江道。',52,'宋词/ci.song.1000.json','["楼前流水西江道。", "江头水落芙蓉老。", "画鼓叠凉波。", "凭栏颦翠娥。", "当年金马客。", "青鬓芦花色。", "把酒感秋蓬。", "骊歌半醉中。"]'),
('song-ci-956','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','绮栊深闭桃园曲。',52,'宋词/ci.song.1000.json','["绮栊深闭桃园曲。", "刘郎老向花间宿。", "笑脸抹流霞。", "心知是小琶。", "纤纤垂素玉。", "掠鬓春云绿。", "弹了醉思仙。", "小窗红日偏。"]'),
('song-ci-957','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','真珠酒滴琵琶送。',52,'宋词/ci.song.1000.json','["真珠酒滴琵琶送。", "行云旧识巫山梦。", "空得醉中归。", "老来心事非。", "江梅含日暖。", "照水花枝短。", "密叶似商量。", "向人春意长。"]'),
('song-ci-958','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','小亭露厌风枝动。',52,'宋词/ci.song.1000.json','["小亭露厌风枝动。", "鹊炉火冷金瓶冻。", "悄悄对西窗。", "瘦知罗带长。", "欲眠思殢酒。", "坐听寒更久。", "无赖是青灯。", "开花故故明。"]'),
('song-ci-959','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','流年又见风沙送。',52,'宋词/ci.song.1000.json','["流年又见风沙送。", "钧天回首清都梦。", "塞雁几时归。", "镜中双鬓非。", "绿袍同冷暖。", "谁道交情短。", "愁斛若为量。", "还随一线长。"]'),
('song-ci-960','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','白苹洲渚垂杨岸。',52,'宋词/ci.song.1000.json','["白苹洲渚垂杨岸。", "藕花未放青蒲短。", "斜日画船归。", "背人双鹭飞。", "醉眠金马客。", "不道风尘隔。", "红影上窗纱。", "小庭空落花。"]'),
('song-ci-961','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','金船满引人微醉。',52,'宋词/ci.song.1000.json','["金船满引人微醉。", "红绡笼烛崔归骑。", "香泛雪盈杯。", "云龙疑梦回。", "不辞风满腋。", "旧是仙家客。", "坐得夜无眠。", "南窗衾枕寒。"]'),
('song-ci-962','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','江梅未放枝头结。',52,'宋词/ci.song.1000.json','["江梅未放枝头结。", "江楼已见山头雪。", "待得此花开。", "知君来不来。", "风帆双画鹢。", "小雨随行色。", "空得郁金裙。", "酒痕和泪痕。"]'),
('song-ci-963','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','香波绿暖浮鹦鹉。',52,'宋词/ci.song.1000.json','["香波绿暖浮鹦鹉。", "黄金捍拨么弦语。", "小雨落梧桐。", "帘栊残烛红。", "人生闲亦好。", "双鬓催人老。", "莫惜醉中归。", "醒来思醉时。"]'),
('song-ci-964','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','绿窗酒醒春如梦。',52,'宋词/ci.song.1000.json','["绿窗酒醒春如梦。", "小池犹见红云动。", "露湿井干桐。", "翠阴生细风。", "雨过芳塘净。", "清昼闲中永。", "门外立双旌。", "隔花闻笑声。"]'),
('song-ci-965','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','忆曾把酒赏红翠。',52,'宋词/ci.song.1000.json','["忆曾把酒赏红翠。", "舞腰柳弱歌声细。", "纵马杏园西。", "归来香满衣。", "宝车空犊驻。", "事逐孤鸿去。", "搔首立江干。", "春萝挂暮山。"]'),
('song-ci-966','蝶恋花','舒亶','宋','宋词','song-ci','蝶恋花','[]','雪后江城红日晚。',70,'宋词/ci.song.1000.json','["雪后江城红日晚。", "暖入香梢，渐觉玲珑满。", "仿佛临风妆半面。", "冰帘斜卷谁庭院。", "折向樽前君细看。", "便是江南，寄我人还远。", "手把此枝多少怨。", "小楼横笛吹肠断。"]'),
('song-ci-967','蝶恋花','舒亶','宋','宋词','song-ci','蝶恋花','[]','深炷熏炉扃小院。',70,'宋词/ci.song.1000.json','["深炷熏炉扃小院。", "手拈黄花，尚觉金犹浅。", "回首画堂双语燕。", "无情渐渐看人远。", "相见争如初不见。", "短鬓潘郎，斗觉年华换。", "最是西风吹不断。", "心头往事歌中怨。"]'),
('song-ci-968','减字木兰花','舒亶','宋','宋词','song-ci','减字木兰花','[]','眉山敛额。',52,'宋词/ci.song.1000.json','["眉山敛额。", "往事追思空手拍。", "雁字频飞。", "生怕人来说著伊。", "闲抛绣履。", "愁殢香衾浑不起。", "莫似扬州。", "只作寻常薄幸休。"]'),
('song-ci-969','减字木兰花','舒亶','宋','宋词','song-ci','减字木兰花','[]','碎红如绣。',52,'宋词/ci.song.1000.json','["碎红如绣。", "摇曳东风垂彩绶。", "拟倩柔条。", "约住佳人细柳腰。", "蜀江春绿。", "争似枝头能结束。", "纤手攀时。", "欲绾同心寄与谁。"]'),
('song-ci-970','木兰花','舒亶','宋','宋词','song-ci','木兰花','[]','十二阑干褰画箔。',64,'宋词/ci.song.1000.json','["十二阑干褰画箔。", "取次穿花成小酌。", "彩鸾舞罢凤孤飞，回首东风空院落。", "杳杳桃源仙路邈。", "晴日晓窗红薄薄。", "伤春还是懒梳妆，想见绿云垂鬓脚。"]'),
('song-ci-971','木兰花','舒亶','宋','宋词','song-ci','木兰花','["\u897f\u6e56"]','金丝络马青钱路。',64,'宋词/ci.song.1000.json','["金丝络马青钱路。", "笑指玉皇香案去。", "点衣柳陌堕残红，拂面风桥吹细雨。", "晓钗压鬓头慵举。", "恨里歌声兼别苦。", "西湖一顷白菱花，惆怅行云无觅处。"]'),
('song-ci-972','木兰花','舒亶','宋','宋词','song-ci','木兰花','[]','琉璃一片春湖面。',64,'宋词/ci.song.1000.json','["琉璃一片春湖面。", "画舫游人帘外见。", "水边风嫩柳低眠，花底雨乾莺细啭。", "秋千寂寂垂杨岸。", "芳草绿随人渐远。", "一番乐事又将离。", "金盏莫辞红袖劝。"]'),
('song-ci-973','浣溪沙','舒亶','宋','宋词','song-ci','浣溪沙','[]','燕外青楼已禁烟。',48,'宋词/ci.song.1000.json','["燕外青楼已禁烟。", "小寒犹自薄胜绵。", "画桥红日下秋千。", "惟有樽前芳意在，应须沈醉倒花前。", "绿窗还是五更天。"]'),
('song-ci-974','浣溪沙','舒亶','宋','宋词','song-ci','浣溪沙','[]','金缕歌残红烛稀。',48,'宋词/ci.song.1000.json','["金缕歌残红烛稀。", "梁州舞罢小鬟垂。", "酒醒还是独归时。", "画栋日高来语燕，绮窗风暖度游丝。", "几多落叶上青枝。"]'),
('song-ci-975','浣溪沙','舒亶','宋','宋词','song-ci','浣溪沙','[]','黑白纷纷小战争。',48,'宋词/ci.song.1000.json','["黑白纷纷小战争。", "几人心手斗纵横。", "谁知胜处本无情。", "谢傅老来思别墅，杜郎闲去忆鏖兵。", "何妨谈笑下辽城。"]'),
('song-ci-976','浣溪沙','舒亶','宋','宋词','song-ci','浣溪沙','[]','雨洗秋空斜日红。',48,'宋词/ci.song.1000.json','["雨洗秋空斜日红。", "青葱瑶辔玉玲珑。", "好风吹起□江东。", "且尽红裙歌一曲，莫辞白酒饮千锺。", "人生半在别离中。"]'),
('song-ci-977','浣溪沙','舒亶','宋','宋词','song-ci','浣溪沙','[]','白鹭飞飞点碧塘。',48,'宋词/ci.song.1000.json','["白鹭飞飞点碧塘。", "雨荷风卷绿罗裳。", "管弦竟奏杂鱼榔。", "游女谩能歌白纻，使君不学野鸳鸯。", "桃花空解误刘郎。"]'),
('song-ci-978','鹊桥仙','舒亶','宋','宋词','song-ci','鹊桥仙','[]','教来歌舞，接成桃李。',68,'宋词/ci.song.1000.json','["教来歌舞，接成桃李。", "尽是使君指似。", "如今装就满城春，忍便拥、双旌归去。", "莺心巧啭，花心争吐。", "无计可留君住。", "两堤芳草一江云，早晚是、西楼望处。"]'),
('song-ci-979','菩萨蛮','舒亶','宋','宋词','song-ci','菩萨蛮','[]','疏英乍蕾馀寒浅。',52,'宋词/ci.song.1000.json','["疏英乍蕾馀寒浅。", "蹋枝小鹊娇犹颤。", "谩炷水沈香。", "帘波不是湘。", "清愁支酒力。", "畏听江城笛。", "恁忍说华年。", "垂垂欲暮天。"]'),
('song-ci-980','好事近','舒亶','宋','宋词','song-ci','好事近','[]','箫鼓却微寒，犹是芳菲时节。',53,'宋词/ci.song.1000.json','["箫鼓却微寒，犹是芳菲时节。", "分付塞鸿归后，剩一钩寒月。", "双垂锦幄谢残枝，馀香恋衣结。", "又被鸟声呼醒，似征鞍催发。"]'),
('song-ci-981','失调名','舒亶','宋','宋词','song-ci','失调名','[]','十年马上春如梦。',8,'宋词/ci.song.1000.json','["十年马上春如梦。"]'),
('song-ci-982','导引','范祖禹','宋','宋词','song-ci','导引','[]','思齐文母，盛烈对皇天。',58,'宋词/ci.song.1000.json','["思齐文母，盛烈对皇天。", "演宝祚千年。", "卿云复旦治功全。", "厌人世登仙。", "龙舆忽掩三川。", "彩仗属车旋。", "维清象舞告英宣。", "入诗颂歌弦。"]'),
('song-ci-983','六州','范祖禹','宋','宋词','song-ci','六州','[]','太平功。',167,'宋词/ci.song.1000.json','["太平功。", "拥佑帝尧聪。", "歌九德，偃五戎。", "寰海被祥风。", "车书万里文轨同。", "自南北西东。", "耕田凿井，戏垂髫华发，跻仁寿域变时雍。", "大明方天中。", "弃养东朝苦匆匆。", "玉座如存，永隔慈容。", "恨难穷。", "崇庆空。", "飙轮仙驭无踪。", "超宇宙，驾云龙。", "褘翟掩轩宫。", "柏城王气长郁葱。", "温洛照寒崧。", "光灵在上，徽音流千古，昭如日月丽层穹。", "太任家邦隆。", "彤史青编永垂鸿。", "清庙笙镛。", "奏假钦崇。"]'),
('song-ci-984','十二时・忆少年','范祖禹','宋','宋词','song-ci','十二时・忆少年','[]','转招摇。',184,'宋词/ci.song.1000.json','["转招摇。", "厚陵回望，双阙起岧嶢。", "晓日丽谯。", "金爵上干霄。", "风雨阕，夜宫闭，不重朝。", "奉鸾镳渐遥。", "玉京知何处，飞英衔恤，乱絮缠悲，春路迢迢。", "缥缈哀音，发龙笳凤箫。", "光景同，惨淡度岩邑，指河桥。", "马萧萧。", "络绎星轺。", "拂天容卫，江海上寒潮。", "万国魂销。", "追昔御东朝。", "开钿扇，垂珠箔，侍珰貂。", "宝香烧。", "散飘。", "开仁寿域，神孙高拱，昆仑渤澥，玉烛方调。", "一旦宫车晚，旋归泬寥。", "九载初，如梦次，功得琼瑶。"]'),
('song-ci-985','虞神歌','范祖禹','宋','宋词','song-ci','虞神歌','[]','驾玉龙。',180,'宋词/ci.song.1000.json','["驾玉龙。", "设初虞祭终。", "前旌举，天回洛水，路转崧峰。", "瞻寥廓，烟霏冲融。", "窅无踪。", "震地鼓吹悲雄。", "谁何羽卫重。", "拂云旗帜眩青红。", "来渐东。", "清尘洒道，修职百神恭。", "回首苍茫醅雾雨吹风。", "掩泉宫。", "□□□□□□□□□寰畿入，山川改容。", "鼓钟临近次，千官望拜，涕泪衡从。", "人如堵，晨光葱茏。", "阙穹隆。", "驰道禁水相通。", "当年游幸空。", "皇仪事毕泣重瞳。", "哀未穷。", "巍巍馀烈，辉映简编中。", "亿万斯年，覆载同功。"]'),
('song-ci-986','导引','范祖禹','宋','宋词','song-ci','导引','[]','延和幄座，临御九年中。',60,'宋词/ci.song.1000.json','["延和幄座，临御九年中。", "往事已成空。", "皇基固覆盂四海，本自太任功。", "九虞初毕下西宫。", "庙祏与天崇。", "周家盛，卜年卜世，万祀永无穷。"]'),
('song-ci-987','千秋岁','孔平仲','宋','宋词','song-ci','千秋岁','[]','春风湖外。',87,'宋词/ci.song.1000.json','["春风湖外。", "红杏花初退。", "孤馆静，愁肠碎。", "泪馀痕在枕，别久香销带。", "新睡起。", "小园戏蝶飞成对。", "惆怅人谁会。", "随处聊倾盖。", "情暂遣，心何在。", "锦书消息断，玉漏花阴改。", "迟日暮，仙山杳杳空云海。"]'),
('song-ci-988','满庭芳','了元','宋','宋词','song-ci','满庭芳','[]','鳞甲何多，羽毛无数，悟来佛性皆同。',118,'宋词/ci.song.1000.json','["鳞甲何多，羽毛无数，悟来佛性皆同。", "世人何事，刚爱口头浓。", "痛把群生割剖，刀头转、鲜血飞红。", "□□□，零炮碎炙，不忍见渠侬。", "喉咙。", "才咽罢，龙肝凤髓，毕竟无踪。", "谩赢得、生前夭寿多凶。", "奉劝世人省悟，休恣意、激恼阎翁。", "轮回转，本来面目，改换片时中。"]'),
('song-ci-989','极相思令・极相思','太尉夫人','宋','宋词','song-ci','极相思令・极相思','[]','柳烟霁色方春。',60,'宋词/ci.song.1000.json','["柳烟霁色方春。", "花露逼金茎。", "秋千院落，海棠渐老，才过清明。", "嫩玉腕托香脂脸，相傅粉、更与谁情。", "秋波绽处，相思泪迸，天阻深诚。"]'),
('song-ci-990','醉翁操','郭祥正','宋','宋词','song-ci','醉翁操','[]','冷冷潺潺。',113,'宋词/ci.song.1000.json','["冷冷潺潺。", "寒泉。", "泻云间。", "如弹。", "醉翁洗心逃区寰。", "自期猿鹤俱闲。", "情未阑。", "日暮造深原。", "异芳谁与搴。", "忘还。", "琼楼玉阙，归去何年。", "遗风馀思，犹有猿吟鹤怨。", "花落溪边。", "萧然。", "莺语林中清圆。", "空山。", "春又残。", "客怀文章仙。", "度曲响涓涓。", "清商回徵星斗寒。"]'),
('song-ci-991','望江南・忆江南','董','宋','宋词','song-ci','望江南・忆江南','[]','缥缈烟中渔父桨，坡陀山上使君衙。',16,'宋词/ci.song.1000.json','["缥缈烟中渔父桨，坡陀山上使君衙。"]'),
('song-ci-992','望江南・忆江南','董','宋','宋词','song-ci','望江南・忆江南','[]','六月凉窗凉衽袖，二苏辞翰照青冥。',16,'宋词/ci.song.1000.json','["六月凉窗凉衽袖，二苏辞翰照青冥。"]'),
('song-ci-993','绛都春','丁仙现','宋','宋词','song-ci','绛都春','[]','融和又报。',122,'宋词/ci.song.1000.json','["融和又报。", "乍瑞霭霁色，皇州春早。", "翠幰竞飞，玉勒争驰都门道。", "鳌山彩结蓬莱岛。", "向晚色、双龙衔照。", "绛绡楼上，彤芝盖底，仰瞻天表。", "缥缈。", "风传帝乐，庆三殿共赏，群仙同到。", "迤逦御香，飘满人间闻嬉笑。", "须臾一点星球小。", "渐隐隐、鸣鞘声杳。", "游人月下归来，洞天未晓。"]'),
('song-ci-994','减字木兰花','刘泾','宋','宋词','song-ci','减字木兰花','["\u897f\u6e56"]','凭谁妙笔。',52,'宋词/ci.song.1000.json','["凭谁妙笔。", "横扫素缣三百尺。", "天下应无。", "此是钱塘湖上图。", "一般奇绝。", "云淡天高秋夜月。", "费尽丹青。", "只这些儿画不成。"]'),
('song-ci-995','夏初临','刘泾','宋','宋词','song-ci','夏初临','[]','泛水新荷，舞风轻燕，园林夏日初长。',120,'宋词/ci.song.1000.json','["泛水新荷，舞风轻燕，园林夏日初长。", "庭树阴浓，雏莺学弄新簧。", "小桥飞如横塘。", "跨青苹、绿藻幽香。", "朱阑斜倚，霜纨未摇，衣袂先凉。", "歌欢稀遇，怨别多同，路遥水远，烟淡梅黄。", "轻衫短帽，相携洞府流觞。", "况有红妆。", "醉归来、宝蜡成行。", "拂牙床。", "纱厨半开，月在回廊。"]'),
('song-ci-996','桂枝香','黄裳','宋','宋词','song-ci','桂枝香','[]','人烟一簇。',124,'宋词/ci.song.1000.json','["人烟一簇。", "正寄演，客飞升，翠微麓。", "楼阁参差，下瞰水天红绿。", "腰间剑去人安在，记千年、寸阴何速。", "山趋三岸，潭吞二水，岁丰人足。", "是处有、雕阑送目。", "更无限笙歌，芳酝初熟。", "休诧滕王看处，落霞孤鹜。", "雨中尤爱烟波上，见渔舟、来去相逐。", "数声歌向芦花，还疑是湘灵曲。"]'),
('song-ci-997','桂枝香','黄裳','宋','宋词','song-ci','桂枝香','[]','插云翠壁。',124,'宋词/ci.song.1000.json','["插云翠壁。", "为送目，入遥空，见山色。", "金鼎丹成去也，晋朝高客。", "百花岩下遗孙在，赋何人、离尘风骨。", "翠微缘近，希夷志远，洞天踪迹。", "近剑有、为龙信息。", "怪潭上灵光，雷电相击。", "尤好风波乍霁，鹭汀斜日。", "倚栏白尽行人鬓，但沈沈、群岫凝碧。", "利名休事蝇头，飞舠送君南北。"]'),
('song-ci-998','新荷叶','黄裳','宋','宋词','song-ci','新荷叶','[]','落日衔山，行云载雨俄鸣。',100,'宋词/ci.song.1000.json','["落日衔山，行云载雨俄鸣。", "一顷新荷，坐间疑是秋声。", "烟波醉客，见快哉、风恼娉婷。", "香和清点，为人吹在衣襟。", "珠佩欢言，放船且向前汀。", "绿伞红幢，自从天汉相迎。", "飞鸥独落，芦边对、几朵繁英。", "侑觞人唱，乍闻应似湘灵。"]'),
('song-ci-999','渔家傲','黄裳','宋','宋词','song-ci','渔家傲','[]','多幸春来云雨少。',72,'宋词/ci.song.1000.json','["多幸春来云雨少。", "且教月与花相照。", "清色真香庭院悄。", "前事杳。", "还嗟此景何时了。", "莫道难逢开口笑。", "夜游须趁人年少。", "光泛雕栏寒料峭。", "迂步绕。", "不劳秉烛壶天晓。"]'),
('song-ci-0','浣溪沙','范成大','宋','宋词','song-ci','浣溪沙','[]','白玉堂前绿绮疏。',48,'宋词/ci.song.10000.json','["白玉堂前绿绮疏。", "烛残歌罢困相扶。", "问人春思肯浓无。", "梦里粉香浮枕簟，觉来烟月满琴书。", "个浓情分更何如。"]'),
('song-ci-1','朝中措','范成大','宋','宋词','song-ci','朝中措','[]','东风半夜度关山。',57,'宋词/ci.song.10000.json','["东风半夜度关山。", "和雪到阑干。", "怪见梅梢未暖，情知柳眼犹寒。", "青丝菜甲，银泥饼饵，随分杯盘。", "已把宜春缕胜，更将长命题幡。"]'),
('song-ci-2','朝中措','范成大','宋','宋词','song-ci','朝中措','[]','身闲身健是生涯。',57,'宋词/ci.song.10000.json','["身闲身健是生涯。", "何况好年华。", "看了十分秋月，重阳更插黄花。", "消磨景物，瓦盆社酿，石鼎山茶。", "饱吃红莲香饭，侬家便是仙家。"]'),
('song-ci-3','朝中措','范成大','宋','宋词','song-ci','朝中措','[]','系船沽酒碧帘坊。',57,'宋词/ci.song.10000.json','["系船沽酒碧帘坊。", "酒满胜鹅黄。", "醉后西园入梦，东风柳色花香。", "水浮天处，夕阳如锦，恰似鲈乡。", "中有忆人双泪，几时流到横塘。"]'),
('song-ci-4','朝中措','范成大','宋','宋词','song-ci','朝中措','[]','海棠如雪殿春馀。',57,'宋词/ci.song.10000.json','["海棠如雪殿春馀。", "禽弄晚晴初。", "倦客长惭杜宇，佳辰且醉提壶。", "逍遥放浪，还他渔子，输与樵夫。", "一棹何时归去，扁舟终要江湖。"]'),
('song-ci-5','朝中措','范成大','宋','宋词','song-ci','朝中措','[]','天容云意写秋光。',57,'宋词/ci.song.10000.json','["天容云意写秋光。", "木叶半青黄。", "珍重西风祛暑，轻衫早怯新凉。", "故人情分，留连病客，孤负轻觞。", "陌上千愁易散，尊前一笑难忘。"]'),
('song-ci-6','蝶恋花','范成大','宋','宋词','song-ci','蝶恋花','[]','春涨一篙添水面。',70,'宋词/ci.song.10000.json','["春涨一篙添水面。", "芳草鹅儿，绿满微风岸。", "画舫夷犹湾百转。", "横塘塔近依前远。", "江国多寒农事晚。", "村北村南，谷雨才耕遍。", "秀麦连冈桑叶贱。", "看看尝面收新茧。"]'),
('song-ci-7','南柯子・南歌子','范成大','宋','宋词','song-ci','南柯子・南歌子','[]','槁项诗馀瘦，愁肠酒后柔。',62,'宋词/ci.song.10000.json','["槁项诗馀瘦，愁肠酒后柔。", "晚凉团扇欲知秋。", "卧看明河银影、界天流。", "鹤警人初静，虫吟夜更幽。", "佳辰只合算花筹。", "除了一天风月、更何求。"]'),
('song-ci-8','南柯子・南歌子','范成大','宋','宋词','song-ci','南柯子・南歌子','[]','怅望梅花驿，凝情杜若洲。',62,'宋词/ci.song.10000.json','["怅望梅花驿，凝情杜若洲。", "香云低处有高楼。", "可惜高楼、不近木兰舟。", "缄素双鱼远，题红片叶秋。", "欲凭江水寄离愁。", "江已东流、那肯更西流。"]'),
('song-ci-9','南柯子・南歌子','范成大','宋','宋词','song-ci','南柯子・南歌子','[]','银渚盈盈渡，金风缓缓吹。',62,'宋词/ci.song.10000.json','["银渚盈盈渡，金风缓缓吹。", "晚香浮动五云飞。", "月姊妒人、颦尽一弯眉。", "短夜难留处，斜河欲淡时。", "半愁半喜是佳期。", "一度相逢、添得两相思。"]'),
('song-ci-10','水调歌头','范成大','宋','宋词','song-ci','水调歌头','[]','细数十年事，十处过中秋。',114,'宋词/ci.song.10000.json','["细数十年事，十处过中秋。", "今年新梦，忽到黄鹤旧山头。", "老子个中不浅，此会天教重见，今古一南楼。", "星汉淡无色，玉镜独空浮。", "敛秦烟，收楚雾，熨江流。", "关河离合，南北依旧照清愁。", "想见姮娥冷眼，应笑归来双鬓，空敞黑貂裘。", "酾酒问蟾兔，肯去伴沧洲。"]'),
('song-ci-11','水调歌头','范成大','宋','宋词','song-ci','水调歌头','[]','万里汉家使，双节照清秋。',114,'宋词/ci.song.10000.json','["万里汉家使，双节照清秋。", "旧京行遍，中夜呼禹济黄流。", "寥落桑榆西北，无限太行紫翠，相伴过芦沟。", "岁晚客多病，风露冷貂裘。", "对重九，须烂醉，莫牢愁。", "黄花为我，一笑不管鬓霜羞。", "袖里天书咫尺，眼底关河百二，歌罢此生浮。", "惟有平安信，随雁到南州。"]'),
('song-ci-12','西江月','范成大','宋','宋词','song-ci','西江月','[]','十月谁云春小，一年两见风娇。',58,'宋词/ci.song.10000.json','["十月谁云春小，一年两见风娇。", "云英此夕度蓝桥。", "人意花枝都好。", "百媚朝天淡粉，六铢步月生绡。", "人间霜叶满庭皋，别有东风不老。"]'),
('song-ci-13','西江月','范成大','宋','宋词','song-ci','西江月','[]','北客开眉乐岁，东君著意华年。',58,'宋词/ci.song.10000.json','["北客开眉乐岁，东君著意华年。", "遮风藏雨晚云天。", "应怕杏梢红浅。", "不惜灯前放夜，从教雪后留寒。", "水晶帘箔万花钿。", "听彻南楼晓箭。"]'),
('song-ci-14','鹊桥仙','范成大','宋','宋词','song-ci','鹊桥仙','[]','双星良夜，耕慵织懒，应被群仙相妒。',68,'宋词/ci.song.10000.json','["双星良夜，耕慵织懒，应被群仙相妒。", "娟娟月姊满眉颦，更无奈、风姨吹雨。", "相逢草草，争如休见，重搅别离心绪。", "新欢不抵旧愁多，倒添了、新愁归去。"]'),
('song-ci-15','宜男草','范成大','宋','宋词','song-ci','宜男草','["\u6d1e\u5ead\u6e56"]','篱菊滩芦被霜后。',74,'宋词/ci.song.10000.json','["篱菊滩芦被霜后。", "袅长风、万重高柳。", "天为谁、展尽湖光渺渺，应为我、扁舟入手。", "橘中曾醉洞庭酒。", "辗云涛、挂帆南斗。", "追旧游、不减商山杳杳，犹有人、能相记否。"]'),
('song-ci-16','宜男草','范成大','宋','宋词','song-ci','宜男草','[]','舍北烟霏舍南浪。',70,'宋词/ci.song.10000.json','["舍北烟霏舍南浪。", "雪倾篱、雨荒薇涨。", "问小桥、别后谁过，惟有迷鸟羁雌来往。", "重寻山水问无恙。", "扫柴荆、土花尘网。", "留小桃、先试光风，从此芝草琅玕日长。"]'),
('song-ci-17','秦楼月・忆秦娥','范成大','宋','宋词','song-ci','秦楼月・忆秦娥','[]','窗纱薄。',56,'宋词/ci.song.10000.json','["窗纱薄。", "日穿红幔催梳掠。", "催梳掠。", "新晴天气，画檐闻鹊。", "海棠逗晓都开却。", "小云先在阑干角。", "阑干角。", "杨花满地，夜来风恶。"]'),
('song-ci-18','秦楼月・忆秦娥','范成大','宋','宋词','song-ci','秦楼月・忆秦娥','[]','珠帘狭。',56,'宋词/ci.song.10000.json','["珠帘狭。", "卷帘春院花围合。", "花围合。", "昼长人静，双双胡蝶。", "花前苦殢金蕉叶。", "瞢腾午睡扶头怯。", "扶头怯。", "闲愁无限，远山斜叠。"]'),
('song-ci-19','秦楼月・忆秦娥','范成大','宋','宋词','song-ci','秦楼月・忆秦娥','[]','香罗薄。',56,'宋词/ci.song.10000.json','["香罗薄。", "带围宽尽无人觉。", "无人觉。", "东风日暮，一帘花落。", "西园空锁秋千索。", "帘垂帘卷闲池阁。", "闲池阁。", "黄昏香火，画楼吹角。"]'),
('song-ci-20','秦楼月・忆秦娥','范成大','宋','宋词','song-ci','秦楼月・忆秦娥','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','楼阴缺。',56,'宋词/ci.song.10000.json','["楼阴缺。", "阑干影卧东厢月。", "东厢月。", "一天风露，杏花如雪。", "隔烟催漏金虬咽。", "罗帏暗淡灯花结。", "灯花结。", "片时春梦，江南天阔。"]'),
('song-ci-21','秦楼月・忆秦娥','范成大','宋','宋词','song-ci','秦楼月・忆秦娥','[]','浮云集。',56,'宋词/ci.song.10000.json','["浮云集。", "轻雷隐隐初惊蛰。", "初惊蛰。", "鹁鸠鸣怒，绿杨风急。", "玉炉烟重香罗浥。", "拂墙浓杏燕支湿。", "燕支湿。", "花梢缺处，画楼人立。"]'),
('song-ci-22','念奴娇','范成大','宋','宋词','song-ci','念奴娇','[]','双峰叠障，过天风海雨，无边空碧。',120,'宋词/ci.song.10000.json','["双峰叠障，过天风海雨，无边空碧。", "月姊年年应好在，玉阕琼宫愁寂。", "谁唤痴云，一杯为尽，夜气寒无色。", "碧城凝望，高楼飘渺西北。", "肠断桂冷蟾孤，佳期如梦，又把阑干拍。", "雾鬓风鬟相借问，浮世几回今夕。", "圆缺晴阴，古今同恨，我更长为客。", "婵娟明夜，尊前谁念南陌。"]'),
('song-ci-23','念奴娇','范成大','宋','宋词','song-ci','念奴娇','[]','十年旧事，醉京花蜀酒，万葩千萼。',120,'宋词/ci.song.10000.json','["十年旧事，醉京花蜀酒，万葩千萼。", "一棹归来吴下看，俯仰心情今昨。", "强倚雕阑，羞簪雪鬓，老恐花枝觉。", "揩摹愁眼，雾中相对依约。", "闻道家宴团栾，光风转夜，月傍西楼落。", "打彻梁州春自远，不饮何时欢乐。", "沾惹天香，留连国艳，莫散灯前酌。", "袜尘生处，为君重赋河洛。"]'),
('song-ci-24','念奴娇','范成大','宋','宋词','song-ci','念奴娇','[]','吴波浮动，看中流翻月，半江金碧。',120,'宋词/ci.song.10000.json','["吴波浮动，看中流翻月，半江金碧。", "醉舞空明三万顷，不管姮娥愁寂。", "指点琼楼，凭虚有路，鲸背横东极。", "水云飘荡，阑干千丈无力。", "家世回首沧洲，烟波渔钓，有鸱夷仙迹。", "一笑闲身游物外，来访扁舟消息。", "天上今宵，人间此地，我是风前客。", "涛生残夜，鱼龙惊听横笛。"]'),
('song-ci-25','念奴娇','范成大','宋','宋词','song-ci','念奴娇','[]','水乡霜落，望西山一寸，修眉横碧。',120,'宋词/ci.song.10000.json','["水乡霜落，望西山一寸，修眉横碧。", "南浦潮生帆影去，日落天青江白。", "万里浮云，被风吹散，又被风吹积。", "尊前歌罢，满空凝淡寒色。", "人世会少离多，都来名利，似蝇头蝉翼。", "赢得长亭车马路，千古羁愁如织。", "我辈情锺，匆匆相见，一笑真难得。", "明年谁健，梦魂飘荡南北。"]'),
('song-ci-26','念奴娇','范成大','宋','宋词','song-ci','念奴娇','[]','湖山如画，系孤篷柳岸，莫惊鱼鸟。',120,'宋词/ci.song.10000.json','["湖山如画，系孤篷柳岸，莫惊鱼鸟。", "料峭春寒花未遍，先共疏梅索笑。", "一梦三年，松风依旧，萝月何曾老。", "邻家相问，这回真个归到。", "绿鬓新点吴霜，尊前强健，不怕衰翁号。", "赖有风流车马客，来觅香云花岛。", "似我粗豪，不通姓字，只有银瓶倒。", "奔名逐利，乱帆谁在天表。"]'),
('song-ci-27','惜分飞','范成大','宋','宋词','song-ci','惜分飞','[]','易散浮云难再聚。',58,'宋词/ci.song.10000.json','["易散浮云难再聚。", "遮莫相随百步。", "谁唤行人去。", "石湖烟浪渔樵侣。", "重别西楼肠断否。", "多少凄风苦雨。", "休梦江南路。", "路长梦短无寻处。"]'),
('song-ci-28','梦玉人引','范成大','宋','宋词','song-ci','梦玉人引','[]','送行人去，犹追路、再相觅。',105,'宋词/ci.song.10000.json','["送行人去，犹追路、再相觅。", "天末交情，长是合堂同席。", "从此尊前，便顿然少个，江南羁客。", "不忍匆匆，少驻船梅驿。", "酒斟虽满，尚少如、别泪万千滴。", "欲语吞声，结心相对呜咽。", "冬火凄清，笙歌无颜色。", "从别后，尽相忘，算也难忘今夕。"]'),
('song-ci-29','梦玉人引','范成大','宋','宋词','song-ci','梦玉人引','[]','共登临处，飘风袂、倚空碧。',104,'宋词/ci.song.10000.json','["共登临处，飘风袂、倚空碧。", "雨卷云飞，长有桂娥看客。", "箫鼓生春，遍锦城如画，雪山无色。", "一梦才成，恍天涯南北。", "舞馀歌罢，料宣华、回首尽陈迹。", "万里秦吴，有情应问消息。", "我欲归耕，如何重来得。", "故人若望江南，且折梅花相忆。"]'),
('song-ci-30','如梦令','范成大','宋','宋词','song-ci','如梦令','[]','罨画屏中客住。',40,'宋词/ci.song.10000.json','["罨画屏中客住。", "水色山光无数。", "斜日满江声，何处撑来小渡。", "休去。", "休去。", "惊散一舟鸥鹭。"]'),
('song-ci-31','如梦令','范成大','宋','宋词','song-ci','如梦令','[]','两两莺啼何许。',40,'宋词/ci.song.10000.json','["两两莺啼何许。", "寻遍绿阴浓处。", "天气润罗衣，病起却忺微暑。", "休雨。", "休雨。", "明日榴花端午。"]'),
('song-ci-32','菩萨蛮','范成大','宋','宋词','song-ci','菩萨蛮','[]','小轩今日开窗了。',52,'宋词/ci.song.10000.json','["小轩今日开窗了。", "揉蓝染碧绿阶草。", "檐佩可怜风。", "杏梢烟雨红。", "飘零欢事少。", "鬓点吴霜早。", "天色不愁人。", "眼前无限春。"]'),
('song-ci-33','菩萨蛮','范成大','宋','宋词','song-ci','菩萨蛮','[]','雪林一夜收寒了。',52,'宋词/ci.song.10000.json','["雪林一夜收寒了。", "东风恰向灯前到。", "今夕是何年。", "新春新月圆。", "绮丛香雾隔。", "犹记疏狂客。", "留取缕金旛。", "夜蛾相并看。"]'),
('song-ci-34','菩萨蛮','范成大','宋','宋词','song-ci','菩萨蛮','[]','黄梅时节春萧索。',52,'宋词/ci.song.10000.json','["黄梅时节春萧索。", "越罗香润吴纱薄。", "丝雨日昽明。", "柳梢红未晴。", "多愁多病后。", "不识会中酒。", "愁病送春归。", "恰如中酒时。"]'),
('song-ci-35','临江仙','范成大','宋','宋词','song-ci','临江仙','[]','羽扇纶巾风袅袅，东厢月到蔷薇。',70,'宋词/ci.song.10000.json','["羽扇纶巾风袅袅，东厢月到蔷薇。", "新声谁唤出罗帏。", "龙须将笛绕，雁字入筝飞。", "陶写中年须个里，留连月扇云衣。", "周郎去后赏音稀。", "为君持酒听，那肯带春归。"]'),
('song-ci-36','临江仙','范成大','宋','宋词','song-ci','临江仙','[]','万事灰心犹薄宦，尘埃未免劳形。',70,'宋词/ci.song.10000.json','["万事灰心犹薄宦，尘埃未免劳形。", "故人相见似河清。", "恰逢梅柳动，高兴逐春生。", "卜昼匆匆还卜夜，仍须月坠河倾。", "明年我去白鸥盟。", "金闺三玉树，好问紫霄程。"]'),
('song-ci-37','减字木兰花','范成大','宋','宋词','song-ci','减字木兰花','[]','玉烟浮动。',52,'宋词/ci.song.10000.json','["玉烟浮动。", "银阕三山连海冻。", "翠袖阑干。", "不怕楼高酒力寒。", "双松冻折。", "忽忆衰翁容易别。", "想见鸥边。", "压损年时小钓船。"]'),
('song-ci-38','减字木兰花','范成大','宋','宋词','song-ci','减字木兰花','[]','折残金菊。',52,'宋词/ci.song.10000.json','["折残金菊。", "枨子香时新酒熟。", "谁伴芳尊。", "先问梅花借小春。", "道人破戒。", "染酒题诗金凤带。", "愁病相关。", "不似年时酒量宽。"]'),
('song-ci-39','减字木兰花','范成大','宋','宋词','song-ci','减字木兰花','[]','波娇鬓袅。',52,'宋词/ci.song.10000.json','["波娇鬓袅。", "中隐堂前人意好。", "不奈春何。", "拚却轻寒透薄罗。", "翦梅新曲。", "欲断还联三叠促。", "围坐风流。", "饶我尊前第一筹。"]'),
('song-ci-40','减字木兰花','范成大','宋','宋词','song-ci','减字木兰花','[]','枕书睡熟。',52,'宋词/ci.song.10000.json','["枕书睡熟。", "珍重月明相伴宿。", "宝鸭金寒。", "香满围屏宛转山。", "鸡人声杳。", "瑶井玉绳相对晓。", "黯淡窗纱。", "却下风帘护烛花。"]'),
('song-ci-41','减字木兰花','范成大','宋','宋词','song-ci','减字木兰花','[]','腊前三白。',52,'宋词/ci.song.10000.json','["腊前三白。", "春到西园还见雪。", "红紫花迟。", "借作东风万玉枝。", "归田计决。", "麦饭熟时应快活。", "身在高楼。", "心在山阴一叶舟。"]'),
('song-ci-42','鹧鸪天','范成大','宋','宋词','song-ci','鹧鸪天','[]','休舞银貂小契丹。',64,'宋词/ci.song.10000.json','["休舞银貂小契丹。", "满堂宾客尽关山。", "从今袅袅盈盈处，谁复端端正正看。", "模泪易，写愁难。", "潇湘江上竹枝斑。", "碧云日暮无书寄，寥落烟中一雁寒。"]'),
('song-ci-43','鹧鸪天','范成大','宋','宋词','song-ci','鹧鸪天','["\u897f\u6e56"]','荡漾西湖采绿苹。',64,'宋词/ci.song.10000.json','["荡漾西湖采绿苹。", "扬鞭南埭衮红尘。", "桃花暖日茸茸笑，杨柳光风浅浅颦。", "章贡水，郁孤云。", "多情争似桂江春。", "崔徽卷轴瑶姬梦，纵有相逢不是真。"]'),
('song-ci-44','鹧鸪天','范成大','宋','宋词','song-ci','鹧鸪天','[]','嫩绿重重看得成。',64,'宋词/ci.song.10000.json','["嫩绿重重看得成。", "曲栏幽槛小红英。", "酴醿架上蜂儿闹，杨柳行间燕子轻。", "春婉娩，客飘零。", "残花浅酒片时清。", "一杯且买明朝事，送了斜阳月又生。"]'),
('song-ci-45','鹧鸪天','范成大','宋','宋词','song-ci','鹧鸪天','[]','压蕊拈须粉作团。',64,'宋词/ci.song.10000.json','["压蕊拈须粉作团。", "疏香辛苦颤朝寒。", "须知风月寻常见，不似层层带雪看。", "春髻重，晓眉弯。", "一枝斜并缕金旛。", "酒红不解东风冻，惊怪钗头玉燕乾。"]'),
('song-ci-46','好事近','范成大','宋','宋词','song-ci','好事近','[]','云暮暗千山，肠断玉楼金阕。',53,'宋词/ci.song.10000.json','["云暮暗千山，肠断玉楼金阕。", "应是高唐小妇，妒姮娥清绝。", "夜凉不放酒杯寒，醉眼渐生缬。", "何待桂花相照，有人人如月。"]'),
('song-ci-47','好事近','范成大','宋','宋词','song-ci','好事近','[]','昨夜报春来，的皪岭梅开雪。',53,'宋词/ci.song.10000.json','["昨夜报春来，的皪岭梅开雪。", "携手玉人同赏，比看谁奇绝。", "阑干倚遍忆多情，怕角声呜咽。", "与折一枝斜戴，衬鬓云梳月。"]'),
('song-ci-48','卜算子','范成大','宋','宋词','song-ci','卜算子','[]','凉夜竹堂虚，小睡匆匆醒。',52,'宋词/ci.song.10000.json','["凉夜竹堂虚，小睡匆匆醒。", "银漏无声月上阶，满地阑干影。", "何处最知秋，风在梧桐井。", "不惜骖鸾弄玉箫，露湿衣裳冷。"]'),
('song-ci-49','卜算子','范成大','宋','宋词','song-ci','卜算子','[]','云压小桥深，月到重门静。',52,'宋词/ci.song.10000.json','["云压小桥深，月到重门静。", "冷蕊疏枝半不禁，更著横窗影。", "回首故园春，往事难重省。", "半夜清香入梦来，从此熏炉冷。"]'),
('song-ci-50','三登乐','范成大','宋','宋词','song-ci','三登乐','[]','一碧鳞鳞，横万里、天垂吴楚。',91,'宋词/ci.song.10000.json','["一碧鳞鳞，横万里、天垂吴楚。", "四无人、橹声自语。", "向浮云、西下处，水村烟树。", "何处系船，暮涛涨浦。", "正江南、遥落后，好山无数。", "尽乘流、兴来便去。", "对青灯、独自叹，一生羁旅。", "敧枕梦寒，又还夜雨。"]'),
('song-ci-51','三登乐','范成大','宋','宋词','song-ci','三登乐','[]','路转横塘，风卷地、水肥帆饱。',91,'宋词/ci.song.10000.json','["路转横塘，风卷地、水肥帆饱。", "眼双明、旷怀浩渺。", "问菟裘、无恙否，天教重到。", "木落雾收，故山更好。", "过溪门、休荡桨，恐惊鱼鸟。", "算年来、识翁者少。", "喜山林、踪迹在，何曾如扫。", "归宾任霜，醉红未老。"]'),
('song-ci-52','三登乐','范成大','宋','宋词','song-ci','三登乐','[]','今夕何朝，披岫幌、云关重启。',91,'宋词/ci.song.10000.json','["今夕何朝，披岫幌、云关重启。", "引冰壶、素空似洗。", "卷帘中、敧枕上，月星浮水。", "天镜夜明，半窗万里。", "盼庭柯、都老大，树犹如此。", "六年前、转头未几。", "唤邻翁、来话旧，同篘新蚁。", "秉烛夜阑，又疑梦里。"]'),
('song-ci-53','三登乐','范成大','宋','宋词','song-ci','三登乐','[]','方帽卫寒，重检校、旧时农圃。',90,'宋词/ci.song.10000.json','["方帽卫寒，重检校、旧时农圃。", "荒三径、不知何许。", "但姑苏台下，有苍然平楚。", "人笑此翁，又来访古。", "况五湖、元自有，扁舟祖武。", "记沧洲、白鸥伴侣。", "叹年来、孤负了，一蓑烟雨。", "寂寞暮潮，唤回棹去。"]'),
('song-ci-54','浪淘沙','范成大','宋','宋词','song-ci','浪淘沙','[]','黯淡养花天。',64,'宋词/ci.song.10000.json','["黯淡养花天。", "小雨能悭。", "烟轻云薄有无间。", "官柳丝丝都绿遍，犹有春寒。", "空翠湿征鞍。", "马首千山。", "多情若是肯俱还。", "别有玉杯承露冷，留共君看。"]'),
('song-ci-55','虞美人','范成大','宋','宋词','song-ci','虞美人','[]','霜馀好探梅消息。',66,'宋词/ci.song.10000.json','["霜馀好探梅消息。", "日日溪桥侧。", "不如君有似梅人。", "歌里工颦妍笑、两眉春。", "疏枝冷蕊风情少。", "却称衰翁老。", "从教来作静中邻。", "冷淡无言无笑、也无颦。"]'),
('song-ci-56','虞美人','范成大','宋','宋词','song-ci','虞美人','[]','落梅时节冰轮满。',66,'宋词/ci.song.10000.json','["落梅时节冰轮满。", "何似中秋看。", "琼楼玉宇一般明。", "只为姮娥、添了万枝灯。", "锦江城下杯残后。", "还照鄞江酒。", "天东相见说天西。", "除却衰翁和月、更谁知。"]'),
('song-ci-57','虞美人','范成大','宋','宋词','song-ci','虞美人','[]','玉箫惊报同云重。',66,'宋词/ci.song.10000.json','["玉箫惊报同云重。", "仍怪金瓶冻。", "清明将近雪花翻。", "不道海堂消瘦、柳丝寒。", "王孙沈醉狨毡幕。", "谁怕罗衣薄。", "烛灯香雾两厌厌。", "仿佛有人愁损、上眉尖。"]'),
('song-ci-58','虞美人','范成大','宋','宋词','song-ci','虞美人','[]','谁将击碎珊瑚玉。',66,'宋词/ci.song.10000.json','["谁将击碎珊瑚玉。", "装上交枝粟。", "恰如娇小万琼妃。", "涂罢额黄、嫌怕污燕支。", "夜深未觉清香绝。", "风露溶溶月。", "满身花影弄凄凉。", "无限月和风露、一齐香。"]'),
('song-ci-59','醉落魄・一斛珠','范成大','宋','宋词','song-ci','醉落魄・一斛珠','[]','春城胜绝。',67,'宋词/ci.song.10000.json','["春城胜绝。", "暮林风舞催花发。", "垂云卷尽添空阔。", "吹上新年，美满十分月。", "红蕖影下勾丝抹。", "老来牵强随时节。", "无人知道心情别。", "唯有蛾儿，惊见鬓边雪。"]'),
('song-ci-60','步虚词・西江月','范成大','宋','宋词','song-ci','步虚词・西江月','[]','珠霄境，却似化人宫。',32,'宋词/ci.song.10000.json','["珠霄境，却似化人宫。", "梵气弥罗融万象，玉楼十二倚清空。", "一片宝光中。"]'),
('song-ci-61','步虚词・西江月','范成大','宋','宋词','song-ci','步虚词・西江月','[]','浮黎路，依约太微间。',32,'宋词/ci.song.10000.json','["浮黎路，依约太微间。", "雪色宝阶千万丈，人间遥作白虹看。", "幢节度高寒。"]'),
('song-ci-62','步虚词・西江月','范成大','宋','宋词','song-ci','步虚词・西江月','[]','罡风起，背负玉虚廷。',32,'宋词/ci.song.10000.json','["罡风起，背负玉虚廷。", "九素烟中寒一色，扶阑四面是青冥。", "环拱万珠星。"]'),
('song-ci-63','步虚词・西江月','范成大','宋','宋词','song-ci','步虚词・西江月','[]','流铃响，龙驭籋云来。',32,'宋词/ci.song.10000.json','["流铃响，龙驭籋云来。", "夹道骞华龙彩仗，红云扶辂辗天街。", "迎驾鹤毰毸。"]'),
('song-ci-64','步虚词・西江月','范成大','宋','宋词','song-ci','步虚词・西江月','[]','钧天奏，流韵满空明。',32,'宋词/ci.song.10000.json','["钧天奏，流韵满空明。", "琪树玲珑珠网碎，仙风吹作步虚声。", "相和八鸾鸣。"]'),
('song-ci-65','步虚词・西江月','范成大','宋','宋词','song-ci','步虚词・西江月','[]','楼阑外，辇道插非烟。',32,'宋词/ci.song.10000.json','["楼阑外，辇道插非烟。", "闲上郁萧台上看，空歌来自始青天。", "扬袂揖飞仙。"]'),
('song-ci-66','玉楼春','范成大','宋','宋词','song-ci','玉楼春','[]','佳人无对甘幽独。',64,'宋词/ci.song.10000.json','["佳人无对甘幽独。", "竹雨松风相澡浴。", "山深翠袖自生寒，夜久玉肌元不粟。", "却寻千树烟江曲。", "道骨仙风终绝俗。", "绛裙缟袂各朝元，只有散仙名萼绿。"]'),
('song-ci-67','霜天晓角','范成大','宋','宋词','song-ci','霜天晓角','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','晚晴风歇。',54,'宋词/ci.song.10000.json','["晚晴风歇。", "一夜春折威。", "脉脉花疏天淡，云来去、数枝雪。", "胜绝。", "愁亦绝。", "此情谁共说。", "惟有两行低雁，知人倚、画楼月。"]'),
('song-ci-68','玉楼春','范成大','宋','宋词','song-ci','玉楼春','[]','云横水绕芳尘陌。',64,'宋词/ci.song.10000.json','["云横水绕芳尘陌。", "一万重花春拍拍。", "蓝桥仙路不崎岖，醉舞狂歌容倦客。", "真香解语人倾国。", "知是紫云谁敢觅。", "满蹊桃李不能言，分付仙家君莫惜。"]'),
('song-ci-69','醉落魄・一斛珠','范成大','宋','宋词','song-ci','醉落魄・一斛珠','[]','马蹄尘扑。',67,'宋词/ci.song.10000.json','["马蹄尘扑。", "春风得意笙歌逐。", "款门不问谁家竹。", "只拣红装，高处烧银烛。", "碧鸡坊里花如屋。", "燕王宫下花成谷。", "不须悔唱关山曲。", "只为海棠，也合来西蜀。"]'),
('song-ci-70','菩萨蛮','范成大','宋','宋词','song-ci','菩萨蛮','[]','冰明玉润天然色。',52,'宋词/ci.song.10000.json','["冰明玉润天然色。", "凄凉拼作西风客。", "不肯嫁东风。", "殷勤霜露中。", "绿窗梳洗晚。", "笑把玻璃盏。", "斜日上妆台。", "酒红和困来。"]'),
('song-ci-71','眼儿媚','范成大','宋','宋词','song-ci','眼儿媚','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','酣酣日脚紫烟浮。',58,'宋词/ci.song.10000.json','["酣酣日脚紫烟浮。", "妍暖破轻裘。", "困人天色，醉人花气，午梦扶头。", "春慵恰似春塘水，一片縠纹愁。", "溶溶泄泄，东风无力，欲皱还休。"]'),
('song-ci-72','惜分飞','范成大','宋','宋词','song-ci','惜分飞','[]','画戟锦车皆雅故。',58,'宋词/ci.song.10000.json','["画戟锦车皆雅故。", "箫鼓留连客住。", "南浦春波暮。", "难望罗袜生尘处。", "明日船旗应不驻。", "且唱断肠新句。", "卷尽珠帘雨。", "雪花一夜随人去。"]'),
('song-ci-73','菩萨蛮','范成大','宋','宋词','song-ci','菩萨蛮','[]','客行忽到湘东驿。',52,'宋词/ci.song.10000.json','["客行忽到湘东驿。", "明朝真是潇湘客。", "晴碧万重云。", "几时逢故人。", "江南如塞北。", "别后书难得。", "先自雁来稀。", "那堪春半时。"]'),
('song-ci-74','满江红','范成大','宋','宋词','song-ci','满江红','[]','千古东流，声卷地、云涛如屋。',115,'宋词/ci.song.10000.json','["千古东流，声卷地、云涛如屋。", "横浩渺、樯竿十丈，不胜帆腹。", "夜雨翻江春浦涨，船头鼓急风初熟。", "似当年、呼禹乱黄川，飞梭速。", "击楫誓，空惊俗。", "休拊髀，都生肉。", "任炎天冰海，一杯相属。", "荻笋蒌芽新入馔，鵾弦凤吹能翻曲。", "笑人间、何处似尊前，添银烛。"]'),
('song-ci-75','谒金门','范成大','宋','宋词','song-ci','谒金门','[]','塘水碧。',53,'宋词/ci.song.10000.json','["塘水碧。", "仍带麴尘颜色。", "泥泥縠纹无气力。", "东风如爱惜。", "恰似越来溪侧。", "也有一双鸂鶒。", "只欠柳丝千百尺。", "系船春弄笛。"]'),
('song-ci-76','秦楼月・忆秦娥','范成大','宋','宋词','song-ci','秦楼月・忆秦娥','[]','湘江碧。',56,'宋词/ci.song.10000.json','["湘江碧。", "故人同作湘中客。", "湘中客。", "东风回雁，杏花寒食。", "温温月到蓝桥侧。", "醒心弦里春无极。", "春无极。", "明朝残梦，马嘶南陌。"]'),
('song-ci-77','醉落魄・一斛珠','范成大','宋','宋词','song-ci','醉落魄・一斛珠','[]','雪晴风作。',67,'宋词/ci.song.10000.json','["雪晴风作。", "松梢片片轻鸥落。", "玉楼天半褰珠箔。", "一笛梅花，吹裂冻云幕。", "去年小猎漓山脚。", "弓刀湿遍犹横槊。", "今年翻怕貂裘薄。", "寒似去年，人比去年觉。"]'),
('song-ci-78','霜天晓角','范成大','宋','宋词','song-ci','霜天晓角','[]','少年豪纵。',53,'宋词/ci.song.10000.json','["少年豪纵。", "袍锦团花凤。", "曾是京城游子，驰宝马、飞金鞚。", "旧游浑似梦。", "鬓点吴霜重。", "多少燕情莺意，都泻入、玻璃瓮。"]'),
('song-ci-79','菩萨蛮','范成大','宋','宋词','song-ci','菩萨蛮','[]','彤楼鼓密催金轮。',52,'宋词/ci.song.10000.json','["彤楼鼓密催金轮。", "沈沈青琐重重幕。", "宣唤晚朝天。", "五云笼暝烟。", "风急东华路。", "暖扇遮微雨。", "香雾扑人衣。", "上林乌满枝。"]'),
('song-ci-80','水调歌头','范成大','宋','宋词','song-ci','水调歌头','[]','万里汉都护。',10,'宋词/ci.song.10000.json','["万里汉都护。", "（下缺）"]'),
('song-ci-81','水调歌头','范成大','宋','宋词','song-ci','水调歌头','[]','万里桥边客。',10,'宋词/ci.song.10000.json','["万里桥边客。", "（下缺）"]'),
('song-ci-82','水调歌头','范成大','宋','宋词','song-ci','水调歌头','[]','万里吴船泊，归访菊篱秋。',16,'宋词/ci.song.10000.json','["万里吴船泊，归访菊篱秋。", "（下缺）"]'),
('song-ci-83','醉落魄・一斛珠','范成大','宋','宋词','song-ci','醉落魄・一斛珠','[]','栖乌飞绝。',68,'宋词/ci.song.10000.json','["栖乌飞绝。", "绛河绿雾星明灭。", "烧香曳簟眠清樾。", "花久影吹笙，满地淡黄月。", "好风碎竹声如雪。", "昭华三弄临风咽。", "鬓丝撩乱纶巾折。", "凉满北窗，休共软红说。"]'),
('song-ci-84','朝中措','范成大','宋','宋词','song-ci','朝中措','[]','长年心事寄林扃。',57,'宋词/ci.song.10000.json','["长年心事寄林扃。", "尘鬓已星星。", "芳意不如水远，归心欲与云平。", "留连一醉，花残日永，雨后山明。", "从此量船载酒，莫教闲却春情。"]'),
('song-ci-85','水龙吟','范成大','宋','宋词','song-ci','水龙吟','[]','仙翁家在丛霄，五云八景来尘表。',126,'宋词/ci.song.10000.json','["仙翁家在丛霄，五云八景来尘表。", "黄扉紫闼，化钧高妙，风霆挥扫。", "漠北寒烟，峤南和气，笑谈都了。", "自玉麟归去，金牛再款，却回首、人间少。", "天与丹台旧籍，笑苍生、祝公难老。", "春葩秋叶，喧寒易变，壶天长好。", "物外新闻，凤歌鸾翥，龙蟠虎绕。", "想如心高会，寒霜夜永，尽横参晓。"]'),
('song-ci-86','满江红','范成大','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','山绕西湖，曾同泛、一篙春绿。',115,'宋词/ci.song.10000.json','["山绕西湖，曾同泛、一篙春绿。", "重会面、未温往事，先翻新曲。", "劲柏乔松霜雪后，知心惟有孤生竹。", "对荒园、犹解两高歌，空惊俗。", "人更健，情逾熟。", "樱共柳，冰和玉。", "恐相逢如梦，夜阑添烛，别后书来空怅望，尊前酒到休拘束。", "笑簟瓢、未足已能狂，那堪足。"]'),
('song-ci-87','青玉案','王质','宋','宋词','song-ci','青玉案','[]','中央自有仙风度。',78,'宋词/ci.song.10000.json','["中央自有仙风度。", "散入千林去。", "万点秋芳洒飞露。", "舜裳赭色，尧眉黄彩，化作花无数。", "层层翠葆鸾旗舞。", "吹下天香遍瑶宇。", "万岁千秋奉明主。", "桂华月苑，蕊珠宝殿，长听黄金缕。"]'),
('song-ci-88','青玉案','王质','宋','宋词','song-ci','青玉案','[]','浮萍不碍鱼行路。',78,'宋词/ci.song.10000.json','["浮萍不碍鱼行路。", "细数鱼来去。", "静倚溪阴深觅句。", "碧鲜清润，影摇香度。", "易觉阑干暮。", "凫雏深傍苹根住。", "浴罢红衣褪残缕。", "一寸江湖无可付。", "渚兰汀草，卧烟敧雨。", "荒了垂纶处。"]'),
('song-ci-89','江城子','王质','宋','宋词','song-ci','江城子','[]','细风微揭碧鳞鳞。',86,'宋词/ci.song.10000.json','["细风微揭碧鳞鳞。", "绣帏深。", "不闻声。", "时见推帘，笼袖玉轻轻。", "不似绮楼高卷幔，相指点，总分明。", "斜湾丛柳暗阴阴。", "且消停。", "莫催行。", "只恨夕阳，虽好近黄昏。", "得到钗梁容略住，无分做，小蜻蜓。"]'),
('song-ci-90','江城子','王质','宋','宋词','song-ci','江城子','[]','细风吹起翠田田。',86,'宋词/ci.song.10000.json','["细风吹起翠田田。", "雨和烟。", "入梅天。", "鲜润繁阴，悄悄转清圆。", "十顷蒲萄深贮碧，鸥共鹭，各翩翩。", "影摇香度小婵娟。", "竹林贤。", "总神仙。", "滴露飞霜，雪壑注冰泉。", "伴了芙蓉城里客，无一事，北窗眠。"]'),
('song-ci-91','江城子','王质','宋','宋词','song-ci','江城子','[]','柳梢无雪受风吹。',86,'宋词/ci.song.10000.json','["柳梢无雪受风吹。", "绿垂垂。", "乳鸦啼。", "直下蒲萄，春水未平堤。", "却似今年春气早，白团扇，已相宜。", "红巾当日鸟衔飞。", "曲江湄。", "暮春时。", "孔雀麒麟，交蹙绣罗衣。", "何似野堂陪胜客，花影外，竹影移。"]'),
('song-ci-92','蓦山溪','王质','宋','宋词','song-ci','蓦山溪','[]','枯林荒陌，矮树敷鲜叶。',102,'宋词/ci.song.10000.json','["枯林荒陌，矮树敷鲜叶。", "不见雅风标，十二分、山容野色。", "因何嫩茁，舞动小旗枪，梅花后，杏花前，色味香三绝。", "含光隐耀，尘土埋豪杰。", "试看大粗疏，争知变、寒云飞雪。", "休说休说，世只两名花，芍药相，牡丹王，未尽人间舌。"]'),
('song-ci-93','满江红','王质','宋','宋词','song-ci','满江红','[]','方丈维摩，蒙衲被、都齐不省。',115,'宋词/ci.song.10000.json','["方丈维摩，蒙衲被、都齐不省。", "空怅望、锦裘绣帽，玉珂金镫。", "十月小春逢此日，一时胜事输公等。", "问短衣、匹马射南山，何人肯。", "山暮紫，峰如笋。", "江寒碧，沙如粉。", "望塞鸿杳杳，水遥天永。", "饮罢不妨瓶屡卧，归来自有风吹醒。", "试断桥、流水月明边，寻疏影。"]'),
('song-ci-94','满江红','王质','宋','宋词','song-ci','满江红','[]','整顿乾坤，恨无袖、回旋不足。',115,'宋词/ci.song.10000.json','["整顿乾坤，恨无袖、回旋不足。", "须付与、腰金叠赤，面槐参绿。", "功业岂无人可了，英豪自有心相伏。", "自孤窗、寒烛听经纶，常三复。", "举大白，倾醽醁。", "为公起，歌此曲。", "曲中意惟有，斯贤堪属。", "萱草喜除烦恼障，莲花妙享清凉福。", "愿年年、团扇弄生绡，长如玉。"]'),
('song-ci-95','满江红','王质','宋','宋词','song-ci','满江红','[]','惨淡轻阴，都养就、朱朱白白。',115,'宋词/ci.song.10000.json','["惨淡轻阴，都养就、朱朱白白。", "最好是、梨花带雨，海棠映日。", "暖雾烘成芳草色，娇风分与垂杨力。", "听红边、翠杪啭清圆，曾相识。", "春绪乱，还如织。", "春梦断，还堪觅。", "看青梅下有，游人啧啧。", "爱酒正香须满泛，怜花太嫩休轻摘。", "把领巾、收聚众香浓，凭风立。"]'),
('song-ci-96','满江红','王质','宋','宋词','song-ci','满江红','[]','生縠平铺，吹不起、轻风无力。',115,'宋词/ci.song.10000.json','["生縠平铺，吹不起、轻风无力。", "西江上、斗牛相射，水天一色。", "二妙风流今代少，一时光价何时息。", "更绛霄、白日下云軿，芙蓉客。", "整飞驭，成得得。", "寻前约、宽忆忆。", "正云飞雨卷，旧红新碧。", "茁茁抽长荷柄绿，毵毵吐净杨花白。", "渐衣篝、香润入梅天，红绡湿。"]'),
('song-ci-97','满江红','王质','宋','宋词','song-ci','满江红','[]','莽莽云平，都不辨、近山远水。',115,'宋词/ci.song.10000.json','["莽莽云平，都不辨、近山远水。", "尽徘徊、尚留波面，未归湾尾。", "浪猛深深鸥抱稳，波寒缩缩鱼沈底。", "恐狂风、颠雨岸多摧，舟难舣。", "船篷重，拖不起。", "蓑衣湿，森如洗。", "想杖头未足，杯中无计。", "渔网吹翻无把捉，钓竿冻断成抛弃。", "到高歌、风静月明时，谁如你。"]'),
('song-ci-98','满江红','王质','宋','宋词','song-ci','满江红','[]','落尽斜阳，尚有些、断霞残影。',115,'宋词/ci.song.10000.json','["落尽斜阳，尚有些、断霞残影。", "甚弯环、东溪西巷，南岩北岭。", "行熟更教羊引著，睡浓却被鸦惊醒。", "渐孤村、树暗颤山敧，霜风冷。", "人世里，嫌他蠢。", "牛背上，输他稳。", "但芒鞋一緉，蓑衣一领。", "五脏荒陂蔬荐口，双髽幽崦花漫顶。", "虽云乌、月黑路蒙笼，何曾窘。"]'),
('song-ci-99','满江红','王质','宋','宋词','song-ci','满江红','[]','纸张梅花，有丛桂、又有修竹。',118,'宋词/ci.song.10000.json','["纸张梅花，有丛桂、又有修竹。", "是何声、雪飘远渚，泉鸣幽谷。", "红蓼白苹须拂袖，馀音尚带清香馥。", "挽素娥青女、问飞琼，谁家曲。", "韩退之，欧永叔。", "惚兮恍，恍兮惚。", "试侧耳，山常似黛，水常如玉。", "颜子操中何足怨，醉翁徽外无人续。", "正青天、明月上东南，芳时足。"]'),
('song-ci-100','水调歌头','王质','宋','宋词','song-ci','水调歌头','[]','江水去无极，无地有青天。',113,'宋词/ci.song.10000.json','["江水去无极，无地有青天。", "怒涛汹涌，卷浪成雪蔽长川。", "一望扬州苍莽，隐见烟竿双矗，何处卷珠帘。", "落日瓜洲渡，鸿鹭满风前。", "古战场，皆白草，更苍烟。", "清平犹有遗恨，久矣在江边。", "北固山前三杰，遥想当年意气，□□昵中原。", "上马促归去，风堕接罗翩"]'),
('song-ci-101','水调歌头','王质','宋','宋词','song-ci','水调歌头','[]','细数十年梦，十处过中秋。',114,'宋词/ci.song.10000.json','["细数十年梦，十处过中秋。", "今年清梦，还在黄鹤旧楼头。", "老子个中不浅，此会天教重见，今古一南楼。", "星汉淡无色，玉锦倚空浮。", "带秦烟，萦楚雾，熨江流。", "关河离合南北，依旧照清愁。", "想见姮娥冷笑，笑我归来霜鬓，空敝黑貂裘。", "把酒问清影，肯去伴沧洲。"]'),
('song-ci-102','水调歌头','王质','宋','宋词','song-ci','水调歌头','[]','晚嶂倚斜日，秋树战悲风。',114,'宋词/ci.song.10000.json','["晚嶂倚斜日，秋树战悲风。", "一泓绀紫澄碧，中有睡蛟龙。", "散作清溪明玉，激上长松流水，雨电乱寒空。", "抛却红尘袂，飞入妙光宫。", "佛国大，天溥博，地含洪。", "空岩乱壑递响，珠影动金容。", "万古碧潭空界，一点青霄明月，涝漉总无功。", "云散殿突兀，风动铎丁东。"]'),
('song-ci-103','水调歌头','王质','宋','宋词','song-ci','水调歌头','[]','草蔓已多露，松竹总含风。',114,'宋词/ci.song.10000.json','["草蔓已多露，松竹总含风。", "群山左顾右盼，如虎更如龙。", "时见渔灯三两，知在谁家浦溆，星斗烂垂空。", "万有付一扫，人世等天宫。", "秋萧瑟，林脱叶，水归洪。", "江湖飘泊鸿雁，洲渚肯相容。", "要使群生安堵，不听三更吠犬，此则是奇功。", "一任画麟阁，吾自老墙东。"]'),
('song-ci-104','水调歌头','王质','宋','宋词','song-ci','水调歌头','[]','云巘在空碧，天宇共高明。',114,'宋词/ci.song.10000.json','["云巘在空碧，天宇共高明。", "重阳易得风雨，今日不胜晴。", "天为两朝元老，付与四时佳节，不动一丝尘。", "香霭洗金戟，飞雾洒霓旌。", "山鸣叶，江动石，总欢声。", "剑关玉垒千载，谁见此升平。", "细看尊前万蕊，相映眉间一点，黄气郁骎骎。", "江汉下淮海，都赖一长城。"]'),
('song-ci-105','水调歌头','王质','宋','宋词','song-ci','水调歌头','[]','花上插苍碧，花下走清湍。',114,'宋词/ci.song.10000.json','["花上插苍碧，花下走清湍。", "浓霜深覆残雪，更有月相参。", "似我竹溪茅屋，欲晓未明天气，扶杖绕篱看。", "秦楚五千里，何处是江南。", "饶风下，人不断，马相连。", "颇尝见有此客，相属意惓惓。", "欲为横吹出塞，无处可寻羌管，短策叩征鞍。", "策断征鞍裂，惊坠玉毵毵。"]'),
('song-ci-106','水调歌头','王质','宋','宋词','song-ci','水调歌头','[]','淮海一星出，分野到梁州。',114,'宋词/ci.song.10000.json','["淮海一星出，分野到梁州。", "玉京群帝朝斗，公在列仙流。", "尽扫欃枪格泽，高拱紫微太乙，霞佩拂红裯。", "非雾非烟里，永侍绀云裘。", "日南至，月既望，寿君侯。", "梅花满眼，一朵聊当一千秋。", "半夜玉堂承诏，翼旦路朝宣册，归去作班头。", "风静瞿塘峡，安稳放行舟。"]'),
('song-ci-107','水调歌头','王质','宋','宋词','song-ci','水调歌头','[]','河汉湛秋碧，玉露嗳瑶空。',114,'宋词/ci.song.10000.json','["河汉湛秋碧，玉露嗳瑶空。", "太清仙子，飘渺飞佩响玲珑。", "暂驭青鸾紫凤，来玩十洲三岛，旌旆卷芙蓉。", "身在大江表，名系绛霄宫。", "两仙客，歌驻月，舞迥风。", "宝薰轻度帘幕，香雾结重重。", "已觉长安近日，会看此星朝斗，千载庆云龙。", "翠霭彤烟里，长侍衮衣红。"]'),
('song-ci-108','八声甘州','王质','宋','宋词','song-ci','八声甘州','[]','海茫茫、天北与天南，吾友定安归。',119,'宋词/ci.song.10000.json','["海茫茫、天北与天南，吾友定安归。", "闻濡须江上，皖公山下，驾白云飞。", "莽苍空郊虚野，古路立斜晖。", "颜跖皆尘土，苦泪休挥。", "一代锦肠绣肺，想英魂皎皎，健口霏霏。", "望寒空明月，无路寄相思。", "叹千古、兴亡成败，满乾坤、遗恨有谁知。", "今何在，一川烟惨，万壑风悲。"]'),
('song-ci-109','八声甘州','王质','宋','宋词','song-ci','八声甘州','[]','事茫茫、赤壁半帆风，四海忽三分。',118,'宋词/ci.song.10000.json','["事茫茫、赤壁半帆风，四海忽三分。", "想苍烟金虎，碧云铜爵，恨满乾坤。", "郁郁秣陵王气，传到第三孙。", "风虎云龙会，自有其人。", "朱颜二十有四，正锦帏秋梦，玉帐春声。", "望吴江楚汉，明月伴英魂。", "浥浥小桥红浪湿，抚虚弦、何处得郎闻。", "雪堂老，千年一瞬，再击空明。"]'),
('song-ci-110','八声甘州','王质','宋','宋词','song-ci','八声甘州','[]','过隆中、桑柘倚斜阳，禾黍战悲风。',119,'宋词/ci.song.10000.json','["过隆中、桑柘倚斜阳，禾黍战悲风。", "世若无徐庶，更无庞统，沈了英雄。", "本计东荆西益，观变取奇功。", "转尽青天粟，无路能通。", "他日杂耕渭上，忽一星飞坠，万事成空。", "使一曹三马，云雨动蛟龙。", "看璀璨、出师一表，照乾坤、牛斗气常冲。", "千年后，锦城相吊，遇草堂翁。"]'),
('song-ci-111','八声甘州','王质','宋','宋词','song-ci','八声甘州','[]','气佳哉、烟紫石头城，云碧雨花台。',119,'宋词/ci.song.10000.json','["气佳哉、烟紫石头城，云碧雨花台。", "想东山前后，望春树绿，看晚潮回。", "自古英雄豪杰，无不待时来。", "拥鼻微吟处，山静花开。", "商皓亦常如此，羡苍生皆有，瞻望之怀。", "但淝河洛涧，此事偶然谐。", "疑是彼、八公草木，得神明、相亮不相猜。", "西州泪、千年犹湿，回望兴哀。"]'),
('song-ci-112','倦寻芳','王质','宋','宋词','song-ci','倦寻芳','[]','冰壶秋月，去了潘郎，传到梁老。',120,'宋词/ci.song.10000.json','["冰壶秋月，去了潘郎，传到梁老。", "骑马乘船，麾斥五湖三岛。", "任捎云，兼拂日，拽蛟龙、鳞鬣都推倒。", "厢尘中，分付高人胜士，把云烟扫。", "乾坤巧。", "自苍筠无汗，乌锥无刃，此为至宝。", "第一君门通表。", "书囊谏草。", "第二文章扬事业，第三编简摅怀抱。", "千百般，终久被他磨了。"]'),
('song-ci-113','倦寻芳','王质','宋','宋词','song-ci','倦寻芳','[]','断崖树老，侧岸槎枯，倒倚斜插。',120,'宋词/ci.song.10000.json','["断崖树老，侧岸槎枯，倒倚斜插。", "脚面浅溪，掌样平洲重叠。", "著芒鞋，携竹杖，遇乱莎幽涧萦纡涉。", "那人家，有竹笋瓦缶。", "颇颇清冽。", "曾微呷。", "正斜阳淡淡，暮霭昏昏，晚风猎猎。", "转眼已成陈迹。", "不堪追蹑。", "试问旧醅还好在，暂停归影留时霎。", "待重来，细拈弄、水花山叶。"]'),
('song-ci-114','万年欢','王质','宋','宋词','song-ci','万年欢','["\u957f\u6c5f"]','一轮明月，古人心万年，更寸心存。',122,'宋词/ci.song.10000.json','["一轮明月，古人心万年，更寸心存。", "沧海化为黄土，心不成尘。", "杳杳兴亡成败，满乾坤、未见知音。", "抚阑干、欲唤英魂，沈沈又没人应。", "无聊敧枕搔首，梦庐中坛上，一似平生。", "共挽长江为酒，相对同倾。", "不觉霜风敲竹，睡觉来、海与愁深。", "拂袖去，塞北河西，红尘陌上寻人。"]'),
('song-ci-115','真珠帘','王质','宋','宋词','song-ci','真珠帘','[]','翠虬夭矫拿苍玉。',123,'宋词/ci.song.10000.json','["翠虬夭矫拿苍玉。", "飞来到、吾庐溪湾山麓。", "一笑忽相逢，更解包投宿。", "北池之畔西墙曲，与主人、呼青吸绿。", "恨我，无天寒翠袖，共倚修竹。", "每遇飞雪萧萧，更惊风槭槭，清标可掬。", "更与月同来，无半点尘俗。", "冬有寒梅闲相伴，春亦有、幽兰相逐。", "香足。", "才露下霜飞，又有秋菊。"]'),
('song-ci-116','沁园春','王质','宋','宋词','song-ci','沁园春','[]','二百年间，十二时中，悲欢往来。',139,'宋词/ci.song.10000.json','["二百年间，十二时中，悲欢往来。", "但盖头一把，容身方丈，无多缘饰，莫遣尘埃。", "屈曲成幽，萧条生净，野草闲花都妙哉。", "家无力，虽然咫尺，强作萦回。", "竹斋。", "向背松斋。", "须次第、春兰秋菊开。", "在竹篱虚处，密栽甘橘，荆桥斜畔，疏种香梅。", "山芋芼羹，地黄酿粥，冬后春前皆可栽。", "门通水，荷汀蓼渚，足可徘徊。"]'),
('song-ci-117','红窗怨','王质','宋','宋词','song-ci','红窗怨','[]','欲寄意，都无有。',69,'宋词/ci.song.10000.json','["欲寄意，都无有。", "且须折赠、市桥官柳。", "看君著上征衣，也寻思、榜舟楚江口。", "此会未知何时又。", "恨男儿、不长相守。", "苟富贵、毋相忘，若相忘、有如此酒。"]'),
('song-ci-118','红窗怨','王质','宋','宋词','song-ci','红窗怨','[]','帘不卷。',67,'宋词/ci.song.10000.json','["帘不卷。", "人难见。", "缥缈歌声，暗随香转。", "记与三五少年，在杭州、曾听得几遍。", "唱到生绡白团扇。", "晚凉初、桐阴满院。", "待要图入丹青，无奈缘识如花面。"]'),
('song-ci-119','凤时春','王质','宋','宋词','song-ci','凤时春','[]','标格风流前辈。',75,'宋词/ci.song.10000.json','["标格风流前辈。", "才瞥见春风，萧然无对。", "只有月娥心不退。", "依旧断桥，横在流水。", "我亦共、月娥同意。", "肯将情移在，粗红俗翠。", "除丁香蔷薇酴醿外。", "便作花王，不是此辈。"]'),
('song-ci-120','泛兰舟','王质','宋','宋词','song-ci','泛兰舟','[]','萧萧乌帽黄衫。',98,'宋词/ci.song.10000.json','["萧萧乌帽黄衫。", "元水拍云岩。", "风清月白，一双碧眼莹秋潭。", "四海九州，茫茫东北，渺渺西南。", "松霜杉露毵毵。", "龙门隔如参井，青城佳气与天参。", "蔽山充野，牡丹红外茯苓甘。", "鹤顶凝丹，隙驹蹀躞，尽百年闲。", "乾坤云海风帆。"]'),
('song-ci-121','无月不登楼','王质','宋','宋词','song-ci','无月不登楼','[]','池塘生春草，梦中共、水仙相识。',123,'宋词/ci.song.10000.json','["池塘生春草，梦中共、水仙相识。", "细拨冰绡，低沈玉骨，搅动一池寒碧。", "吹尽杨花，糁毡消白。", "却有青钱，点点如积。", "渐成翠、亭亭如立。", "汉女江妃入奁室。", "掰破靓妆拥出。", "夜月明前，夕阳敧后，清妙世间标格。", "中贮琼瑶汁。", "才嚼破、露飞霜泣。", "何益。", "未转眼，度秋风，成陈迹。"]'),
('song-ci-122','别素质・忆瑶姬','王质','宋','宋词','song-ci','别素质・忆瑶姬','[]','一个茅奄，三间七架。',126,'宋词/ci.song.10000.json','["一个茅奄，三间七架。", "两畔更添两厦。", "倒坐双亭平分，扶阑两下。", "门前数十丘�岫枴�", "塍外更百十株桑柘。", "一溪活水长流，馀波及、蔬畦菜把。", "便是招提与兰若。", "时钞疏乡园，看经村社。", "随分斗米相酬，环钱相谢。", "便阕少亦堪借借。", "常收些、笋乾蕨鮓。", "好年岁，更无兵无火，快活杀也。"]'),
('song-ci-123','笛家弄・笛家','王质','宋','宋词','song-ci','笛家弄・笛家','[]','凌乱败荷，既似沙莞，又如淝水。',151,'宋词/ci.song.10000.json','["凌乱败荷，既似沙莞，又如淝水。", "颠倒旌旗都靡。", "馀花敧谢，又似乌江，骓兮不逝。", "虞兮奈尔。", "凋柳萧骚，又如轵道，故老何颜对。", "因缘断。", "时节转。", "自然如彼。", "自然如此。", "水边沙际。", "芦花摇曳。", "唤住行人，蓼花妩媚。", "引翻游子。", "又似江都酣夜延秋，建业望仙结绮。", "月下心飞，风前骨醉。", "共苹花得意。", "今看昔、后看今未。", "一回头，已百弹指。"]'),
('song-ci-124','念奴娇','沈瀛','宋','宋词','song-ci','念奴娇','[]','郊原浩荡，正夺目花光，动人春色。',120,'宋词/ci.song.10000.json','["郊原浩荡，正夺目花光，动人春色。", "白下长干佳丽最，寒食嬉游人物。", "雾卷香轮，风嘶宝骑，云表歌声遏。", "归来灯火，不知斗柄西揭。", "六代当日繁华，幕天席地，醉拍江流窄。", "游女人人争唱道，缓缓踏青阡陌。", "乐事何穷，赏心无限，惟惜年光迫。", "须臾聚散，人生真信如客。"]'),
('song-ci-125','念奴娇','沈瀛','宋','宋词','song-ci','念奴娇','[]','梧桐响雨，忆空江寒浪，渔舟冲雪。',120,'宋词/ci.song.10000.json','["梧桐响雨，忆空江寒浪，渔舟冲雪。", "横卧云峰千叠嶂，风旆槽香新压。", "网跃银刀，纶收钩线，倚棹清歌发。", "征鸿嘹亮，助予闲奏音节。", "天上桂子阴成，月中香旧，几度人间别。", "玉斧匣中常夜吼，可惜光阴虚设。", "唤下云梯，直攀金户，打透重门铁。", "姮娥念旧，料应重许人折。"]'),
('song-ci-126','念奴娇','沈瀛','宋','宋词','song-ci','念奴娇','[]','春来腊去，一番新风景，为君开设。',120,'宋词/ci.song.10000.json','["春来腊去，一番新风景，为君开设。", "试忆前时花雨坠，只少梅花清绝。", "两个难逢，一分才欠，巧杀终如拙。", "玉梅人唤，雪儿来对时节。", "应更付属楼头，丁宁笛伴，莫把声声彻。", "玉女行春娇渡马，休是鹊桥轻别。", "对我三人，与君一醉，醉了樽重设。", "清歌未放，更须天上呼月。"]'),
('song-ci-127','念奴娇','沈瀛','宋','宋词','song-ci','念奴娇','[]','赏心佳处，登临地、千古人人都说。',120,'宋词/ci.song.10000.json','["赏心佳处，登临地、千古人人都说。", "何况江天来雪望，添得十分奇绝。", "倚遍栏干，下窥寒镜，照我容颜拙。", "举头惊笑，问今天是何节。", "天外矗矗琼山，溶溶银海，上下光相接。", "年去岁来频览为，何事今朝浑别。", "坐蹴云茵，横牵绡幕，玉女来铺设。", "公馀多暇，正堪同此风月。"]'),
('song-ci-128','念奴娇','沈瀛','宋','宋词','song-ci','念奴娇','[]','阳春布暖，又还见、光景如梭催逼。',120,'宋词/ci.song.10000.json','["阳春布暖，又还见、光景如梭催逼。", "帝里皇都人共道，好个前时春色。", "默默暗沈，含颦不语，此意谁人识。", "何如索笑，放开说尽端的。", "须信漏泄风光，百花头上，报一枝消息。", "多少园林应次第，迤逦排红骈白。", "金鼎芳滋，玉堂璀璨，趁取佳时节。", "东君归后，绿阴依旧南陌。"]'),
('song-ci-129','念奴娇','沈瀛','宋','宋词','song-ci','念奴娇','[]','万般照破，无一点闲愁，萦系心目。',120,'宋词/ci.song.10000.json','["万般照破，无一点闲愁，萦系心目。", "种柳栽花园数亩，不觉吾庐幽独。", "闲上高台，溪光山色，一洗襟尘俗。", "小庵深处，萧然无限修竹。", "尽日闭却柴门，故人相问，扣户来车毂。", "相对围棋看胜负，更听弹琴一曲。", "尔汝忘形，高谈剧论，莫遣人来促。", "村歌社舞，为予倒尽千斛。"]'),
('song-ci-130','念奴娇','沈瀛','宋','宋词','song-ci','念奴娇','[]','光阴转毂，况生死事大，无常迅速。',121,'宋词/ci.song.10000.json','["光阴转毂，况生死事大，无常迅速。", "学道参禅、要识取，自家本来面目。", "闹里提撕，静中打坐，闲看传灯录。", "话头记取，要须生处教熟。", "一日十二时中，莫教间断，念念来相续。", "唤作竹蓖还则背，不唤竹蓖则触。", "斩却猫儿，问他狗子，更去参尊宿。", "忽然瞥地，碧潭冷浸寒玉。"]'),
('song-ci-131','满江红','沈瀛','宋','宋词','song-ci','满江红','["\u9ec4\u5c71", "\u957f\u6c5f"]','姑孰名邦，黄山畔、古台巍立。',115,'宋词/ci.song.10000.json','["姑孰名邦，黄山畔、古台巍立。", "秋渐老、重阳天气，郊原澄碧。", "隐隐西州增远望，长江一带平如席。", "怅英雄、千古到如今，空遗迹。", "吴太守，文章伯。", "寻胜事，酬佳节。", "拥笙歌千骑，遍游南陌。", "襟带江城当一面，折冲千里无强敌。", "更行看、击楫溯中流，妖氛息。"]'),
('song-ci-132','满江红','沈瀛','宋','宋词','song-ci','满江红','[]','半世飘蓬，今何幸、得归乡曲。',115,'宋词/ci.song.10000.json','["半世飘蓬，今何幸、得归乡曲。", "却还似、重来燕子，认巢新屋。", "好是秋晴风日美，饭香云子炊如玉。", "念蟹螯、满把欲黄时，笋新绿。", "仍更有，初开菊。", "何妨更，重添竹。", "与此君相对，且无荣辱。", "待得吾庐三径就，此生素愿都齐足。", "任三竿、红日上檐梢，眠方熟。"]'),
('song-ci-133','水调歌头','沈瀛','宋','宋词','song-ci','水调歌头','[]','潇洒云中鹤，容与水边鸥。',114,'宋词/ci.song.10000.json','["潇洒云中鹤，容与水边鸥。", "缑山仙客，飘然曾约此中留。", "更有骑鲸公子，相与翱翔八极，凛凛气横秋。", "明月楼头宴，樽俎好诗流。", "思往事，增逸兴，唤仙舟。", "谁能拘束，尘埃堆里蹙昏眸。", "拟附星槎直上，十二玉京绛阕，高处且嬉游。", "回首视人世，天地一沙舟。"]'),
('song-ci-134','水调歌头','沈瀛','宋','宋词','song-ci','水调歌头','[]','岁月如奔箭，屈指又中秋。',114,'宋词/ci.song.10000.json','["岁月如奔箭，屈指又中秋。", "去年江上行役，常动故乡愁。", "容与碧云亭畔，极目江山千里，隐隐是西州。", "日暮天容敛，鸥雁下汀洲。", "迥故棹，寻旧里，解客裘。", "功名前定，时到安得为淹留。", "幸有青编万轴，且又日长无事，莫恁做闲忧。", "花下常携酒，明月好登楼。"]'),
('song-ci-135','水调歌头','沈瀛','宋','宋词','song-ci','水调歌头','[]','门外可罗雀，长者肯来寻。',114,'宋词/ci.song.10000.json','["门外可罗雀，长者肯来寻。", "留君且住，听我一曲楚狂吟。", "枉了闲烦闲恼，莫管闲非闲是，说甚古和今。", "但看镜中影，双鬓已星星。", "人生世，多聚散，似浮萍。", "适然相会，须索有酒且同倾。", "说到人情真处，引入无何境界，惟酒是知音。", "况有好风月，相对且频斟。"]'),
('song-ci-136','满庭芳','沈瀛','宋','宋词','song-ci','满庭芳','[]','画戟霜匀，谯门风动，满城和气氤氲。',118,'宋词/ci.song.10000.json','["画戟霜匀，谯门风动，满城和气氤氲。", "一年好事，今朝属东君。", "歌管欢迎五马，金章烂、华毂朱轮。", "班春了，归来燕寝，香重烛花轻。", "盈盈。", "春酒暖，金幡彩胜，霞袂云旌。", "算重重佳庆，都聚今辰。", "且听雪儿歌罢，称寿处、兰玉诜诜。", "新春暖，貂蝉象服，同日感皇恩。"]'),
('song-ci-137','满庭芳','沈瀛','宋','宋词','song-ci','满庭芳','[]','春琐琼台，花藏瑶圃，彩云片片来归。',117,'宋词/ci.song.10000.json','["春琐琼台，花藏瑶圃，彩云片片来归。", "任城仙子，玉芨镇长移。", "时会三元金母，云璈奏、天上佳期。", "嬉游处，飘然侍女，玉佩紫霞衣。", "芙蓉帔欲去，鸾音鹤驭，洞府应迷。", "向人间挥手，留语人知。", "此去何须怅望，蓬莱水、弹指依稀。", "还知否，刘安未老，仙籍有津涯。"]'),
('song-ci-138','满庭芳','沈瀛','宋','宋词','song-ci','满庭芳','[]','裘带功名，裤襦歌颂，世间谁似公贤。',118,'宋词/ci.song.10000.json','["裘带功名，裤襦歌颂，世间谁似公贤。", "去年江上，谈笑息狼烟。", "多少宜民事了，芹宫内、华屋修椽。", "邦人爱，频频借寇，飞诏下甘泉。", "开筵。", "春昼永，朱颜相对，三凤齐肩。", "正鸾鸣丹桂，凤映红莲。", "人道名驹千里，他年事、能继青毡。", "休辞醉，三槐影里，岁岁捧金船。"]'),
('song-ci-139','满庭芳','沈瀛','宋','宋词','song-ci','满庭芳','[]','柳外山光，林间塔影，一溪横泻清流。',117,'宋词/ci.song.10000.json','["柳外山光，林间塔影，一溪横泻清流。", "四围洲渚，绿叶泼如油。", "荷盖亭亭照水，红蓼岸、芦荻萧飕。", "乘闲兴，溪云亭畔，终日看莲游。", "修篁栽欲遍，青松相映，两径成丘。", "种桃杏，随时亦弄春柔。", "此是先生活计，高卧处、无喜无忧。", "门前事，人来问我，回首但摇头。"]'),
('song-ci-140','朝中措','沈瀛','宋','宋词','song-ci','朝中措','[]','论兵齿颊带霜寒。',57,'宋词/ci.song.10000.json','["论兵齿颊带霜寒。", "清似碧琅玕。", "好是天然风韵，琳宫瑶馆清闲。", "华筵初启，小蛮二八，对影朱颜。", "便好添筹索笑，双枝原应双鬟。"]'),
('song-ci-141','朝中措','沈瀛','宋','宋词','song-ci','朝中措','[]','东风吹上小桃枝。',57,'宋词/ci.song.10000.json','["东风吹上小桃枝。", "春色拥旌麾。", "昨夜三台星见，分明直照姑溪。", "皇都禁阕，天颜遥想，应待公归。", "此去再登黄阁，火城光映沙堤。"]'),
('song-ci-142','西江月','沈瀛','宋','宋词','song-ci','西江月','[]','五马人生最贵，金陵自古繁华。',58,'宋词/ci.song.10000.json','["五马人生最贵，金陵自古繁华。", "光悬相印拥朱牙。", "况值边庭闲暇。", "满劝东西碧玉，高烧丽烛红葩。", "诏黄新湿字如鸦。", "明日天庭飞下。"]'),
('song-ci-143','醉落魄・一斛珠','沈瀛','宋','宋词','song-ci','醉落魄・一斛珠','[]','野庵吹鼓。',67,'宋词/ci.song.10000.json','["野庵吹鼓。", "翻腾似与寻常异。", "笙萧筝笛皆非是。", "今日头场，看取些儿戏。", "心中无事无萦系。", "村歌数首新来制。", "参禅渐渐知滋味。", "细语粗言，俱是第一义。"]'),
('song-ci-144','醉落魄・一斛珠','沈瀛','宋','宋词','song-ci','醉落魄・一斛珠','[]','时光盛逼。',67,'宋词/ci.song.10000.json','["时光盛逼。", "杯盘渐渐来收拾。", "主人便欲留连客。", "末后殷勤，一著怎生得。", "来时便有归时刻。", "归时便是来时迹。", "世间万事曾经历。", "只看如今，无不散筵席。"]'),
('song-ci-145','醉落魄・一斛珠','沈瀛','宋','宋词','song-ci','醉落魄・一斛珠','[]','致知格物。',67,'宋词/ci.song.10000.json','["致知格物。", "初学工夫参圣域。", "天高地远无穷极。", "欲造精微，莫若守惟一。", "纯全天理明如日。", "都缘人欲来相惑。", "且将持敬为先入。", "若能持敬，真个是神力。"]'),
('song-ci-146','醉落魄・一斛珠','沈瀛','宋','宋词','song-ci','醉落魄・一斛珠','[]','致知格物。',67,'宋词/ci.song.10000.json','["致知格物。", "孔颜学问从兹出。", "圣言句句皆真实。", "涵养功深，将见自家得。", "毋意毋我毋固必。", "视听言动非礼勿。", "胜己之私之谓克。", "克尽私心，天理甚明白。"]'),
('song-ci-147','柳梢青','沈瀛','宋','宋词','song-ci','柳梢青','[]','相逢今夕。',61,'宋词/ci.song.10000.json','["相逢今夕。", "故人相见，先谈踪迹。", "旧日书生，而今村叟，新来禅客。", "跳过世界三千，特特地、人间九百。", "自在狂歌，□□□□，一场杂剧。"]'),
('song-ci-148','行香子','沈瀛','宋','宋词','song-ci','行香子','[]','野叟愚痴。',84,'宋词/ci.song.10000.json','["野叟愚痴。", "一向昏迷。", "笑呵呵、前事皆非。", "从前业债，今尽拼离。", "也不能文，不能酒，不能诗。", "屏除人事，闭却门儿。", "於奇中、别有儿戏。", "几般骨董，衮过年时。", "待参些禅，弹些曲，学些棋。"]'),
('song-ci-149','行香子','沈瀛','宋','宋词','song-ci','行香子','[]','野叟归欤。',84,'宋词/ci.song.10000.json','["野叟归欤。", "朋友来无。", "数无多、几个相於。", "问谁姓字，在底中居。", "云陶靖节，白居士，邵尧夫。", "时时对语，一笑轩渠。", "他行藏、是我规模。", "朝朝暮暮，相唤相呼。", "愿今生世，长相守，作门徒。"]'),
('song-ci-150','行香子','沈瀛','宋','宋词','song-ci','行香子','[]','野叟长年。',85,'宋词/ci.song.10000.json','["野叟长年。", "一室萧然。", "都齐收、万轴牙签。", "只留三件，三教都全。", "时看周易，读庄子，诵楞严。", "阕�匣岬茫�万语千言。", "得鱼儿、了后忘筌。", "行行坐坐，相与周旋。", "待将此意，寻老孔，问金仙。"]'),
('song-ci-151','卜算子','沈瀛','宋','宋词','song-ci','卜算子','[]','睡觉五更钟，正好深提省。',52,'宋词/ci.song.10000.json','["睡觉五更钟，正好深提省。", "只看如今梦几般，觉后原无影。", "明暗若从来，且道来从甚。", "不是空生不是根，认取真如性。"]'),
('song-ci-152','卜算子','沈瀛','宋','宋词','song-ci','卜算子','[]','那里是闲时，这里何曾定。',52,'宋词/ci.song.10000.json','["那里是闲时，这里何曾定。", "毕竟忙时恼杀人，到了还他静。", "静处又如何，莫被顽空引。", "一道神光总现前，受用无穷尽。"]'),
('song-ci-153','卜算子','沈瀛','宋','宋词','song-ci','卜算子','[]','只管要参禅，又被禅萦绕。',52,'宋词/ci.song.10000.json','["只管要参禅，又被禅萦绕。", "好笑西来老秃奴，赚了人多少。", "你待更瞒咱，咱也今知晓。", "只这喃喃说底人，又被傍人笑。"]'),
('song-ci-154','如梦令','沈瀛','宋','宋词','song-ci','如梦令','[]','才听笛声三弄。',40,'宋词/ci.song.10000.json','["才听笛声三弄。", "关捩一时都动。", "收拾去来休，三脚驴儿相送。", "珍重。", "珍重。", "归去好生作梦。"]'),
('song-ci-155','捣练子','沈瀛','宋','宋词','song-ci','捣练子','[]','神欲出，便收来。',48,'宋词/ci.song.10000.json','["神欲出，便收来。", "神返心中气自回。", "换丹元，朝玉台。", "时运水，日搬柴。", "寸田一点是根荄。", "这交梨，常种栽。"]'),
('song-ci-156','捣练子','沈瀛','宋','宋词','song-ci','捣练子','[]','神欲出，便收来。',48,'宋词/ci.song.10000.json','["神欲出，便收来。", "神返心中气自回。", "返婴儿，成圣胎。", "灵液注，蕊珠开。", "大丹炉里响如雷。", "忽飞升，游九垓。"]'),
('song-ci-157','捣练子','沈瀛','宋','宋词','song-ci','捣练子','[]','放下著，须弥山。',48,'宋词/ci.song.10000.json','["放下著，须弥山。", "分明北斗面南看。", "没丝毫，相阻拦。", "休儱侗，莫颟顸。", "含元殿上问长安。", "欲归家，行路难。"]'),
('song-ci-158','捣练子','沈瀛','宋','宋词','song-ci','捣练子','[]','放下著，须弥山。',48,'宋词/ci.song.10000.json','["放下著，须弥山。", "百斛油麻水上摊。", "欲成团，真个难。", "除有累，去痴顽。", "无心犹是隔重关。", "到其中，方是安。"]'),
('song-ci-159','捣练子','沈瀛','宋','宋词','song-ci','捣练子','[]','放下著，须弥山。',48,'宋词/ci.song.10000.json','["放下著，须弥山。", "情人今日出阳关。", "看人间，天地宽。", "徒缱绻，枉酒澜。", "别郎容易见郎难。", "且还家，重整冠。"]'),
('song-ci-160','浣溪沙','沈瀛','宋','宋词','song-ci','浣溪沙','[]','雨点真珠水上鸣。',56,'宋词/ci.song.10000.json','["雨点真珠水上鸣。", "更将青盖一时倾。", "总是江妃来坠珥，访娉婷。", "不为含愁啼粉泪，只因贪爱湿行云。", "惟有游鱼偏得意，许成群。"]'),
('song-ci-161','画堂春','沈瀛','宋','宋词','song-ci','画堂春','[]','荷花含笑调薰风。',55,'宋词/ci.song.10000.json','["荷花含笑调薰风。", "两情著意尤浓。", "水精栏槛四玲珑。", "照见妆容。", "醉里偷开盏面，晓来暗坼香风。", "不知何事苦匆匆。", "飘落残红。"]'),
('song-ci-162','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','乘流坎止。',52,'宋词/ci.song.10000.json','["乘流坎止。", "住个斋儿无愠喜。", "竹引清风。", "透入虚窗窍窍通。", "仰天酌酒。", "万八千年磐古寿。", "身在无何。", "只这斋儿已自多。"]'),
('song-ci-163','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','蓬门居止。',52,'宋词/ci.song.10000.json','["蓬门居止。", "竹见宾来先啸喜。", "窗外敲风。", "果有宾朋姓字通。", "莫嫌村酒。", "且祝佳宾万千寿。", "无用辞何。", "日出明朝事更多。"]'),
('song-ci-164','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','停杯且止。',52,'宋词/ci.song.10000.json','["停杯且止。", "斋里百无为客喜。", "冷淡文风。", "只有狂言数百通。", "不须载酒。", "粗有五车聊当寿。", "莫笑予何。", "空恁贪多嚼不多。"]'),
('song-ci-165','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','或行或止。',52,'宋词/ci.song.10000.json','["或行或止。", "难得人间相聚喜。", "一日分风。", "千里如何信息通。", "再倾寿酒。", "五福从来先说寿。", "其次云何。", "直至三公未足多。"]'),
('song-ci-166','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','渊明酒止。',52,'宋词/ci.song.10000.json','["渊明酒止。", "莫信渠言心妄喜。", "达士高风。", "只说三杯大道通。", "不如饮酒。", "人世岂能金石寿。", "无奈渠何。", "赢得尊前笑语多。"]'),
('song-ci-167','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','老而不止。',52,'宋词/ci.song.10000.json','["老而不止。", "三岁发蒙心已喜。", "朴略其风。", "裴楷王戎简要通。", "昏如醉酒。", "羞见总龟灵且寿。", "笑杀常何。", "空有闲言长语多。"]'),
('song-ci-168','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','不能者止。',52,'宋词/ci.song.10000.json','["不能者止。", "百念灰心无所喜。", "暖日和风。", "手把奇文诵数通。", "老来怯酒。", "欲保残生期养寿。", "少恕予何。", "近日衰翁病觉多。"]'),
('song-ci-169','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','且安汝止。',52,'宋词/ci.song.10000.json','["且安汝止。", "快活心中惟法喜。", "一处通风。", "万别千差处处通。", "腐肠是酒。", "伐性蛾眉徒损寿。", "诗到阴何。", "剗地乱丝头绪多。"]'),
('song-ci-170','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','不如知止。',52,'宋词/ci.song.10000.json','["不如知止。", "看尽世间无可喜。", "心热生风。", "王老门前问仲通。", "六经如酒。", "一句中人仁者寿。", "仁道伊何。", "要处还他静处多。"]'),
('song-ci-171','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','动而思止。',52,'宋词/ci.song.10000.json','["动而思止。", "止即患生徒自喜。", "试举幡风。", "未举之前说已通。", "携瓶沽酒。", "却著衫来为我寿。", "者也之何。", "赚却阎浮世上多。"]'),
('song-ci-172','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','贪而忘止。',52,'宋词/ci.song.10000.json','["贪而忘止。", "贪即生瞋逢饱喜。", "一逐贪风。", "恨不当初嫁邓通。", "残杯剩酒。", "食籍名中犹折寿。", "若使兼何。", "他日阴司罪过多。"]'),
('song-ci-173','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','人无常止。',52,'宋词/ci.song.10000.json','["人无常止。", "暮四朝三时怒喜。", "怪雨嫌风。", "高耳皇天下听通。", "刚而使酒。", "骂坐灌夫忘客寿。", "魋若予何。", "夫子雍容语不多。"]'),
('song-ci-174','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','心如皎止。',52,'宋词/ci.song.10000.json','["心如皎止。", "何必佯痴藏暗喜。", "聋不听风。", "要得人情内外通。", "半醨半酒。", "痴黠恺之真短寿。", "莫折随何。", "宁可书痴胜彼多。"]'),
('song-ci-175','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','纠缠弗止。',52,'宋词/ci.song.10000.json','["纠缠弗止。", "成是败非生戚喜。", "即灭灾风。", "否极还须有泰通。", "祸常因酒。", "酒亦令人能介寿。", "成也萧何。", "败也萧何更是多。"]'),
('song-ci-176','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','贪容肯止。',52,'宋词/ci.song.10000.json','["贪容肯止。", "结绶弹冠王贡喜。", "稍借天风。", "便说今年运大通。", "华亭别酒。", "安得思如亭鹤寿。", "贵若从何。", "只恐来生折本多。"]'),
('song-ci-177','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','瞻乌爰止。',52,'宋词/ci.song.10000.json','["瞻乌爰止。", "不是檐前闻鹊喜。", "上下鸣风。", "以类相从自感通。", "嫌茶爱酒。", "恶彼芝焚夸柏寿。", "说汝言何。", "一切人言口众多。"]'),
('song-ci-178','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','未行先止。',52,'宋词/ci.song.10000.json','["未行先止。", "鱼上竹竿人噪喜。", "九万鹏风。", "六月天池一息通。", "邯郸鲁酒。", "却笑行人陵柏寿。", "笑彼迟何。", "不道能行失亦多。"]'),
('song-ci-179','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','圣经五止。',52,'宋词/ci.song.10000.json','["圣经五止。", "止向丘隅黄鸟喜。", "广大儒风。", "一贯三才万类通。", "太羹玄酒。", "圣域能跻民域寿。", "支派从何。", "关内濂溪洛涧多。"]'),
('song-ci-180','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','定而后止。',52,'宋词/ci.song.10000.json','["定而后止。", "善到止时心地喜。", "鱼跃鸢风。", "此理昭然上下通。", "好如好酒。", "欲似人常心欲寿。", "若到兹何。", "治国治家用处多。"]'),
('song-ci-181','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','朱幡归止。',52,'宋词/ci.song.10000.json','["朱幡归止。", "却返烟霞寻旧喜。", "羽帔香风。", "再拜天门直上通。", "青君赐酒。", "乞与长生无量寿。", "更挟仙何。", "跨鹤凌云洞府多。"]'),
('song-ci-182','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','气开气止。',52,'宋词/ci.song.10000.json','["气开气止。", "引得丹元童子喜。", "耳里闻风。", "知是泥丸一窍通。", "危楼宴酒。", "不觉黄芽生蕊寿。", "牙长如何。", "只觉金花罩体多。"]'),
('song-ci-183','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','琴心和止。',52,'宋词/ci.song.10000.json','["琴心和止。", "姹女与君相对喜。", "窗牖藏风。", "每唤其名应即通。", "玉英金酒。", "更唤黄婆同饮寿。", "莫讳人何。", "见说婴儿屋里多。"]'),
('song-ci-184','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','工夫莫止。',52,'宋词/ci.song.10000.json','["工夫莫止。", "脱得壳儿方是喜。", "不识真风。", "只说双关夹脊通。", "氤氲似酒。", "元气本同天地寿。", "君可能何。", "一跃红楼好处多。"]'),
('song-ci-185','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','擎拳仰止。',52,'宋词/ci.song.10000.json','["擎拳仰止。", "不是凡人名尹喜。", "道骨仙风。", "与帝神游结信通。", "献花跪酒。", "清彻云璈歌益寿。", "所愿维何。", "愿得升平乐事多。"]'),
('song-ci-186','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','雨难禁止。',52,'宋词/ci.song.10000.json','["雨难禁止。", "恼得衰翁浑没喜。", "一夜南风。", "北望苕溪震泽通。", "只鸡斗酒。", "且为晚禾生日寿。", "不奈之何。", "今岁田畴晚底多。"]'),
('song-ci-187','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','寿诗且止。',52,'宋词/ci.song.10000.json','["寿诗且止。", "设席肆筵谁助喜。", "抹月批风。", "先向天厨号令通。", "满卮天酒。", "上与天田同日寿。", "其应维何。", "寿及天民性命多。"]'),
('song-ci-188','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','玉人来止。',52,'宋词/ci.song.10000.json','["玉人来止。", "见说冰翁心甚喜。", "好个家风。", "举案齐眉胜敬通。", "华堂举酒。", "簇簇亲姻相祝寿。", "善颂言何。", "桂树鸾鸣子姓多。"]'),
('song-ci-189','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','谁来贲止。',52,'宋词/ci.song.10000.json','["谁来贲止。", "千里得朋方切喜。", "汪氏门风。", "大学中庸正脉通。", "不妨诗酒。", "请以还丹为荐寿。", "已过羊何。", "绍述韩门得趣多。"]'),
('song-ci-190','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','凌波不止。',52,'宋词/ci.song.10000.json','["凌波不止。", "少小拍浮荷女喜。", "出没由风。", "安得灵犀与暗通。", "龙池醉酒。", "应是太真羞见寿。", "不晓谁何。", "却是浑身一半多。"]'),
('song-ci-191','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','渴心先止。',52,'宋词/ci.song.10000.json','["渴心先止。", "惟有杨家梅可喜。", "争笑梅风。", "空怨楼头角数通。", "甜浆酿酒。", "紫气结成千日寿。", "不奈人何。", "化作飞星处处多。"]'),
('song-ci-192','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','必恭敬止。',52,'宋词/ci.song.10000.json','["必恭敬止。", "老子甚为桑梓喜。", "骏马争风。", "诗卷人人数百通。", "斗杓挹酒。", "齐祝乡人箕翼寿。", "天若言何。", "更乞文星下照多。"]'),
('song-ci-193','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','锦囊送止。',52,'宋词/ci.song.10000.json','["锦囊送止。", "拆看篇篇珠玉喜。", "大胜鱼风。", "韶沪宫商角徵通。", "醉而强酒。", "有愧多闻张子寿。", "其哂由何。", "刻画无盐已甚多。"]'),
('song-ci-194','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','竹斋陋止。',52,'宋词/ci.song.10000.json','["竹斋陋止。", "坐客无毡为客喜。", "壁不遮风。", "八达门窗更四通。", "邻家觅酒。", "赤脚扶翁翁老寿。", "子曰其何。", "除却渠侬没事多。"]'),
('song-ci-195','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','荷公临止。',52,'宋词/ci.song.10000.json','["荷公临止。", "宾客惯看儿亦喜。", "歌雅歌风。", "通鉴通书又史通。", "欲相酹酒。", "瓦缶田家羞出寿。", "甚欲舟何。", "愧没瑶觞玉斝多。"]'),
('song-ci-196','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','棋枰响止。',52,'宋词/ci.song.10000.json','["棋枰响止。", "胜负岂能全两喜。", "不竞南风。", "忽尔三生六劫通。", "客方对酒。", "一片捷音来自寿。", "甚快人何。", "大胜呼庐百万多。"]'),
('song-ci-197','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','酒巡未止。',52,'宋词/ci.song.10000.json','["酒巡未止。", "先说一些儿事喜。", "别调吹风。", "佛曲由来自普通。", "长鲸吸酒。", "面对沈香山刻寿。", "吸尽如何。", "吸了西江说甚多。"]'),
('song-ci-198','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','酒巡未止。',52,'宋词/ci.song.10000.json','["酒巡未止。", "听说二疏归可喜。", "随意乘风。", "拄杖深村狭巷通。", "渊明漉酒。", "更与庞公庞媪寿。", "切莫讥何。", "唤取同来作队多。"]'),
('song-ci-199','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','酒巡未止。',52,'宋词/ci.song.10000.json','["酒巡未止。", "更号三般杨氏喜。", "上苑春风。", "宝带灵犀点点通。", "听歌侑酒。", "富贵两全添个寿。", "人少兼何。", "彭祖人言只寿多。"]'),
('song-ci-200','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','酒巡未止。',52,'宋词/ci.song.10000.json','["酒巡未止。", "说著四并须著喜。", "好月兼风。", "好个情怀命又通。", "明朝醒酒。", "起看佳人妆学寿。", "定问人何。", "昨夜何人饮最多。"]'),
('song-ci-201','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','酒巡未止。',52,'宋词/ci.song.10000.json','["酒巡未止。", "更说五行人听喜。", "康节淳风。", "说道诸公运数通。", "乞浆得酒。", "更检戊申前定寿。", "亥子推何。", "甲子生年四百多。"]'),
('song-ci-202','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','酒巡未止。',52,'宋词/ci.song.10000.json','["酒巡未止。", "鼓吹六经为公喜。", "也没回风。", "只有村中鼓数通。", "长须把酒。", "自当长头杯捧寿。", "问得穷何。", "一坐靴皮笑面多。"]'),
('song-ci-203','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','酒巡未止。',52,'宋词/ci.song.10000.json','["酒巡未止。", "且听七言馀韵喜。", "弹到悲风。", "醒酒风吹路必通。", "休休避酒。", "末后茶仙来献寿。", "七碗休何。", "不独茶多酒亦多。"]'),
('song-ci-204','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','八巡将止。',52,'宋词/ci.song.10000.json','["八巡将止。", "八节四时人贺喜。", "汉俗成风。", "薛老之言贵尚通。", "妻儿设酒。", "更得比邻相庆寿。", "虚度时何。", "只恐妻儿怪汝多。"]'),
('song-ci-205','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','九巡将止。',52,'宋词/ci.song.10000.json','["九巡将止。", "留读九歌章句喜。", "尽溘埃风。", "发轫苍梧万里通。", "楚歌发酒。", "读到人生何所寿。", "试问原何。", "尔独惺然枉了多。"]'),
('song-ci-206','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','十巡今止。',52,'宋词/ci.song.10000.json','["十巡今止。", "乐事要须防极喜。", "烛影摇风。", "月落参横影子通。", "粗茶淡酒。", "五十狂歌供宴寿。", "敬谢来何。", "再得寻盟后日多。"]'),
('song-ci-207','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','陋人居止。',52,'宋词/ci.song.10000.json','["陋人居止。", "旬一集真终日喜。", "先自薰风。", "客目轮流次第通。", "昔贤置酒。", "十老半千年纪寿。", "知彼由何。", "真处闲中日月多。"]'),
('song-ci-208','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','鸡鸣弗止。',52,'宋词/ci.song.10000.json','["鸡鸣弗止。", "弗到天明心弗喜。", "投辖成风。", "壑谷吾公宜弗通。", "齐盟歃酒。", "扬觯先听方饮寿。", "盟载言何。", "卜昼三杯不用多。"]'),
('song-ci-209','减字木兰花','沈瀛','宋','宋词','song-ci','减字木兰花','[]','适然萃止。',52,'宋词/ci.song.10000.json','["适然萃止。", "不待灯花先报喜。", "不速真风。", "且免毛生不为通。", "诗歌棋酒。", "真正清欢真正寿。", "事事真何。", "更得真真真更多。"]'),
('song-ci-210','野庵曲','沈瀛','宋','宋词','song-ci','野庵曲','[]','野叟最昏迷。',170,'宋词/ci.song.10000.json','["野叟最昏迷。", "叹世间、光阴奔走如驰。", "逢这闲时。", "忽寻忖、一生里事都非。", "从头到尾。", "都改了、重立根基。", "枕上披衣。", "浑无寐。", "时时摩挲行气。", "才睡起。", "避户扉。", "爇一炷清香，烟气霏霏。", "膜拜更归依。", "冥心坐、看经念佛行持。", "消除秽恶，光洒洒、禅律威仪。", "佛力慈悲。", "愿今世。", "永没冤债相随。", "食将惭愧。", "才饭了、一枕茶香美。", "迟迟日长，觅伴相对围棋。", "安排势子。", "相望相窥。", "闭心机。"]'),
('song-ci-211','醉乡曲','沈瀛','宋','宋词','song-ci','醉乡曲','[]','说与贤瞒，这躯壳、安能久仗凭。',105,'宋词/ci.song.10000.json','["说与贤瞒，这躯壳、安能久仗凭。", "幸尊中有酒浇磊块，先交神气平。", "醉乡道路无他径。", "任陶陶、现出真如性。", "没闲恼、没闲争。", "也能使情怀长似春。", "也能使飘然逸气如云。", "饶君万劫修功行。", "又争如、一盏乐天真。", "这些儿，休放过、且重斟。"]'),
('song-ci-212','驻马听','沈瀛','宋','宋词','song-ci','驻马听','[]','人都道四者难并。',71,'宋词/ci.song.10000.json','["人都道四者难并。", "也由在人心。", "烦恼欢喜元无定。", "奸峭底自能称停。", "你待前面怎那，且随任咱分。", "自家有后自未奔。", "枉劳人方寸。", "眼前推辞怎。", "那知他人也心闷。"]'),
('song-ci-213','风入松','沈瀛','宋','宋词','song-ci','风入松','[]','金榜初登。',125,'宋词/ci.song.10000.json','["金榜初登。", "绮楼朱楼对娉婷。", "软红尘、有人相等。", "归来寝立功名。", "油盖拥著一书生。", "开宴处、笙歌频奏声。", "眼前光景。", "人生如意享欢荣。", "得酒娱情。", "没事汉、清闲人。", "任自由、毁誉利害不上心。", "恣闲吟。", "登山玩水且闲行。", "来主他、风华雪月盟。", "相逢道友，握手闲语百事真。", "得酒忘情。"]'),
('song-ci-214','归去来兮引・归去来兮','杨万里','宋','宋词','song-ci','归去来兮引・归去来兮','[]','侬家贫甚诉长饥。',227,'宋词/ci.song.10000.json','["侬家贫甚诉长饥。", "幼稚满庭闱。", "正坐瓶无储粟，漫求为吏东西。", "偶然彭泽近邻圻。", "公秫滑流匙。", "葛巾劝我求为酒，黄菊怨、冷落东篱。", "五斗折腰，谁能许事，归去来兮。", "老圃半榛茨。", "山田欲蒺藜。", "念心为形役又奚悲。", "独惆怅前迷。", "不谏后方追。", "觉今来是了，觉昨来非。", "扁舟轻扬破朝霏。", "风细漫吹衣。", "试问征夫前路，晨光小，恨熹微。", "乃瞻衡宇载奔弛。", "迎候满荆扉。", "已荒三径存松菊，喜诸幼、入室相携。", "有酒盈尊，引觞自酌，庭树遣颜怡。", "容膝易安栖。", "南窗寄傲睨。", "更小园日涉趣尤奇。", "尽虽设柴门，长是闭斜晖。"]'),
('song-ci-215','念奴娇','杨万里','宋','宋词','song-ci','念奴娇','[]','老夫归去，有三径、足可长拖衫袖。',120,'宋词/ci.song.10000.json','["老夫归去，有三径、足可长拖衫袖。", "一道官衔清彻骨，别有监临主守。", "主守清风，监临明月，兼管栽花柳。", "登山临水，作诗三首两首。", "休说白日升天，莫夸金印，斗大悬双肘。", "且说庐陵传盛事，三个闲人眉寿。", "拣罢军员，归农押录，致政诚斋叟。", "只愁醉杀，螺江门外私酒。"]'),
('song-ci-216','好事近','杨万里','宋','宋词','song-ci','好事近','[]','月未到诚斋，先到万花川谷。',53,'宋词/ci.song.10000.json','["月未到诚斋，先到万花川谷。", "不是诚斋无月，隔一林修竹。", "如今才是十三夜，月色已如玉。", "未是秋光奇绝，看十五十六。"]'),
('song-ci-217','昭君怨','杨万里','宋','宋词','song-ci','昭君怨','[]','偶听松梢扑鹿。',48,'宋词/ci.song.10000.json','["偶听松梢扑鹿。", "知是沙鸥来宿。", "稚子莫喧哗。", "恐惊他。", "俄顷忽然飞去。", "飞去不知何处。", "我已乞归休。", "报沙鸥。"]'),
('song-ci-218','昭君怨','杨万里','宋','宋词','song-ci','昭君怨','["\u897f\u6e56"]','午梦扁舟花底。',48,'宋词/ci.song.10000.json','["午梦扁舟花底。", "香满西湖烟水。", "急雨打篷声。", "梦初惊。", "却是池荷跳雨。", "散了真珠还聚。", "聚作水银窝。", "泻清波。"]'),
('song-ci-219','武陵春','杨万里','宋','宋词','song-ci','武陵春','[]','长铗归乎逾十暑，不著鵕鸃冠。',56,'宋词/ci.song.10000.json','["长铗归乎逾十暑，不著鵕鸃冠。", "道是今年胜去年。", "特地减清欢。", "旧赐龙团新作祟，频啜得中寒。", "瘦骨如柴痛又酸。", "儿信问平安。"]'),
('song-ci-220','水调歌头','杨万里','宋','宋词','song-ci','水调歌头','[]','玉树映阶秀，玉节逐年新。',114,'宋词/ci.song.10000.json','["玉树映阶秀，玉节逐年新。", "年年九月，好为阿母作生辰。", "涧底蒲芽九节，海底银涛万顷，酿作一杯春。", "泛以东篱菊，寿以漆园椿。", "对西风，吹鬓雪，炷香云。", "郎君入奏，又迎珠幰入修门。", "看即金花紫诰，并举莆常两国，册命太夫人。", "三点台星上，一点老人星。"]'),
('song-ci-221','忆秦娥','杨万里','宋','宋词','song-ci','忆秦娥','[]','新春早。',56,'宋词/ci.song.10000.json','["新春早。", "春前十日春归了。", "春归了。", "落梅如雪，野桃红小。", "老夫不管春催老。", "只图烂醉花前倒。", "花前倒。", "儿扶归去，醒来窗晓。"]'),
('song-ci-222','眼儿媚','某教授','宋','宋词','song-ci','眼儿媚','[]','鬓边一点似飞鸦。',58,'宋词/ci.song.10000.json','["鬓边一点似飞鸦。", "莫把翠钿遮。", "三年两载，千撋百就，今日天涯。", "杨花又逐东风去，随分落谁家。", "若还忘得，除非睡起，不照菱花。"]'),
('song-ci-223','水调歌头','陈居仁','宋','宋词','song-ci','水调歌头','[]','重过钓台路，风物故依然。',114,'宋词/ci.song.10000.json','["重过钓台路，风物故依然。", "羊裘轩上，俯临清泚面孱颜。", "仰见先生风节，更有两公名德，冰雪照人寒。", "龙野方驰逐，鸿翼自孤骞。", "酹壶觞，追往昔，笑华颠。", "别来三纪，推排曾戴侍臣冠。", "惭愧君恩难答，聊复守符重绾，敢叹客途艰。", "少报期年政，行泛五湖船。"]'),
('song-ci-224','满庭芳','李洪','宋','宋词','song-ci','满庭芳','[]','香满千岩，芳传丛桂，小山曾咏幽菲。',118,'宋词/ci.song.10000.json','["香满千岩，芳传丛桂，小山曾咏幽菲。", "仙姿冷淡，不奈此香奇。", "翠葆层层障日，深爱惜、早被风吹。", "秋英嫩，夜来露浥，月底半离披。", "谁知。", "清品贵，带装金粟，韵透文犀。", "与降真为侣，罗袖相宜。", "宝鸭休薰百濯，清芬在、常惹人衣。", "姮娥约，广寒宫殿，留折最高枝。"]'),
('song-ci-225','满江红','李洪','宋','宋词','song-ci','满江红','[]','梅雨成霖，倦永昼、暑行岩曲。',112,'宋词/ci.song.10000.json','["梅雨成霖，倦永昼、暑行岩曲。", "爱云梢翠樾，枕溪蓬屋。", "轻木凌波冲卷雪，飞泉奔壑呜哀玉。", "羡渔翁、终岁老烟波，披蓑绿。", "嗟客宦，荒松菊。", "颓壮志，青编竹。", "更长年谙尽，是非荣辱。", "钟鼎无心时节异，山林有味簟瓢足。", "感故人、於此赋归欤，思之熟。"]'),
('song-ci-226','南乡子','李洪','宋','宋词','song-ci','南乡子','[]','挂席泛安流。',66,'宋词/ci.song.10000.json','["挂席泛安流。", "细雨斜风到渡头。", "万叠云鬟真似画，云州。", "自古诗人几个游。", "旌旆去悠悠。", "别驾无功愧食浮。", "却忆五湖烟浪里，扁舟。", "第四桥南云水秋。"]'),
('song-ci-227','鹧鸪天','李洪','宋','宋词','song-ci','鹧鸪天','[]','十月南闽未有霜。',64,'宋词/ci.song.10000.json','["十月南闽未有霜。", "蕉林蔗圃郁相望。", "压枝橄榄浑如画，透甲香橙半弄黄。", "斟绿醑，泛沧浪。", "白沙翠竹近温汤。", "分明水墨山阴道，只欠冰溪雪月光。"]'),
('song-ci-228','西江月','李洪','宋','宋词','song-ci','西江月','[]','渺渺长汀远壑，萧萧雨叶风枝。',58,'宋词/ci.song.10000.json','["渺渺长汀远壑，萧萧雨叶风枝。", "几回临水送将归。", "客里暗添憔悴。", "门枕数峰滴翠，舟横几度涟漪。", "绿秧深处鹭于飞。", "愈觉田园有味。"]'),
('song-ci-229','菩萨蛮','李洪','宋','宋词','song-ci','菩萨蛮','[]','寒山横抹修眉绿。',52,'宋词/ci.song.10000.json','["寒山横抹修眉绿。", "楼前溪瀑锵鸣玉。", "车马各西东。", "行人如转蓬。", "阑干成独倚。", "海阔天无际。", "云淡隔壶山。", "鸿飞杳霭间。"]'),
('song-ci-230','浣溪沙','李洪','宋','宋词','song-ci','浣溪沙','[]','夭矫翔鸾溪上峰。',48,'宋词/ci.song.10000.json','["夭矫翔鸾溪上峰。", "飘萧雪霰打船篷。", "天花凌乱水晶宫。", "飞透纸窗斜取势，吹回溪面舞因风。", "身游水墨画图中。"]'),
('song-ci-231','浣溪沙','李洪','宋','宋词','song-ci','浣溪沙','[]','碧涧苍崖玉四围。',48,'宋词/ci.song.10000.json','["碧涧苍崖玉四围。", "东君翦水散明玑。", "半开桃杏不胜威。", "疑是群仙游阆苑，歌云舞蝶斗高飞。", "珠幢玉节送人归。"]'),
('song-ci-232','浣溪沙','李洪','宋','宋词','song-ci','浣溪沙','["\u897f\u6e56"]','扫地烧香绝点尘。',48,'宋词/ci.song.10000.json','["扫地烧香绝点尘。", "绿阶绿草又残春。", "略无闲事挠天真。", "时落燕泥沾几席，乱粘飞絮上衣巾。", "西湖回柁少年人。"]'),
('song-ci-233','念奴娇','李洪','宋','宋词','song-ci','念奴娇','[]','丽谯吹角，渐疏星明澹，帘筛残月。',120,'宋词/ci.song.10000.json','["丽谯吹角，渐疏星明澹，帘筛残月。", "袅袅霜飙欺翠袖，飞下一庭香雪。", "半面妆新，回风舞困，此况真奇绝。", "桄榔林里，苏仙偏感华发。", "休怨时暂飘零，玉堂清梦，不惹闲蜂蝶。", "好似王家从竹畔，乘兴山阴时节。", "剪水无情，阆风归去，忍使芳心歇。", "和羹有待，恁时身到天阕。"]'),
('song-ci-234','卜算子','李洪','宋','宋词','song-ci','卜算子','[]','南国小春时，常是寒威浅。',52,'宋词/ci.song.10000.json','["南国小春时，常是寒威浅。", "玉缀香苞已有梅，疏影无人见。", "愁忆故园芳，梦断扬州远。", "不御铅华自出尘，赛过徐妃面。"]'),
('song-ci-235','鹊桥仙','李漳','宋','宋词','song-ci','鹊桥仙','[]','迢迢郎意，盈盈妾恨，今夕鹊桥欲度。',68,'宋词/ci.song.10000.json','["迢迢郎意，盈盈妾恨，今夕鹊桥欲度。", "世间儿女一何痴，斗乞巧、纷纷无数。", "遥知此际，有人孤坐，心切天街云路。", "好因缘是恶因缘，梦魂远、阳台雨暮。"]'),
('song-ci-236','桃源忆故人','李漳','宋','宋词','song-ci','桃源忆故人','[]','小楼帘卷栏干外。',56,'宋词/ci.song.10000.json','["小楼帘卷栏干外。", "花下朱门半启。", "中有倾城佳丽。", "一笑西风里。", "盈盈临水情难致。", "尽日相看如醉。", "乾鹊不知人意。", "只管声声喜。"]'),
('song-ci-237','满江红','李漳','宋','宋词','song-ci','满江红','[]','雨歇前林，薰风度、琴声清淑。',115,'宋词/ci.song.10000.json','["雨歇前林，薰风度、琴声清淑。", "绮窗迥、张眉初扫，弄弦鸣玉。", "三叠瑶池仙侣宴，九江鹤唳清江曲。", "政伯鸾、此日梦维熊，祥烟馥。", "金徽外，音时续。", "雕筵上，听难足。", "且相将一醉，满倾醽醁。", "共祝遐龄何所似，水流不尽高山矗。", "算未应、归去抱琴书，云间宿。"]'),
('song-ci-238','鹧鸪天','李漳','宋','宋词','song-ci','鹧鸪天','[]','淑德由来孟母名。',64,'宋词/ci.song.10000.json','["淑德由来孟母名。", "方瞳鹤发莹精神。", "天教遐算灵椿比，亲见贤郎擢桂荣。", "逢诞日，庆孙曾。", "金花纶诰又重新。", "愿君学得司空母，管取年高寿太平。"]'),
('song-ci-239','生查子','李漳','宋','宋词','song-ci','生查子','[]','家承阀阅高，人擅闺房秀。',48,'宋词/ci.song.10000.json','["家承阀阅高，人擅闺房秀。", "嫁得伯鸾夫，直是齐眉偶。", "榴花著子时，萱草宜男候。", "一笑捧觥船，共祝人常寿。"]'),
('song-ci-240','南歌子','李漳','宋','宋词','song-ci','南歌子','[]','小子何时见，高秋此日生。',62,'宋词/ci.song.10000.json','["小子何时见，高秋此日生。", "阶兰岩桂正欣荣。", "家比杜陵犹有、彩衣轻。", "应诏须三载，传家有一经。", "齐禽刷羽早蜚鸣。", "莫效老夫头白、好归耕。"]'),
('song-ci-241','水调歌头','李泳','宋','宋词','song-ci','水调歌头','[]','危楼云雨上，其下水扶天。',114,'宋词/ci.song.10000.json','["危楼云雨上，其下水扶天。", "群山四合，飞动寒翠落檐前。", "尽是秋清栏槛，一笑波翻涛怒，雪阵卷苍烟。", "炎暑去无迹，清驶久翩翩。", "夜将阑，人欲静，月初圆。", "素娥弄影，光射空际绿婵娟。", "不用濯缨垂钓，唤取龙宫仙驾，耕此万琼田。", "横笛望中起，吾意已超然。"]'),
('song-ci-242','贺新郎','李泳','宋','宋词','song-ci','贺新郎','[]','门掩长安道。',142,'宋词/ci.song.10000.json','["门掩长安道。", "卷重帘、垂杨散暑，嫩凉生早。", "午梦惊回庭阴翠，蝶舞莺吟未了。", "政露冷、芙蓉池沼。", "金雁尘昏么弦断，理馀音、尚想腰支袅。", "欢渐远，思还绕。", "临皋望极苍江渺。", "晚潮平、湘烟万顷，断虹残照。", "彩舫凌波分飞后，别浦菱花自老。", "问锦鲤、何时重到。", "楼迥层城看不见，对潇潇、暮雨怜芳草。", "幽恨阔、楚天杳。"]'),
('song-ci-243','定风波','李泳','宋','宋词','song-ci','定风波','[]','点点行人趁落晖。',70,'宋词/ci.song.10000.json','["点点行人趁落晖。", "摇摇烟艇出渔扉。", "一路水香流不断。", "零乱。", "春潮绿浸野蔷薇。", "南去北来愁几许，登临怀古欲沾衣。", "试问越王歌舞地。", "佳丽。", "只今惟有鹧鸪啼。"]'),
('song-ci-244','满庭芳','李洤','宋','宋词','song-ci','满庭芳','[]','麦秀连云，桑枝重绿，史君佳政流传。',118,'宋词/ci.song.10000.json','["麦秀连云，桑枝重绿，史君佳政流传。", "凤衔丹诏，来自九重天。", "千里欢腾祖帐，棠阴外、多少攀辕。", "津亭路，紞如五鼓，难驻邓侯船。", "光华，家世事，门中列戟，圯上遗编。", "况建炎勋业，图画凌烟。", "此去朝端济美，看平步、两两台躔。", "须知道，中兴盛治，主圣赖臣贤。"]'),
('song-ci-245','西江月','李洤','宋','宋词','song-ci','西江月','[]','可是江梅开晚，从教蜡雪来迟。',58,'宋词/ci.song.10000.json','["可是江梅开晚，从教蜡雪来迟。", "此花清绝胜南枝。", "搀过春风第一。", "蘸蜡女工斗巧，涂黄汉额偏宜。", "□腮相倚并开时。", "认取东君深意。"]'),
('song-ci-246','踏莎行','李淛','宋','宋词','song-ci','踏莎行','[]','红药香残，绿筠粉嫩。',68,'宋词/ci.song.10000.json','["红药香残，绿筠粉嫩。", "春归何处寻春信。", "绣鞍初上马啼轻，举头便觉长安近。", "别酒无情，啼妆有恨。", "山城向晚斜阳褪。", "清江极目带寒烟，锦鳞去后凭谁问。"]'),
('song-ci-247','满庭芳','李淛','宋','宋词','song-ci','满庭芳','[]','油幕新开，騂旄前导，暂归梓里舂容。',118,'宋词/ci.song.10000.json','["油幕新开，騂旄前导，暂归梓里舂容。", "致身槐府，功在鼎彛中。", "慨想东山故侣，烟霞外，久阔仙踪。", "今何幸，相逢吐握，谈笑一尊同。", "德星，占瑞处，旌髦五马，衮绣三公。", "对渭川遗老，绛县仙翁。", "厚意杯传绀玉，那堪更，篚实囊红。", "拼沈醉，今宵盛事，复见古人风。"]'),
('song-ci-248','千秋岁','李淛','宋','宋词','song-ci','千秋岁','[]','鄮峰凝瑞，鄞水浮佳气。',87,'宋词/ci.song.10000.json','["鄮峰凝瑞，鄞水浮佳气。", "晴景转，花光媚。", "碧幢森大纛，红旆纷千骑。", "相遇处，满城鹤发群仙萃。", "绮席张高会。", "鼍鼓笙箫沸。", "金兽袅，檀烟翠。", "玉山环回座，休惜今朝醉。", "觞再举，清歌共引千秋岁。"]'),
('song-ci-249','浣溪沙','朱熹','宋','宋词','song-ci','浣溪沙','[]','压架年来雪作堆。',48,'宋词/ci.song.10000.json','["压架年来雪作堆。", "珍丛也是近移栽。", "肯令容易放春回。", "却恐阴晴无定度，从教红白一时开。", "多情蜂蝶早飞来。"]'),
('song-ci-250','菩萨蛮','朱熹','宋','宋词','song-ci','菩萨蛮','[]','晚红飞尽春寒浅。',52,'宋词/ci.song.10000.json','["晚红飞尽春寒浅。", "浅寒春尽飞红晚。", "尊酒绿阴繁。", "繁阴绿酒尊。", "老仙诗句好。", "好句诗仙老。", "长恨送年芳。", "芳年送恨长。"]'),
('song-ci-251','菩萨蛮','朱熹','宋','宋词','song-ci','菩萨蛮','[]','暮江寒碧萦长路。',52,'宋词/ci.song.10000.json','["暮江寒碧萦长路。", "路长萦碧寒江暮。", "花坞夕阳斜。", "斜阳夕坞花。", "客愁无胜集。", "集胜无愁客。", "醒似醉多情。", "情多醉似醒。"]'),
('song-ci-252','好事近','朱熹','宋','宋词','song-ci','好事近','[]','春色欲来时，先散满天风雪。',53,'宋词/ci.song.10000.json','["春色欲来时，先散满天风雪。", "坐使七闽松竹，变珠幢玉节。", "中原佳气郁葱葱，河山壮宫阕。", "丞相功成千载，映黄流清彻。"]'),
('song-ci-253','西江月','朱熹','宋','宋词','song-ci','西江月','[]','睡处林风瑟瑟，觉来山月团团。',58,'宋词/ci.song.10000.json','["睡处林风瑟瑟，觉来山月团团。", "身心无累久轻安。", "况有清池凉馆。", "句稳翻嫌白俗，情高却笑郊寒。", "兰膏元自少陵残。", "好处金章不换。"]'),
('song-ci-254','西江月','朱熹','宋','宋词','song-ci','西江月','[]','堂下水浮新绿，门前树长交枝。',58,'宋词/ci.song.10000.json','["堂下水浮新绿，门前树长交枝。", "晚凉快写一篇诗。", "不说人间忧喜。", "身老心闲益壮，形癯道胜还肥。", "软轮加璧未应迟。", "莫道前非今是。"]'),
('song-ci-255','鹧鸪天','朱熹','宋','宋词','song-ci','鹧鸪天','[]','暮雨朝云不自怜。',64,'宋词/ci.song.10000.json','["暮雨朝云不自怜。", "放教春涨绿浮天。", "祗令画阁临无地，宿昔新诗满系船。", "青鸟外，白鸥前。", "几生香火旧因缘。", "酒阑山月移雕槛，歌罢江风拂玳筵。"]'),
('song-ci-256','鹧鸪天','朱熹','宋','宋词','song-ci','鹧鸪天','[]','已分江湖寄此生。',64,'宋词/ci.song.10000.json','["已分江湖寄此生。", "长蓑短笠任阴晴。", "鸣桡细雨沧洲远，系舸斜阳画阁明。", "奇绝处，未忘情。", "几时还得去寻盟。", "江妃定许捐双佩，渔父何劳笑独醒。"]'),
('song-ci-257','鹧鸪天','朱熹','宋','宋词','song-ci','鹧鸪天','[]','脱却儒冠著羽衣。',64,'宋词/ci.song.10000.json','["脱却儒冠著羽衣。", "青山绿水浩然归。", "看成鼎内真龙虎，管甚人间闲与非。", "生羽翼，上烟霏。", "回头祗见冢累累。", "未寻跨凤吹箫侣，且伴孤云独鹤飞。"]'),
('song-ci-258','南乡子','朱熹','宋','宋词','song-ci','南乡子','[]','落日照楼船。',66,'宋词/ci.song.10000.json','["落日照楼船。", "稳过澄江一片天。", "珍重使君留客意，依然。", "风月从今别一川。", "离绪悄危弦。", "永夜清霜透幕毡。", "明日回头江树远，怀贤。", "目断晴空雁字连。"]'),
('song-ci-259','满江红','朱熹','宋','宋词','song-ci','满江红','[]','秀野诗翁，念故山、十年乖隔。',115,'宋词/ci.song.10000.json','["秀野诗翁，念故山、十年乖隔。", "聊命驾、朱门旧隐，绿槐新陌。", "好雨初晴仍半暖，金釭玉斝开瑶席。", "更流传、丽藻借江天，留春色。", "过里社、将儿侄。", "谈往事，悲陈迹。", "喜尊前现在，镜中如昔。", "两鬓全期烟树绿，方瞳好映寒潭碧。", "但一年、一度一归来，欢何极。"]'),
('song-ci-260','水调歌头','朱熹','宋','宋词','song-ci','水调歌头','[]','富贵有馀乐，贫贱不堪忧。',114,'宋词/ci.song.10000.json','["富贵有馀乐，贫贱不堪忧。", "谁知天路幽险，倚伏互相酬。", "请看东门黄犬，更听华亭清唳，千古恨难收。", "何似鸱夷子，散发弄扁舟。", "鸱夷子，成霸业，有馀谋。", "致身千乘卿相，归把钓渔钩。", "春画五湖烟浪，秋夜一天云月，此外尽悠悠。", "永弃人间事，吾道付沧洲。"]'),
('song-ci-261','水调歌头','朱熹','宋','宋词','song-ci','水调歌头','[]','长记与君别，丹凤九重城。',114,'宋词/ci.song.10000.json','["长记与君别，丹凤九重城。", "归来故里，愁思怅望渺难平。", "今夕不知何夕，得共寒潭烟艇，一笑俯空明。", "有酒径须醉，无事莫关情。", "寻梅去，疏竹外，一枝横。", "与君吟弄风月，端不负平生。", "何处车尘不到，有个江天如许，争肯换浮名。", "只恐买山隐，却要炼丹成。"]'),
('song-ci-262','水调歌头','朱熹','宋','宋词','song-ci','水调歌头','[]','江水浸云影，鸿雁欲南飞。',114,'宋词/ci.song.10000.json','["江水浸云影，鸿雁欲南飞。", "携壶结客，何处空翠渺烟霏。", "尘世难逢一笑，况有紫萸黄菊，堪插满头归。", "风景今朝是，身世昔人非。", "酬佳节，须酩酊，莫相违。", "人生如寄，何事辛苦怨斜晖。", "无尽今来古往，多少春花秋月，那更有危机。", "与问牛山客，何必独沾衣。"]'),
('song-ci-263','念奴娇','朱熹','宋','宋词','song-ci','念奴娇','[]','临风一笑，问群芳谁是，真香纯白。',121,'宋词/ci.song.10000.json','["临风一笑，问群芳谁是，真香纯白。", "独立无朋，算只有、姑射山头仙客。", "绝艳谁怜，真心自保，邈与尘缘隔。", "天然殊胜，不关风露冰雪。", "应笑俗李粗桃，无言翻引得，狂蜂轻蝶。", "争似黄昏闲弄影，清浅一溪霜月。", "画角吹残，瑶台梦断，直下成休歇。", "绿阴青子，莫教容易波折。"]'),
('song-ci-264','水调歌头','朱熹','宋','宋词','song-ci','水调歌头','[]','雪月两相映，水石互悲鸣。',112,'宋词/ci.song.10000.json','["雪月两相映，水石互悲鸣。", "不知岩上枯木，今夜若为情。", "应见尘中胶扰。", "便道山间空旷，与麽了平生。", "与麽平生了，□水不流行。", "起披衣，瞻碧汉，露华清。", "寥寥千载，此事本分明。", "若向乾坤识易，便信行藏无间，处处总圆成。", "记取渊冰语，莫错定盘星。"]'),
('song-ci-265','忆秦娥','朱熹','宋','宋词','song-ci','忆秦娥','[]','云垂幕。',56,'宋词/ci.song.10000.json','["云垂幕。", "阴风惨淡天花落。", "天花落。", "千林琼玖，一空鸾鹤。", "征车渺渺穿华薄。", "路迷迷路增离索。", "增离索。", "剡溪山水，碧湘楼阁。"]'),
('song-ci-266','忆秦娥','朱熹','宋','宋词','song-ci','忆秦娥','[]','梅花发。',56,'宋词/ci.song.10000.json','["梅花发。", "寒梢挂著瑶台月。", "瑶台月。", "和羹心事，履霜时节。", "野桥流水声呜咽。", "行人立马空愁绝。", "空愁绝。", "为谁凝伫，为谁攀折。"]'),
('song-ci-267','水调歌头','朱熹','宋','宋词','song-ci','水调歌头','[]','不见严夫子，寂莫富春山。',114,'宋词/ci.song.10000.json','["不见严夫子，寂莫富春山。", "空馀千丈危石，高插暮云端。", "想象羊裘披了，一笑两忘身世，来把钓鱼竿。", "不似林间翮，飞倦始知还。", "中兴主，功业就，鬓毛斑。", "驰驱一世豪杰，相与济时艰。", "独委狂奴心事，不羡痴儿鼎足，放去任疏顽。", "爽气动心斗，千古照林峦。"]'),
('song-ci-268','江神子・江城子','黄铢','宋','宋词','song-ci','江神子・江城子','[]','秋风袅袅夕阳红。',86,'宋词/ci.song.10000.json','["秋风袅袅夕阳红。", "晚烟浓。", "暮云重。", "万叠青山，山外叫孤鸿。", "独上高楼三百尺，凭玉楯，睇层空。", "人间日月去匆匆。", "碧梧桐。", "又西风。", "北去南来，销尽几英雄。", "掷下玉尊天外去，多少事，不言中。"]'),
('song-ci-269','菩萨蛮','黄铢','宋','宋词','song-ci','菩萨蛮','[]','海山翠叠青螺浅。',52,'宋词/ci.song.10000.json','["海山翠叠青螺浅。", "暮云散尽天容远。", "匹马度江皋。", "北风生怒号。", "解鞍栖倦翮。", "皓月空庭白。", "何处小阑干。", "玉箫吹夜寒。"]'),
('song-ci-270','渔家傲','黄铢','宋','宋词','song-ci','渔家傲','[]','永日离忧千万绪。',72,'宋词/ci.song.10000.json','["永日离忧千万绪。", "雪舟远泛清漳浦。", "珍重故人寒夜语。", "挥玉麈。", "沈沈画阁凝香雾。", "风砌落花留不住。", "红蜂翠蝶闲飞舞。", "明日柳营江上路。", "云起处。", "苍山万叠人归去。"]'),
('song-ci-271','卜算子','高宣教','宋','宋词','song-ci','卜算子','[]','去又如何去。',26,'宋词/ci.song.10000.json','["去又如何去。", "住又如何住。", "但得山花插满头。", "休问奴归处。"]'),
('song-ci-272','卜算子','严蕊','宋','宋词','song-ci','卜算子','[]','不是爱风尘，似被前身误。',52,'宋词/ci.song.10000.json','["不是爱风尘，似被前身误。", "花落花开自有时，总是东君主。", "去也终须去。", "住也如何住。", "若得山花插满头，莫问奴归处。"]'),
('song-ci-273','如梦令','严蕊','宋','宋词','song-ci','如梦令','[]','道是梨花不是。',40,'宋词/ci.song.10000.json','["道是梨花不是。", "道是杏花不是。", "白白与红红，别是东风情味。", "曾记。", "曾记。", "人在武陵微醉。"]'),
('song-ci-274','鹊桥仙','严蕊','宋','宋词','song-ci','鹊桥仙','[]','碧梧初出，桂花才吐，池上水花微谢。',68,'宋词/ci.song.10000.json','["碧梧初出，桂花才吐，池上水花微谢。", "穿针人在合欢楼，正月露、玉盘高泻。", "蛛忙鹊懒，耕慵织倦，空做古今佳话。", "人间刚道隔年期，指天上、方才隔夜。"]'),
('song-ci-275','满江红','晦庵','宋','宋词','song-ci','满江红','[]','胶扰劳生，待足后、何时是足。',115,'宋词/ci.song.10000.json','["胶扰劳生，待足后、何时是足。", "据见定、随家丰俭，便堪龟缩。", "得意浓时休进步，须知世事多翻覆。", "漫教人、白了少年头，徒碌碌。", "谁不爱，黄金屋。", "谁不羡，千锺禄。", "奈五行不是，这般题目。", "枉费心神空计较，儿孙自有儿孙福。", "也不须、采药访神仙，惟寡欲。"]'),
('song-ci-276','清平乐','徐逸','宋','宋词','song-ci','清平乐','[]','风韶雨秀。',54,'宋词/ci.song.10000.json','["风韶雨秀。", "春已平分后。", "陡顿故人疏把酒。", "闲恁画阑搔首。", "争须携手踏青。", "人生几度清明。", "待得燕慵莺懒，杨花点点浮萍。"]'),
('song-ci-277','五福降中天','沈端节','宋','宋词','song-ci','五福降中天','[]','月胧烟澹霜蹊滑，孤宿暮林荒驿。',123,'宋词/ci.song.10000.json','["月胧烟澹霜蹊滑，孤宿暮林荒驿。", "绕树微吟，巡檐索笑，自分平生相得。", "冰池半释。", "正节物惊心，泪痕沾臆。", "流水溅溅，照影古寺满春色。", "沈叹今年未识。", "暗香微动处，人□初寂。", "酷爱芳姿，最怜幽韵，来款禅房深密。", "他时恨□。", "怅却月凌风，信音难的。", "雪底幽期，为谁还露立。"]'),
('song-ci-278','卜算子','沈端节','宋','宋词','song-ci','卜算子','[]','愁极强登临，毕竟愁难避。',52,'宋词/ci.song.10000.json','["愁极强登临，毕竟愁难避。", "千里江山黯淡中，总是悲秋意。", "谁插菊花枝，谁带茱萸佩。", "独倚阑干醉不成，日暮西风起。"]'),
('song-ci-279','卜算子','沈端节','宋','宋词','song-ci','卜算子','[]','冷蕊伴疏枝，一笑何时共。',52,'宋词/ci.song.10000.json','["冷蕊伴疏枝，一笑何时共。", "江北江南两处愁，忍看花影动。", "旅泊怕逢春，卜睡都无梦。", "岁暮何郎未得归，手拈频呵冻。"]'),
('song-ci-280','卜算子','沈端节','宋','宋词','song-ci','卜算子','[]','踏雪探孤芳，只有诗人共。',52,'宋词/ci.song.10000.json','["踏雪探孤芳，只有诗人共。", "守定南枝待得开，不觉冰轮动。", "却月与凌风，谩说扬州梦。", "想见雕阑曲沼边，残雪和烟冻。"]'),
('song-ci-281','卜算子','沈端节','宋','宋词','song-ci','卜算子','[]','客里见梅花，独赏无人共。',52,'宋词/ci.song.10000.json','["客里见梅花，独赏无人共。", "风度精神总是伊，又是归心动。", "把酒破忧端，熏被寻佳梦。", "梦觉香残一味寒，有泪都成冻。"]'),
('song-ci-282','卜算子','沈端节','宋','宋词','song-ci','卜算子','[]','烘手熨笙簧，呵冻匀酥面。',52,'宋词/ci.song.10000.json','["烘手熨笙簧，呵冻匀酥面。", "闲向梅花树下行，拜月遥相见。", "何处托春心，乐府流深怨。", "却拈寒窗傍绮疏，恨极东风远。"]'),
('song-ci-283','忆秦娥','沈端节','宋','宋词','song-ci','忆秦娥','[]','凭阑独。',56,'宋词/ci.song.10000.json','["凭阑独。", "南山影蘸杯心绿。", "杯心绿。", "悠然忽见，卧披横轴。", "西风暗度钗梁玉。", "手香记得人簪菊。", "人簪菊。", "无穷幽韵，细看不足。"]'),
('song-ci-284','惜分飞','沈端节','宋','宋词','song-ci','惜分飞','[]','喜入眉心黄点莹。',58,'宋词/ci.song.10000.json','["喜入眉心黄点莹。", "珠佩玲珑透影。", "风露萧萧冷。", "梦回月窟香成阵。", "秋后情怀君莫问。", "拼了因他瘦损。", "不似寻常韵。", "细看没处安排闷。"]'),
('song-ci-285','南歌子','沈端节','宋','宋词','song-ci','南歌子','[]','远树昏鸦闹，衰芦睡鸭双。',62,'宋词/ci.song.10000.json','["远树昏鸦闹，衰芦睡鸭双。", "雪篷烟棹炯寒光。", "疑是风林纤月、到船窗。", "时序惊心破，江山引梦长。", "思量也待不思量。", "泪染罗巾犹带、旧时香。"]'),
('song-ci-286','鹊桥仙','沈端节','宋','宋词','song-ci','鹊桥仙','[]','怀人意思，悲秋情绪，长是文园病后。',68,'宋词/ci.song.10000.json','["怀人意思，悲秋情绪，长是文园病后。", "蛛丝轻袅玉钗风，想花貌、参差依旧。", "无穷往事，一襟新恨，老泪淋浪卮酒。", "天涯相对话平生，怅南北、还如箕斗。"]'),
('song-ci-287','醉落魄・一斛珠','沈端节','宋','宋词','song-ci','醉落魄・一斛珠','[]','红娇翠弱。',67,'宋词/ci.song.10000.json','["红娇翠弱。", "春寒睡起慵匀掠。", "些儿心事谁能学。", "深院无人，时有燕穿幕。", "漏声滴尽莲花萼。", "静看月转西阑角。", "世情一任浮云薄。", "花与东君，却解慰流落。"]'),
('song-ci-288','太常引','沈端节','宋','宋词','song-ci','太常引','[]','三三五五短长亭。',62,'宋词/ci.song.10000.json','["三三五五短长亭。", "都只解、送人行。", "天远树冥冥。", "怅好梦、才成又惊。", "夜堂歌罢，小楼钟断，归路已闻莺。", "应是困瞢腾。", "问心绪、而今怎生。"]'),
('song-ci-289','谒金门','沈端节','宋','宋词','song-ci','谒金门','[]','真个忆。',53,'宋词/ci.song.10000.json','["真个忆。", "花下雨声初息。", "猛记乌衣曾旧识。", "丁宁教去觅。", "春半峭寒犹力。", "泪滴两襟成迹。", "独倚危阑清昼寂。", "草长流翠碧。"]'),
('song-ci-290','谒金门','沈端节','宋','宋词','song-ci','谒金门','[]','春欲去。',53,'宋词/ci.song.10000.json','["春欲去。", "人瘦不胜金缕。", "门巷阴阴飞絮舞。", "断肠双燕语。", "孤坐晚窗闲处。", "月到花心亭午。", "寒色著人无意绪。", "竹鸣风似雨。"]'),
('song-ci-291','谒金门','沈端节','宋','宋词','song-ci','谒金门','[]','寻胜去。',53,'宋词/ci.song.10000.json','["寻胜去。", "湖色净涵疏树。", "欸乃一声何处起。", "风铃相应语。", "目断遥林修渚。", "画出江南烟雨。", "山水照人人楚楚。", "锦肠生秀句。"]'),
('song-ci-292','菩萨蛮','沈端节','宋','宋词','song-ci','菩萨蛮','[]','春山千里供行色。',52,'宋词/ci.song.10000.json','["春山千里供行色。", "客愁浓似春山碧。", "幸自不思归。", "子规心上啼。", "芳意随人老。", "绿尽江南草。", "窈窕可人花。", "路长何处家。"]'),
('song-ci-293','菩萨蛮','沈端节','宋','宋词','song-ci','菩萨蛮','[]','愁人道酒能消解。',52,'宋词/ci.song.10000.json','["愁人道酒能消解。", "元来酒是愁人害。", "对酒越思量。", "醉来还断肠。", "酒醒初梦破。", "梦破愁无那。", "乾净不如休。", "休时只恁愁。"]'),
('song-ci-294','浣溪沙','沈端节','宋','宋词','song-ci','浣溪沙','[]','灯夜香甘动绮筵。',48,'宋词/ci.song.10000.json','["灯夜香甘动绮筵。", "明珠颗颗泛瓯圆。", "佳人巧意底难传。", "喜见翻溪流细滑，却思信手弄轻纤。", "不知辛苦为谁甜。"]'),
('song-ci-295','行香子','沈端节','宋','宋词','song-ci','行香子','[]','烟淡回塘。',84,'宋词/ci.song.10000.json','["烟淡回塘。", "月浸疏篁。", "一枝□、压尽群芳。", "修然风度，玉质金章。", "有许多情，许多韵，许多香。", "中酒情怀，琢句心肠。", "倚屏山、子细端相。", "冰芽初试，柑子新尝。", "更绮窗前，冰壶畔，看匀妆。"]'),
('song-ci-296','喜迁莺','沈端节','宋','宋词','song-ci','喜迁莺','[]','暮云千里。',125,'宋词/ci.song.10000.json','["暮云千里。", "正小雨乍晴，霜风初起。", "芦荻江边，月昏人静，独自小船儿里。", "消魂几声新雁，合造愁人天气。", "怎奈何，少年时光景，一成抛弃。", "回首空肠断，尺素未传，应是无双鲤。", "闷酒孤斟，半醺还醒，乾净不如不醉。", "有得恁多烦恼，直是没些如意。", "受尽也，待今回厮见，从头说似。"]'),
('song-ci-297','菩萨蛮','沈端节','宋','宋词','song-ci','菩萨蛮','[]','楚山千叠伤心碧。',52,'宋词/ci.song.10000.json','["楚山千叠伤心碧。", "伤心只有遥相忆。", "解佩揖巫云。", "愁生洛浦春。", "香波凝宿雾。", "梦断消魂处。", "空听水泠泠。", "如闻宝瑟声。"]'),
('song-ci-298','朝中措','沈端节','宋','宋词','song-ci','朝中措','[]','天遥野阔雁书空。',57,'宋词/ci.song.10000.json','["天遥野阔雁书空。", "山远暮云中。", "目断江南烟雨，□□敧枕春风。", "功名富贵，何须计较，烟际疏钟。", "解道浅妆浓抹，从来惟有坡翁。"]'),
('song-ci-299','念奴娇','沈端节','宋','宋词','song-ci','念奴娇','[]','灯宵渐近，更兵尘初息，韶华偏早。',120,'宋词/ci.song.10000.json','["灯宵渐近，更兵尘初息，韶华偏早。", "太守风流张宴乐，不管江城寒峭。", "发底蜂儿，钗头梅蕊，一一夸新巧。", "笙歌鼎沸，万人争看标表。", "应记革履雍容，天香满袖，侍宴游三岛。", "圣主中兴思用旧，尊礼先朝元老。", "烛赐金莲，柑传罗帕，行即趋严道。", "深杯休诉，任教银漏催晓。"]'),
('song-ci-300','念奴娇','沈端节','宋','宋词','song-ci','念奴娇','[]','重阳恁好，正秋清天色，水容如泻。',120,'宋词/ci.song.10000.json','["重阳恁好，正秋清天色，水容如泻。", "野阔风高香雾满，采菊无人同把。", "堪笑渊明，蓬头曳杖，吟赏东篱下。", "孤风远韵，至今犹作佳话。", "争似太守才贤，慈祥恺悌，赋政多闲暇。", "千里江山供胜践，尊俎延登儒雅。", "只恐相将，吹花春宴，不许斯民借。", "花嘲便坐，尚怀方外司马。"]'),
('song-ci-301','青玉案','沈端节','宋','宋词','song-ci','青玉案','[]','史君标韵如徐庾。',80,'宋词/ci.song.10000.json','["史君标韵如徐庾。", "更名节、高千古。", "卧治姑溪才小驻。", "闲云无定，阳春有脚，又作南昌去。", "兴来亭上清歌度。", "尽能唱、公诗句。", "记取诸生临别语。", "从容占对，天颜应喜，千万留王所。"]'),
('song-ci-302','洞仙歌','沈端节','宋','宋词','song-ci','洞仙歌','[]','雪肌花貌，见了千千万。',100,'宋词/ci.song.10000.json','["雪肌花貌，见了千千万。", "眼去眉来几曾管。", "被今回打住，没□施程，□捺地，却悔看承较晚。", "琴心传密意，唯有相知，失笑他满恁撩乱。", "抖下俏和娇，掩翠凌红，真个是、从前可见。", "据入马牢笼怎乾休，但拈取真诚，试教人看。"]'),
('song-ci-303','洞仙歌','沈端节','宋','宋词','song-ci','洞仙歌','[]','夜来惊怪，冷逼流苏帐。',101,'宋词/ci.song.10000.json','["夜来惊怪，冷逼流苏帐。", "梦破初闻打窗响。", "向晓开帘，凌乱千里寒光，清兴发，鹤氅谁同纵赏。", "江南春意动，梅竹潜通，醉帽冲风自来往。", "慨念故人疏，便理扁舟，须信道、吾曹清旷。", "待石鼎煎茶洗馀醺，更依旧归来，浅斟低唱。"]'),
('song-ci-304','洞仙歌','沈端节','宋','宋词','song-ci','洞仙歌','[]','重阳近也，渐秋光凄劲。',100,'宋词/ci.song.10000.json','["重阳近也，渐秋光凄劲。", "宿雨初收好风景。", "正干戈耆定，禾黍丰登，人意乐，歌舞贤侯美政。", "醉翁游历处，胜概依然，木落淮南见山影。", "有客共登临，醉里疏狂，敧乌帽、从嘲雪鬓。", "但目送孤鸿傍危栏，笑问道，黄花似谁风韵。"]'),
('song-ci-305','虞美人','沈端节','宋','宋词','song-ci','虞美人','[]','去年寒食初相见。',66,'宋词/ci.song.10000.json','["去年寒食初相见。", "花上双飞燕。", "今年寒食又花开。", "垂下重帘不许、燕归来。", "隔帘听燕呢喃语。", "似说相思苦。", "东君都不管闲愁。", "一任落花飞絮、两悠悠。"]'),
('song-ci-306','虞美人','沈端节','宋','宋词','song-ci','虞美人','[]','卧红堆碧纷无数。',66,'宋词/ci.song.10000.json','["卧红堆碧纷无数。", "春事知何许。", "班班小雨裛犁花。", "又是清明时候、不归家。", "伤春减尽东阳带。", "人道多情杀。", "青春留下许多愁。", "分付与君今夜、一齐休。"]'),
('song-ci-307','虞美人','沈端节','宋','宋词','song-ci','虞美人','[]','暮云衰草连天远。',66,'宋词/ci.song.10000.json','["暮云衰草连天远。", "不记离人怨。", "可怜无处不关情。", "梦断孤鸿哀怨、两三声。", "恨眉醉眼何时见。", "夜夜相思遍。", "梧桐叶落候蛩秋。", "唯有一江烟雨、替人愁。"]'),
('song-ci-308','探春令','沈端节','宋','宋词','song-ci','探春令','[]','旧家元夜，追随风月，连宵欢宴。',63,'宋词/ci.song.10000.json','["旧家元夜，追随风月，连宵欢宴。", "被那懑、引得滴流地，一似蛾儿转。", "而今百事心情懒。", "灯下几曾忺看。", "算静中、唯有窗间梅影，合是幽人伴。"]'),
('song-ci-309','如梦令','沈端节','宋','宋词','song-ci','如梦令','[]','雨后轻寒天气。',40,'宋词/ci.song.10000.json','["雨后轻寒天气。", "玉酒中人小醉。", "乍报一番秋，晚簟清凉如水。", "忺睡。", "忺睡。", "窗在芭蕉叶底。"]'),
('song-ci-310','薄幸','沈端节','宋','宋词','song-ci','薄幸','[]','桂轮香满。',132,'宋词/ci.song.10000.json','["桂轮香满。", "送寒色、轻风剪剪。", "又还是、幽窗人静，梅影参差初转。", "念少年孤负芳音，多时不见文君面。", "漫快泻琼舟，浓熏宝鸭，终是心情差懒。", "谩就枕，浑无寐，□听彻、天边飞雁。", "闲愁消万缕，如何消遣。", "绣衾□忆鸳鸯暖。", "细思量、遍倚屏山，挑尽琴心，谁识相思怨。", "休文瘦损，陡觉频移带眼。"]'),
('song-ci-311','江城子','沈端节','宋','宋词','song-ci','江城子','[]','秋声昨夜入梧桐。',86,'宋词/ci.song.10000.json','["秋声昨夜入梧桐。", "雨濛濛。", "洒窗风。", "短杵疏砧，将恨到帘栊。", "归梦未成心已远，云不断，水无穷。", "有人应念水之东。", "鬓如蓬。", "理妆慵。", "览镜沈吟，膏沐为谁容。", "多少相思多少事，都尽在，不言中。"]'),
('song-ci-312','满庭芳','沈端节','宋','宋词','song-ci','满庭芳','[]','雾薄阴轻，林深烟暖，海棠特地开迟。',118,'宋词/ci.song.10000.json','["雾薄阴轻，林深烟暖，海棠特地开迟。", "光风绝艳，独自殿芳时。", "须信东君注意，花神会、别有看持。", "群英外，嫣然一笑，富贵出添姿。", "日长，春睡足，粉香扑扑，酒晕微微。", "明皇当日，称许最相宜。", "妃子扶来半醉，宫妆淡、不扫蛾眉，偏怜处，流莺惊绕，金弹拂丛飞。"]'),
('song-ci-313','采桑子','沈端节','宋','宋词','song-ci','采桑子','[]','昔年曾记寻芳处，短帽冲寒。',52,'宋词/ci.song.10000.json','["昔年曾记寻芳处，短帽冲寒。", "竹外江干。", "玉面皮儿月下观。", "而今老大风流减，百事心阑。", "谷底林间。", "坐对横枝祗鼻酸。"]'),
('song-ci-314','西江月','沈端节','宋','宋词','song-ci','西江月','[]','一枕香消睡恼，十年漂泊江湖。',58,'宋词/ci.song.10000.json','["一枕香消睡恼，十年漂泊江湖。", "空馀清梦绕康庐。", "记得林间风度。", "锦绣谷中旧客，襟怀未肯全疏。", "从今不要别人扶。", "醉拥紫云归去。"]'),
('song-ci-315','喜迁莺','沈端节','宋','宋词','song-ci','喜迁莺','[]','冰池轻皱。',126,'宋词/ci.song.10000.json','["冰池轻皱。", "喜寒律乍回，微阳初透。", "岁晚云黄，日晴烟暖，昼刻暗添宫漏。", "山色岸容都变，春意欲传官柳。", "最好处，正酥融粉薄，一枝梅瘦。", "行乐，春渐近，景胜欢长，幼眇丝簧奏。", "鸣玉鹓行，退朝花院，犹有御香沾袖。", "试问西邻虽富，何似东皋依旧。", "趁未老，便优游林壑，围棋把酒。"]'),
('song-ci-316','西江月','沈端节','宋','宋词','song-ci','西江月','[]','幸自心肠稳审，怎禁眼脑迷奚。',58,'宋词/ci.song.10000.json','["幸自心肠稳审，怎禁眼脑迷奚。", "招愁买恨带人疑。", "一味笑吟吟地。", "闲趁莺来日下，却随燕入乌衣。", "阿蛮风味有谁知。", "认得乐天词意。"]'),
('song-ci-317','念奴娇','沈端节','宋','宋词','song-ci','念奴娇','[]','嫩凉清晓，淡秋容、横写鲛绡十幅。',120,'宋词/ci.song.10000.json','["嫩凉清晓，淡秋容、横写鲛绡十幅。", "山水光中参意味，不管人间荣辱。", "藜杖棕鞋，纶巾鹤氅，宾主俱遗俗。", "倚阑舒啸，一樽花下相属。", "云际有药千年，琼瑶争秀发，龙蛇新斸。", "富贵功名元自有，且乐无穷真福。", "莲社风流，醉乡跌宕，时奏长生曲。", "月娥同听，好风徐韵松竹。"]'),
('song-ci-318','念奴娇','沈端节','宋','宋词','song-ci','念奴娇','[]','洛妃汉女，护春寒、不惜鲛绡重叠。',120,'宋词/ci.song.10000.json','["洛妃汉女，护春寒、不惜鲛绡重叠。", "拾翠江边烟澹澹，交影参差胧月。", "秦虢相将，英娥接武，同宴瑶池雪。", "层冰连璧，个中谁敢优劣。", "著意晕纷饶酥，韵多香剩，都与群花别。", "娟秀敷腴索笑处，玉脸微生娇靥。", "羞损南枝，映翻绿萼，不数黄千叶。", "形容不尽，细看一倍清绝。"]'),
('song-ci-319','念奴娇','沈端节','宋','宋词','song-ci','念奴娇','[]','湖山照影，正日长娇困，不烦匀扫。',120,'宋词/ci.song.10000.json','["湖山照影，正日长娇困，不烦匀扫。", "絮满长洲春澹沲，开遍吴宫花草。", "嫩绿葱葱，轻红簌簌，渐觉枝头少。", "馀芳难并，破愁惟有馨醥。", "应是留得东君，海棠方待折，玉环娇小。", "雾薄阴轻初睡足，宝幄画屏香袅。", "醉态天真，半羞微敛，未肯都开了。", "嫣然一笑，此时风度尤好。"]'),
('song-ci-320','念奴娇','沈端节','宋','宋词','song-ci','念奴娇','[]','寻幽览胜，凭危栏、极目风烟平楚。',120,'宋词/ci.song.10000.json','["寻幽览胜，凭危栏、极目风烟平楚。", "自笑飘零惊岁晚，欲挂衣冠神武。", "芳甸时巡，醉乡日化，庭实名花旅。", "阆风蓬顶，自来不见烽戍。", "宴罢玉宇琼楼，醉中都忘却，瑶池归路。", "俯瞰尘寰千万落，渺渺峰端栖雾。", "群玉图书，广寒宫殿，一一经行处。", "相羊物外，旷怀高视千古。"]'),
('song-ci-321','感皇恩','沈端节','宋','宋词','song-ci','感皇恩','[]','和气霭微宵，黄云飘转。',81,'宋词/ci.song.10000.json','["和气霭微宵，黄云飘转。", "东阁观梅负诗眼。", "满斟绿酒，唱个曲儿亲劝。", "愿从今日去，长相见。", "宝幄欢浓，玉炉香软。", "彼此宜冬镇长键。", "绣床儿畔，渐渐日迟风暖。", "告他事事底，饶一线。"]'),
('song-ci-322','六州歌头','张孝祥','宋','宋词','song-ci','六州歌头','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','长怀望断，关塞莽然平。',182,'宋词/ci.song.10000.json','["长怀望断，关塞莽然平。", "征尘暗，霜风劲，悄边声。", "黯销凝。", "追想当年事，殆天数，非人力，洙泗上，弦歌地，亦膻腥。", "隔水毡乡，落日牛羊下，区脱纵横。", "看名王宵猎，骑火一川明。", "笳鼓悲鸣。", "遣人惊。", "念腰间箭，匣中剑，空埃蠹，竟何成。", "时易失，心徒壮，岁将零。", "渺神京。", "干羽方怀远，静烽燧，且休兵。", "冠盖使，纷驰骛，若为情。", "闻道中原遗老，常南望，羽葆霓旌。", "使行人到此，忠愤气填膺。", "有泪如倾。"]'),
('song-ci-323','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','隆中三顾客，圯上一编书。',114,'宋词/ci.song.10000.json','["隆中三顾客，圯上一编书。", "英雄当日感会，馀事了寰区。", "千载神交二子，一笑眇然兹世，却愿驾柴车。", "长忆淮南岸，耕钓混樵渔。", "忽扁舟，凌骇浪，到三吴。", "纶巾羽扇容与，争看列仙儒。", "不为莼鲈笠泽，便卦衣冠神武，此兴渺江湖。", "举酒对明月，高曳九霞裾。"]'),
('song-ci-324','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','猩鬼啸篁竹，玉帐夜分弓。',114,'宋词/ci.song.10000.json','["猩鬼啸篁竹，玉帐夜分弓。", "少年荆楚剑客，突骑锦襜红。", "千里风飞雷厉，四校星流慧扫，萧斧锉春葱。", "谈笑青油幕，日奏捷书同。", "诗书帅，黄阁老，黑头公。", "家传鸿宝秘略，小试不言功。", "闻道玺书频下，看即沙堤归去，帷幄且从容。", "君王自神武，一举朔庭空。"]'),
('song-ci-325','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','濯足夜滩急，晞发北风凉。',114,'宋词/ci.song.10000.json','["濯足夜滩急，晞发北风凉。", "吴山楚泽行遍，只欠到潇湘。", "买得扁舟归去，此事天公付我，六月下沧浪。", "蝉脱尘埃外，蝶梦水云乡。", "制荷衣，纫兰佩，把琼芳。", "湘妃起舞一笑，抚瑟奏清商。", "唤起九歌忠愤，拂拭三闾文字，还与日争光。", "莫遣儿辈觉，此乐未渠央。"]'),
('song-ci-326','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','江山自雄丽，风露与高寒。',114,'宋词/ci.song.10000.json','["江山自雄丽，风露与高寒。", "寄声月姊，借我玉鉴此中看。", "幽壑鱼龙悲啸，倒影星辰摇动，海气夜漫漫。", "涌起白银阕，危驻紫金山。", "表独立，飞霞佩，切云冠。", "漱水濯雪，眇视万里一毫端。", "回首三山何处，闻道群仙笑我，要我欲俱还。", "挥手从此去，翳风更骖鸾。"]'),
('song-ci-327','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','淮楚襟带地，云梦泽南州。',117,'宋词/ci.song.10000.json','["淮楚襟带地，云梦泽南州。", "沧江翠壁佳处，突兀起红楼。", "凭仗使君胸次，与问老仙何在，长啸俯清秋。", "试遣吹箫看，骑鹤恐来游。", "欲乘风，凌万顷，泛扁舟。", "山高月小，霜露既降，凛凛不能留。", "一吊周郎羽扇，尚想曹公横槊，兴废两悠悠。", "此意无尽藏，分付水东流。"]'),
('song-ci-328','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','青嶂度云气，幽壑舞回风。',114,'宋词/ci.song.10000.json','["青嶂度云气，幽壑舞回风。", "山神助我奇观，唤起碧宵龙。", "电掣金蛇千丈，雷震灵鼍万垒，汹汹欲崩空。", "尽泻银潢水，倾入宝莲宫。", "坐中客，凌积翠，看奔洪。", "人间应失匕箸，此地独从容。", "洗了从来尘垢，润及无边焦槁，造物不言功。", "天宇忽开霁，日在五云东。"]'),
('song-ci-329','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','五岭皆炎热，宜人独桂林。',114,'宋词/ci.song.10000.json','["五岭皆炎热，宜人独桂林。", "江南驿使未到，梅蕊破春心。", "繁会九衢三市，缥缈层楼杰观，雪片一冬深。", "自是清凉国，莫遣瘴烟侵。", "江山好，青罗带，碧玉簪。", "平沙细浪欲尽，陡起忽千寻。", "家种黄柑丹荔，户拾明珠翠羽，箫鼓夜沈沈。", "莫问骖鸾事，有酒且频斟。"]'),
('song-ci-330','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','今夕复何夕，此地过中秋。',114,'宋词/ci.song.10000.json','["今夕复何夕，此地过中秋。", "赏心亭上唤客，追忆去年游。", "千里江山如画，万井笙歌不夜，扶路看遨头。", "玉界拥银阕，珠箔卷琼钩。", "驭风去，忽吹到，岭边州。", "去年明月依旧，还照我登楼。", "楼下水明沙静，楼外参横斗转，搔首思悠悠。", "老子兴不浅，聊复此淹留。"]'),
('song-ci-331','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','雪洗虏尘静，风约楚云留。',117,'宋词/ci.song.10000.json','["雪洗虏尘静，风约楚云留。", "何人为写悲壮，吹角古城楼。", "湖海平生豪气，关塞如今风景，剪烛看吴钩。", "胜喜然犀处，骇浪与天浮。", "忆当年，周与谢，富春秋。", "小乔初嫁，香囊未解，勋业故优游。", "赤壁矶头落照，肥水桥边衰草，渺渺唤人愁。", "我欲乘风去，击楫誓中流。"]'),
('song-ci-332','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','云海漾空阔，风露凛高寒。',114,'宋词/ci.song.10000.json','["云海漾空阔，风露凛高寒。", "仙翁鹤驾，羽节缥缈下天端。", "指点虚无征路，时见双凫飞舞，挥斥隘尘寰。", "吹笛向何处，海上有三山。", "彩衣新，鱼服丽，更朱颜。", "蟠桃未熟，千岁容与且人间。", "早晚金泥封诏，归侍玉皇香案，踵武列仙班。", "玉骨自难老，未用九霞丹。"]'),
('song-ci-333','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','紫橐论思旧，碧落拜除新。',114,'宋词/ci.song.10000.json','["紫橐论思旧，碧落拜除新。", "内家敕使，传诏亲付玉麒麟。", "千里江山增丽，是处旌旗改色，佳气郁轮囷。", "看取连宵雪，借与万家春。", "建崇牙，开盛府，是生辰。", "十州老稚，都向今日祝松椿。", "多少活人阴德，合享无边长算，唯有我知君。", "来岁更今日，一气转洪钧。"]'),
('song-ci-334','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','["\u592a\u6e56"]','舣棹太湖岸，天与水相连。',114,'宋词/ci.song.10000.json','["舣棹太湖岸，天与水相连。", "垂虹亭上，五年不到故依然。", "洗我征尘三斗，快揖商飙千里，鸥鹭亦翩翩。", "身在水晶阕，真作驭风仙。", "望中秋，无五日，月还圆。", "倚栏清啸孤发，惊起壑龙眠。", "欲酹鸱夷西子，未办当年功业，空系五湖船。", "不用知馀事，莼鲙正芳鲜。"]'),
('song-ci-335','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','螯禁辍颇牧，熊拭赖龙黄。',114,'宋词/ci.song.10000.json','["螯禁辍颇牧，熊拭赖龙黄。", "一时林莽千险，蜂午要驱攘。", "金版六韬初拭，烟敛山空野回，低草见牛羊。", "旒纩释南顾，戈甲濯银潢。", "玉书下，褒懿绩，促曹装。", "帝宸天近，红旆东去带朝阳。", "归辅五云丹陛，回首楚楼千里，遗爱满潇湘。", "应记依刘客，曾此奉离觞。"]'),
('song-ci-336','多丽','张孝祥','宋','宋词','song-ci','多丽','[]','景萧疏，楚江那更高秋。',171,'宋词/ci.song.10000.json','["景萧疏，楚江那更高秋。", "远连天，茫茫都是，败芦枯蓼汀洲。", "认炊烟，几家蜗舍，映夕照，一簇渔舟。", "去国虽遥，宁亲渐近，数峰青处是吾州。", "便乘取，波平风静，荃棹且夷犹。", "关情有，冥冥去雁，拍拍轻鸥。", "忽追思，当年往事，惹起无限羁愁。", "拄笏朝来多爽气，秉烛夜永足清游。", "翠袖香寒，朱弦韵悄，无情江水只东流。", "柂楼晚，清商哀怨，还听隔船讴。", "无言久，馀霞散绮，烟际帆收。"]'),
('song-ci-337','木兰花慢','张孝祥','宋','宋词','song-ci','木兰花慢','[]','送归云去雁，澹寒采、满溪楼。',121,'宋词/ci.song.10000.json','["送归云去雁，澹寒采、满溪楼。", "正佩解湘腰，钗孤楚鬓，鸾鉴分收。", "凝情望行处路，但疏烟远树织离忧。", "只有楼前溪水，伴人清泪长流。", "霜华夜永逼衾绸。", "唤谁护衣篝。", "念芬馆重来，芳尘未扫，争见嬉游。", "情知闷来殢酒，奈回肠、不醉只添愁。", "脉脉无言竟日，断魂双鹜南州。"]'),
('song-ci-338','木兰花慢','张孝祥','宋','宋词','song-ci','木兰花慢','[]','紫箫吹散后，恨燕子，只空楼。',120,'宋词/ci.song.10000.json','["紫箫吹散后，恨燕子，只空楼。", "念璧月长亏，玉簪中断，覆水难收。", "青鸾送碧云句，道霞扃雾锁不堪优。", "情与文梭共织，怨随宫叶同流。", "人间天上两悠悠。", "暗泪洒灯篝。", "记谷口园林，当时驿舍，梦里曾游。", "银屏低闻笑语，但醉时冉冉醒时愁。", "拟把菱花一半，试寻高价皇州。"]'),
('song-ci-339','水龙吟','张孝祥','宋','宋词','song-ci','水龙吟','[]','竹舆晓入青阳，细风凉月天如洗。',129,'宋词/ci.song.10000.json','["竹舆晓入青阳，细风凉月天如洗。", "峰回路转，云舒霞卷，了非人世。", "转就丹砂，铸成金鼎，碧光相倚。", "料天关虎守，箕畴龙负，开神秘、留兹地。", "缥缈珠幢羽卫。", "望蓬莱、初无弱水。", "仙人拍手，山头笑我，尘埃满袂。", "春锁瑶房，雾迷芝圃，昔游都记。", "怅世缘未了，匆匆又去，空凝伫、烟霄里。"]'),
('song-ci-340','水龙吟','张孝祥','宋','宋词','song-ci','水龙吟','[]','平生只说浯溪，斜阳唤我归船系。',129,'宋词/ci.song.10000.json','["平生只说浯溪，斜阳唤我归船系。", "月华未吐，波光不动，新凉如水。", "长啸一声，山鸣谷应，栖禽惊起。", "问元颜去后，水流花谢，当年事，凭谁记。", "须信两翁不死。", "驾飞车，时游兹地。", "漫郎宅里，中兴碑下，应留屐齿。", "酌我清尊，洗公孤愤，来同一醉。", "待相将把袂，清都归路，骑鹤去，三千岁。"]'),
('song-ci-341','念奴娇','张孝祥','宋','宋词','song-ci','念奴娇','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u6d1e\u5ead\u6e56"]','洞庭青草，近中秋、更无一点风色。',120,'宋词/ci.song.10000.json','["洞庭青草，近中秋、更无一点风色。", "玉鉴琼田三万顷，著我扁舟一叶。", "素月分辉，明河共影，表里俱澄澈。", "悠然心会，妙处难与君说。", "应念岭海经年，孤光自照，肝肺皆冰雪。", "短发萧骚襟袖冷，稳泛沧浪空阔。", "尽吸西江，细斟北斗，万象为宾客。", "扣舷独笑，不知今夕何夕。"]'),
('song-ci-342','念奴娇','张孝祥','宋','宋词','song-ci','念奴娇','[]','弓刀陌上，净蛮烟瘴雨，朔云边雪。',120,'宋词/ci.song.10000.json','["弓刀陌上，净蛮烟瘴雨，朔云边雪。", "幕府横驱三万里，一把平安遥接。", "方丈三韩，西山八诏，慕义羞椎结。", "梯航入贡，路经头痛身热。", "今代文武通人，青宵不上，却把南州节。", "虏马秋肥雕力健，应看名王宵猎。", "壮士长歌，故人一笑，趁得梅花月。", "王春奏计，便须平布清切。"]'),
('song-ci-343','念奴娇','张孝祥','宋','宋词','song-ci','念奴娇','[]','朔风吹雨，送凄凉天气，垂垂欲雪。',120,'宋词/ci.song.10000.json','["朔风吹雨，送凄凉天气，垂垂欲雪。", "万里南荒云雾满，弱水蓬莱相接。", "冻合龙冈，寒侵铜柱，碧海冰澌结。", "凭高一笑，问君何处炎热。", "家在楚尾吴头，归期犹未，对此惊时节。", "忆得年时貂帽暖，铁马千群观猎。", "狐兔成车，笙歌震地，归踏层城月。", "持杯且醉，不须北望凄切。"]'),
('song-ci-344','念奴娇','张孝祥','宋','宋词','song-ci','念奴娇','[]','绣衣使者，度郢中绝唱，阳春白雪。',120,'宋词/ci.song.10000.json','["绣衣使者，度郢中绝唱，阳春白雪。", "人物应须天上去，一日君恩三接。", "粉省香浓，宫床锦重，更把丝絇结。", "臣心如水，不教炙手成热。", "还记岭海相从，长松千丈，映我秋竿节。", "忍冻推敲清兴满，风里乌巾猎猎。", "只要东归，归心入梦，梦泛寒江月。", "不因莼鲙。", "白头亲望真切。"]'),
('song-ci-345','念奴娇','张孝祥','宋','宋词','song-ci','念奴娇','[]','星沙初下，望重湖远水，长云漠漠。',120,'宋词/ci.song.10000.json','["星沙初下，望重湖远水，长云漠漠。", "一叶扁舟谁念我，今日天涯飘泊。", "平楚南来，大江东去，处处风波恶。", "吴中何地，满怀俱是离索。", "常记送我行时，绿波亭上，泣透青头薄。", "樯燕低飞人去后，依旧湘城帘幕。", "不尽山川，无穷烟浪，辜负秦楼约。", "渔歌声断，为君双泪倾落。"]'),
('song-ci-346','醉蓬莱','张孝祥','宋','宋词','song-ci','醉蓬莱','[]','问人间荣事。',120,'宋词/ci.song.10000.json','["问人间荣事。", "海内高名，似今谁比。", "脱屣归来，眇浮云富贵。", "致远钩深，乐天知命，且从容阅世。", "火候周天，金文满义，从来活计。", "有酒一尊，有棋一局，少日亲朋，旧家邻里。", "世故纷纭，但蚊虻过耳。", "解愠薰风，做凉梅雨，又一般天气。", "曲几蒲团，纶巾羽扇，年年如是。"]'),
('song-ci-347','雨中花慢','张孝祥','宋','宋词','song-ci','雨中花慢','[]','一叶凌波，十里驭风，烟鬟雾鬓萧萧。',119,'宋词/ci.song.10000.json','["一叶凌波，十里驭风，烟鬟雾鬓萧萧。", "认得兰皋琼佩，水馆冰绡。", "秋霁明霞乍吐，曙凉宿霭初消。", "恨微颦不语，少进还收，伫立超遥。", "神交冉冉，愁思盈盈，断魂欲遣谁招。", "犹自待，青鸾传信，乌鹊成桥。", "怅望胎仙琴叠，忍看翡翠兰苕。", "梦回人远，红云一片，天际笙箫。"]'),
('song-ci-348','二郎神','张孝祥','宋','宋词','song-ci','二郎神','[]','坐中客。',130,'宋词/ci.song.10000.json','["坐中客。", "共千里、潇湘秋色。", "渐万宝西成农事了，䆉稏看、黄云阡陌。", "乔□橘洲风浪稳，岳镇耸、倚天青壁。", "追前事、兴亡相续，空与山川陈迹。", "南国。", "都会繁盛，依然似昔。", "聚翠羽明珠三市满，楼观涌、参差金碧。", "乞巧处、家家追乐事，争要做、丰年七夕。", "愿明年强健，百姓欢娱，还如今日。"]'),
('song-ci-349','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','同是瀛州册府仙。',48,'宋词/ci.song.10000.json','["同是瀛州册府仙。", "只今聊结社中莲。", "胡笳按拍酒如川。", "唤起封姨清晚景，更将荔子荐新圆。", "从今三夜看蝉娟。"]'),
('song-ci-350','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','细仗春风簇翠筵。',48,'宋词/ci.song.10000.json','["细仗春风簇翠筵。", "烂银袍拂禁炉烟。", "旃书名字压宫垣。", "太学诸生推独步，玉堂学士合登仙。", "乃翁种德满心田。"]'),
('song-ci-351','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','只说闽山锦绣帷。',48,'宋词/ci.song.10000.json','["只说闽山锦绣帷。", "忽从团扇得生枝。", "绉红衫子映丰肌。", "春线应怜壶漏永，夜针频见烛花摧。", "尘飞一骑忆来时。"]'),
('song-ci-352','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','滟滟湖光绿一围。',48,'宋词/ci.song.10000.json','["滟滟湖光绿一围。", "修林断处白鸥飞。", "天机云锦蘸空飞。", "乞我百弓真可老，为公一饮醉忘归。", "扁舟日日弄晴晖。"]'),
('song-ci-353','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','晚雨潇潇急做秋。',48,'宋词/ci.song.10000.json','["晚雨潇潇急做秋。", "西风凉鬓已飕飕。", "烛花明夜酒花浮。", "醉眼定知非妙赏，□词端为□□留。", "想君泾渭不同流。"]'),
('song-ci-354','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','稳泛仙舟上锦帆。',48,'宋词/ci.song.10000.json','["稳泛仙舟上锦帆。", "桃花清浪舞清湾。", "寿星相伴到人间。", "黄石公传三百字，西王母授九霞丹。", "银潢有路接三山。"]'),
('song-ci-355','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','北苑春风小凤团。',48,'宋词/ci.song.10000.json','["北苑春风小凤团。", "炎州沈水胜龙涎。", "殷勤送与绣衣仙。", "玉食乡来思苦口，芳名久合上凌烟。", "天教富贵出长年。"]'),
('song-ci-356','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','霜日明宵水蘸空。',48,'宋词/ci.song.10000.json','["霜日明宵水蘸空。", "鸣鞘声里绣旗红。", "澹烟衰草有无中。", "万里中原烽火北，一尊浊酒戍楼东。", "酒阑挥泪向悲风。"]'),
('song-ci-357','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','宫柳垂垂碧照空。',48,'宋词/ci.song.10000.json','["宫柳垂垂碧照空。", "九门深处五云红。", "朱衣只在殿当中。", "细拈丝梢龙尾北，缓携纶旨凤池东。", "阿婆三五笑春风。"]'),
('song-ci-358','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','日暖帘帏春画长。',48,'宋词/ci.song.10000.json','["日暖帘帏春画长。", "纤纤玉指动抨床。", "低头佯不顾檀郎。", "豆蔻枝头双蛱蝶，芙蓉花下两鸳鸯。", "壁间闻得唾茸香。"]'),
('song-ci-359','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','射策金门记昔年。',48,'宋词/ci.song.10000.json','["射策金门记昔年。", "又交藩翰入陶甄。", "不妨衣钵再三传。", "粉泪但能添楚竹，罗巾谁解系吴船。", "捧杯犹愿小留连。"]'),
('song-ci-360','浪淘沙','张孝祥','宋','宋词','song-ci','浪淘沙','[]','琪树间瑶林。',64,'宋词/ci.song.10000.json','["琪树间瑶林。", "春意深深。", "梅花还被晓寒禁。", "竹里一枝斜向我，欲诉芳心。", "楼外卷重阴。", "玉界沈沈。", "何人低唱醉泥金。", "掠水飞来双翠碧，应寄归音。"]'),
('song-ci-361','浪淘沙','张孝祥','宋','宋词','song-ci','浪淘沙','[]','溪练写寒林。',64,'宋词/ci.song.10000.json','["溪练写寒林。", "云重烟深。", "楼高风恶酒难禁。", "徙倚阑干谁共语，江上愁心。", "清兴满山阴。", "鸿断鱼沈。", "一书何啻值千金。", "独扶瑶微弦欲断，凭寄知音。"]'),
('song-ci-362','定风波','张孝祥','宋','宋词','song-ci','定风波','[]','铃索声乾夜未央。',70,'宋词/ci.song.10000.json','["铃索声乾夜未央。", "曲栏花影步凄凉。", "莫道岭南冬更暖。", "君看。", "梅花如雪月如霜。", "见说墙西歌吹好，玉人扶坐劝飞觞。", "老子婆婆成独冷。", "谁省。", "自挑寒灺自添香。"]'),
('song-ci-363','望江南・忆江南','张孝祥','宋','宋词','song-ci','望江南・忆江南','[]','谈子醉，独立睨东风。',64,'宋词/ci.song.10000.json','["谈子醉，独立睨东风。", "未试玉堂挥翰手，只今楚泽钓鱼翁。", "万事举杯空。", "谋一笑，一笑与君同。", "身老南山看射虎，眼高四海送飞鸿。", "赤岸晚潮通。"]'),
('song-ci-364','望江南・忆江南','张孝祥','宋','宋词','song-ci','望江南・忆江南','[]','朝元去，深殿扣瑶钟。',64,'宋词/ci.song.10000.json','["朝元去，深殿扣瑶钟。", "天近月明黄道冷，参回斗转碧宵空。", "身在九光中。", "风露下，环佩响丁东。", "玉案烧香萦翠凤，松坛移影动苍龙。", "归路海霞红。"]'),
('song-ci-365','醉落魄・一斛珠','张孝祥','宋','宋词','song-ci','醉落魄・一斛珠','[]','轻黄澹绿。',67,'宋词/ci.song.10000.json','["轻黄澹绿。", "可人风韵闲装束。", "多情早是眉峰蹙。", "一点秋波，闲里观人毒。", "桃花庭院光阴速。", "铜鞮谁唱大堤曲。", "归时想是樱桃熟。", "不道秋千，谁伴那人蹴。"]'),
('song-ci-366','桃源忆故人','张孝祥','宋','宋词','song-ci','桃源忆故人','[]','朔风弄月吹银霰。',56,'宋词/ci.song.10000.json','["朔风弄月吹银霰。", "帘幕低垂三面。", "酒入玉肌香软。", "压得寒威敛。", "檀槽乍拈么丝慢。", "弹得相思一半。", "不道有人肠断。", "犹作声声颤。"]'),
('song-ci-367','临江仙','张孝祥','宋','宋词','song-ci','临江仙','[]','试问梅花何处好，与君藉草携壶。',70,'宋词/ci.song.10000.json','["试问梅花何处好，与君藉草携壶。", "西园清夜片尘无。", "一天云破碎，两树玉扶疏。", "谁擫昭华吹古怨，散花便满衣裾。", "只疑幽梦在清都。", "星稀河影转，霜重月华孤。"]'),
('song-ci-368','临江仙','张孝祥','宋','宋词','song-ci','临江仙','[]','试问宜楼楼下竹，年来应长新篁。',70,'宋词/ci.song.10000.json','["试问宜楼楼下竹，年来应长新篁。", "使君五岭又三湘。", "旧游知好在，熟处更难忘。", "尚念论心舒歗否，只今湖海相望。", "遥怜阴过酒尊凉。", "举觞须酹我，门外是清江。"]'),
('song-ci-369','如梦令','张孝祥','宋','宋词','song-ci','如梦令','[]','花叶相遮相映。',40,'宋词/ci.song.10000.json','["花叶相遮相映。", "雨过翠明金润。", "折得一枝归，满路清香成阵。", "风韵。", "风韵。", "寄赠绮窗云鬓。"]'),
('song-ci-370','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','丝金缕翠幡儿小。',52,'宋词/ci.song.10000.json','["丝金缕翠幡儿小。", "裁罗拈线花枝袅。", "明日是新春。", "春风生鬓云。", "吴霜看点点。", "愁里春来浅。", "只愿此花枝。", "年年长带伊。"]'),
('song-ci-371','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','庭叶翻翻秋向晚。',52,'宋词/ci.song.10000.json','["庭叶翻翻秋向晚。", "凉砧敲月催金剪。", "楼上已清寒。", "不堪频倚栏。", "邻翁开社瓮。", "唤客情意重。", "不醉且无归。", "醉时归路迷。"]'),
('song-ci-372','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','恰则春来春又去。',52,'宋词/ci.song.10000.json','["恰则春来春又去。", "凭谁说与春教住。", "与问坐中人。", "几回迎送春。", "明年春更好。", "只怕人先老。", "春去有来时。", "愿春长见伊。"]'),
('song-ci-373','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','东风约略吹罗幕。',52,'宋词/ci.song.10000.json','["东风约略吹罗幕。", "一檐细雨春阴薄。", "试把杏花看。", "湿红娇暮寒。", "佳人双玉枕。", "烘醉鸳鸯锦。", "折得最繁枝。", "暖香生翠帏。"]'),
('song-ci-374','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','琢成红玉纤纤指。',52,'宋词/ci.song.10000.json','["琢成红玉纤纤指。", "十三弦上调新水。", "一弄入云声。", "月明天更青。", "匆匆莺语啭。", "待寓昭君怨。", "寄语莫重弹。", "有人愁倚栏。"]'),
('song-ci-375','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','玉龙细点三更月。',52,'宋词/ci.song.10000.json','["玉龙细点三更月。", "庭花影下馀残雪。", "寒色到书帏。", "有人清梦迷。", "墙西歌吹好。", "烛暖香闺小。", "多病怯杯觞。", "不禁冬夜长。"]'),
('song-ci-376','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','江山佳处留行客。',52,'宋词/ci.song.10000.json','["江山佳处留行客。", "醉馀老眼迷空碧。", "独倚最高楼。", "乾坤日夜浮。", "微风吹笑语。", "白日鱼龙舞。", "此意忽翩翩。", "凭虚吾欲仙。"]'),
('song-ci-377','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','雪消墙角收灯后。',52,'宋词/ci.song.10000.json','["雪消墙角收灯后。", "野梅官柳春全透。", "池阁又东风。", "烛花烧夜红。", "一尊留好客。", "敧尽阑干月。", "已醉不须归。", "试听乌夜啼。"]'),
('song-ci-378','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','溶溶花月天如水。',52,'宋词/ci.song.10000.json','["溶溶花月天如水。", "阑干小倚东风里。", "夜久寂无人。", "露浓花气清。", "悠然心独喜。", "此意如何意。", "不似隐墙东。", "烛花围坐红。"]'),
('song-ci-379','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','暗潮清涨蒲塘晚。',52,'宋词/ci.song.10000.json','["暗潮清涨蒲塘晚。", "断云不隔东归眼。", "堂上晚风凉。", "藕花开处香。", "夜航人不渡。", "白鹭双飞去。", "待得月华生。", "携筇独自行。"]'),
('song-ci-380','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','缥缈飞来双彩凤。',52,'宋词/ci.song.10000.json','["缥缈飞来双彩凤。", "雨疏云淡撩清梦。", "兰薄未禁秋。", "月华如水流。", "采香溪上路。", "愁满参差树。", "独倚晚楼风。", "断霞萦素空。"]'),
('song-ci-381','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','蘼芜白芷愁烟渚。',52,'宋词/ci.song.10000.json','["蘼芜白芷愁烟渚。", "曲琼细卷江南雨。", "心事怯衣单。", "楼高生晚寒。", "云鬓香雾湿。", "翠袖凄馀泣。", "春去有来时，春从沙际归。"]'),
('song-ci-382','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','十年长作江头客。',52,'宋词/ci.song.10000.json','["十年长作江头客。", "樯竿又挂西风席。", "白鸟去边明。", "楚山无数青。", "倒冠仍落佩。", "我醉君须醉。", "试问识君不。", "青山与白鸥。"]'),
('song-ci-383','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','乳羝属国归来早。',52,'宋词/ci.song.10000.json','["乳羝属国归来早。", "知君胆大身犹小。", "一节不须论。", "功名看致君。", "镇西楼上酒。", "父老为公寿。", "更祝太夫人。", "年年封诏新。"]'),
('song-ci-384','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','胭脂浅染双珠树。',52,'宋词/ci.song.10000.json','["胭脂浅染双珠树。", "东风到处娇无数。", "不语恨厌厌。", "何人思故园。", "故园花烂熳。", "笑我归来晚。", "我老只思归。", "故园花雨时。"]'),
('song-ci-385','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','吴波细卷东风急。',52,'宋词/ci.song.10000.json','["吴波细卷东风急。", "斜阳半落苍烟湿。", "一棹采菱歌。", "倚栏人奈何。", "天公怜好客。", "酒面风吹白。", "更引十玻璃。", "月明骑鹤归。"]'),
('song-ci-386','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','冥濛秋夕溥清露。',52,'宋词/ci.song.10000.json','["冥濛秋夕溥清露。", "玉绳耿耿银潢注。", "永夜滴铜壶。", "月华楼影孤。", "佳人纡绝唱。", "翠幕丛宵上。", "休劝玉东西。", "乌鸦枝上啼。"]'),
('song-ci-387','西江月','张孝祥','宋','宋词','song-ci','西江月','[]','问讯湖边春色，重来又是三年。',58,'宋词/ci.song.10000.json','["问讯湖边春色，重来又是三年。", "东风吹我过湖船。", "杨柳丝丝拂面。", "世路如今已惯，此心到处悠然。", "寒光庭下水如天。", "飞起沙鸥一片。"]'),
('song-ci-388','西江月','张孝祥','宋','宋词','song-ci','西江月','[]','风定滩声未已，雨来篷底先知。',58,'宋词/ci.song.10000.json','["风定滩声未已，雨来篷底先知。", "岸边杨柳最怜伊。", "忆得船儿曾系。", "湖雾平吞白塔，茅檐自有青旗。", "三杯村酒醉如泥。", "天色寒呵且睡。"]'),
('song-ci-389','西江月','张孝祥','宋','宋词','song-ci','西江月','[]','冉冉寒生碧树，盈盈露湿黄花。',58,'宋词/ci.song.10000.json','["冉冉寒生碧树，盈盈露湿黄花。", "故人玉节有光华。", "高会仍逢戏马。", "万事只今如梦，此身到处为家。", "与君相逢更天涯。", "拼了茱萸醉把。"]'),
('song-ci-390','西江月','张孝祥','宋','宋词','song-ci','西江月','[]','诸老何烦荐口，先生自简渊衷。',58,'宋词/ci.song.10000.json','["诸老何烦荐口，先生自简渊衷。", "千年圣学有深功。", "妙处无非日用。", "已授一编圯下，却须三顾隆中。", "鸿钧早晚转春风。", "我亦从君贾勇。"]'),
('song-ci-391','西江月','张孝祥','宋','宋词','song-ci','西江月','[]','慈母行封大国，老仙早上蓬山。',58,'宋词/ci.song.10000.json','["慈母行封大国，老仙早上蓬山。", "天怜阴德遍人间。", "赐与还丹七返。", "莫问清都紫府，长教绿鬓朱颜。", "年年今日采衣斑。", "兄弟同扶酒盏。"]'),
('song-ci-392','西江月','张孝祥','宋','宋词','song-ci','西江月','["\u897f\u6e56"]','不识平源太守，向来水北山人。',58,'宋词/ci.song.10000.json','["不识平源太守，向来水北山人。", "世间功业谩亏成。", "华发萧萧满镜。", "幸有田园故里，聊分风月江城。", "西湖西畔晚波平。", "袖手时来照影。"]'),
('song-ci-393','西江月','张孝祥','宋','宋词','song-ci','西江月','[]','楼外疏星印水，楼头画烛烘帘。',58,'宋词/ci.song.10000.json','["楼外疏星印水，楼头画烛烘帘。", "凭高举酒恨厌厌。", "征路虚无指点。", "酒兴因君开阔，山容向我增添。", "一钩新月弄纤纤。", "浓雾花房办敛。"]'),
('song-ci-394','西江月','张孝祥','宋','宋词','song-ci','西江月','["\u5cb3\u9633\u697c"]','满载一船秋色，平铺十里湖光。',60,'宋词/ci.song.10000.json','["满载一船秋色，平铺十里湖光。", "波神留我看斜阳。", "放起鳞鳞细浪。", "明日风回更好，今宵露宿何妨。", "水晶宫里奏《霓裳》。", "准拟岳阳楼上。"]'),
('song-ci-395','西江月','张孝祥','宋','宋词','song-ci','西江月','[]','窗户青红尚湿，主人已作归期。',58,'宋词/ci.song.10000.json','["窗户青红尚湿，主人已作归期。", "坐中宾客尽邹枚。", "盛事它年应记。", "别酒深深但劝，离歌缓缓休催。", "扁舟明日转清溪。", "好月相望千里。"]'),
('song-ci-396','西江月','张孝祥','宋','宋词','song-ci','西江月','[]','汗铸九金神鼎，隋书小字莲经。',58,'宋词/ci.song.10000.json','["汗铸九金神鼎，隋书小字莲经。", "刚风劫火转清冥。", "护守应烦仙圣。", "昨梦归来帝所，今朝寿我亲庭。", "只将此宝伴长生。", "谈笑中原底定。"]'),
('song-ci-397','西江月','张孝祥','宋','宋词','song-ci','西江月','[]','落日熔金万顷，晴岚洗剑双锋。',58,'宋词/ci.song.10000.json','["落日熔金万顷，晴岚洗剑双锋。", "紫枢元是黑头公。", "佳处因君愈重。", "分得湖光一曲，唤回庐岳千峰。", "清尊今夜偶然同。", "早晚商岩有梦。"]'),
('song-ci-398','西江月','张孝祥','宋','宋词','song-ci','西江月','[]','畴昔通家事契，只今两镇交承。',58,'宋词/ci.song.10000.json','["畴昔通家事契，只今两镇交承。", "起居枢密太夫人。", "绿鬓斑衣相映。", "乞得神仙九酝，祝教福禄千春。", "台星直上寿星明。", "长见门阑鼎盛。"]'),
('song-ci-399','减字木兰花','张孝祥','宋','宋词','song-ci','减字木兰花','[]','佳人绝妙。',52,'宋词/ci.song.10000.json','["佳人绝妙。", "不惜千金频买笑。", "燕姹莺娇。", "始遣清歌透碧宵。", "主人好事。", "更倒一尊留客醉。", "我醉思家。", "月满南池欲漾花。"]'),
('song-ci-400','减字木兰花','张孝祥','宋','宋词','song-ci','减字木兰花','[]','一尊留夜。',52,'宋词/ci.song.10000.json','["一尊留夜。", "宾蜡烘帘光激射。", "冻合铜壶。", "细听冰檐夜剪酥。", "清愁冉冉。", "酒唤红潮登玉脸。", "明日重看。", "玉界琼楼特地寒。"]'),
('song-ci-401','减字木兰花','张孝祥','宋','宋词','song-ci','减字木兰花','[]','爱而不见。',52,'宋词/ci.song.10000.json','["爱而不见。", "立马章台空便面。", "想像娉婷。", "只恐丹青画不成。", "诗人老去。", "恰要莺莺相伴住。", "试与平章。", "岁晚教人枉断肠。"]'),
('song-ci-402','减字木兰花','张孝祥','宋','宋词','song-ci','减字木兰花','[]','阿谁曾见。',52,'宋词/ci.song.10000.json','["阿谁曾见。", "马上墙阴通半面。", "玉立娉婷。", "一点灵犀寄目成。", "明朝重去。", "人在横溪溪畔住。", "乔木千章。", "摇落霜风只断肠。"]'),
('song-ci-403','减字木兰花','张孝祥','宋','宋词','song-ci','减字木兰花','[]','江头送客。',52,'宋词/ci.song.10000.json','["江头送客。", "枫叶荻花秋索索。", "弦索休弹。", "清泪无多怕湿衫。", "故人相遇。", "不醉如何归得去。", "我醉望归。", "烟满空江月满堤。"]'),
('song-ci-404','减字木兰花','张孝祥','宋','宋词','song-ci','减字木兰花','[]','春如有意。',52,'宋词/ci.song.10000.json','["春如有意。", "未接年华春已至。", "春事还新。", "多得年时五日春。", "春郊便绿。", "只向腊前春已足。", "屈指元宵。", "正是新春二十朝。"]'),
('song-ci-405','减字木兰花','张孝祥','宋','宋词','song-ci','减字木兰花','[]','慈闱生日。',52,'宋词/ci.song.10000.json','["慈闱生日。", "见说今年年九十。", "戏彩盈门。", "大底孩儿七个孙。", "人间喜事。", "只这一般难得似。", "愿我双亲。", "都似君家太淑人。"]'),
('song-ci-406','减字木兰花','张孝祥','宋','宋词','song-ci','减字木兰花','[]','吹箫泛月。',52,'宋词/ci.song.10000.json','["吹箫泛月。", "往事悠悠休更说。", "拍碎琉璃。", "始觉从前万事非。", "清齐净戒。", "休作断肠垂泪债。", "识破嚣尘。", "作个逍遥物外人。"]'),
('song-ci-407','减字木兰花','张孝祥','宋','宋词','song-ci','减字木兰花','[]','人间奇绝。',52,'宋词/ci.song.10000.json','["人间奇绝。", "只有梅花枝上雪。", "有个人人。", "梅样风标雪样新。", "芳心不展。", "嫩绿阴阴愁冉冉。", "一笑相看。", "试荐冰磐一点酸。"]'),
('song-ci-408','减字木兰花','张孝祥','宋','宋词','song-ci','减字木兰花','[]','枷花搦柳。',52,'宋词/ci.song.10000.json','["枷花搦柳。", "知道东君留意久。", "惨绿愁红。", "憔悴都因一夜风。", "轻狂蝴蝶。", "拟欲扶持心又怯。", "要免离披。", "不告东君更告谁。"]'),
('song-ci-409','清平乐','张孝祥','宋','宋词','song-ci','清平乐','[]','光尘扑扑。',54,'宋词/ci.song.10000.json','["光尘扑扑。", "宫柳低迷绿。", "斗鸭阑干春诘曲。", "帘额微风绣蹙。", "碧云轻翼无凭。", "困来小倚银屏。", "楚梦未禁春晚，黄鹂犹自声声。"]'),
('song-ci-410','清平乐','张孝祥','宋','宋词','song-ci','清平乐','[]','油幢画戟。',53,'宋词/ci.song.10000.json','["油幢画戟。", "玉铉调春色。", "勋阀诸郎俱第一。", "风流前辈敌。", "玉人双鞚华□。", "翠云深处消摇。", "有客留君东阁，时闻风下笙箫。"]'),
('song-ci-411','清平乐','张孝祥','宋','宋词','song-ci','清平乐','[]','吹香嚼蕊。',54,'宋词/ci.song.10000.json','["吹香嚼蕊。", "独立东风里。", "玉冻云娇天似水。", "羞杀夭桃秾李。", "如今见说阑干。", "不禁月冷霜寒。", "垅上驿程人远，楼头戍角声乾。"]'),
('song-ci-412','清平乐','张孝祥','宋','宋词','song-ci','清平乐','[]','英姿慷慨。',54,'宋词/ci.song.10000.json','["英姿慷慨。", "独立风尘外。", "湖海平生豪气在。", "行矣云龙际会。", "充庭兰玉森森。", "一觞共祝修铃。", "此地去天尺五，明年持櫜西清。"]'),
('song-ci-413','清平乐','张孝祥','宋','宋词','song-ci','清平乐','[]','向来省户。',54,'宋词/ci.song.10000.json','["向来省户。", "谋国参伊吕。", "暂借良筹非再举。", "谈笑肃清三楚。", "良辰上客徜佯。", "奏篇犹记传香。", "此日一尊相属，它时同在岩廊。"]'),
('song-ci-414','点绛唇','张孝祥','宋','宋词','song-ci','点绛唇','[]','四到蕲州，今年更是逢重九。',50,'宋词/ci.song.10000.json','["四到蕲州，今年更是逢重九。", "应时纳祐。", "随分开尊酒。", "屡舞婆娑，醉我平生友。", "休回首。", "世间何有。", "明月疏疏柳。"]'),
('song-ci-415','点绛唇','张孝祥','宋','宋词','song-ci','点绛唇','[]','绮燕高张，玉潭月丽玻璃满。',50,'宋词/ci.song.10000.json','["绮燕高张，玉潭月丽玻璃满。", "旆霞行卷。", "无复长安远。", "夏木阴阴，路袅薰风转。", "空留恋。", "细吹银管。", "别意随声缓。"]'),
('song-ci-416','点绛唇','张孝祥','宋','宋词','song-ci','点绛唇','[]','萱草榴花，画堂永昼风清暑。',50,'宋词/ci.song.10000.json','["萱草榴花，画堂永昼风清暑。", "麝团菰黍。", "助泛菖蒲醑。", "兵辟神符，命续同心缕。", "宜欢聚。", "绮筵歌舞。", "岁岁酬端午。"]'),
('song-ci-417','卜算子','张孝祥','宋','宋词','song-ci','卜算子','[]','雪月最相宜，梅雪都清绝。',52,'宋词/ci.song.10000.json','["雪月最相宜，梅雪都清绝。", "去岁江南见雪时，月底梅花发。", "今岁早梅开，依旧年时月。", "冷艳孤光照眼明，只欠些儿雪。"]'),
('song-ci-418','诉衷情','张孝祥','宋','宋词','song-ci','诉衷情','[]','晚烟斜日思悠悠。',54,'宋词/ci.song.10000.json','["晚烟斜日思悠悠。", "西北有高楼。", "十分准拟明月，还似去年游。", "飞玉斝，卷琼钩。", "唤新愁。", "姮娥贪共，暮雨朝云，忘了中秋。"]'),
('song-ci-419','诉衷情','张孝祥','宋','宋词','song-ci','诉衷情','[]','乱红深紫过群芳。',54,'宋词/ci.song.10000.json','["乱红深紫过群芳。", "初欲灭春光。", "花王自有标格，尘外锁韶阳。", "留国艳，问仙乡。", "自天香。", "翠帏遮日，红烛通宵，与醉千场。"]'),
('song-ci-420','好事近','张孝祥','宋','宋词','song-ci','好事近','[]','一朵木犀花，珍重玉纤新摘。',53,'宋词/ci.song.10000.json','["一朵木犀花，珍重玉纤新摘。", "插向远山深处，占十分秋色。", "满园桃李闹春风，漫红红白白。", "争似淡妆娇面，伴蓬莱仙客。"]'),
('song-ci-421','好事近','张孝祥','宋','宋词','song-ci','好事近','[]','万瓦雪花浮，应是化工融结。',53,'宋词/ci.song.10000.json','["万瓦雪花浮，应是化工融结。", "仍看牡丹初绽，有层层千叶。", "镂冰剪水更鲜明，说道真奇绝。", "来报主人佳兆，庆我公还阕。"]'),
('song-ci-422','南歌子','张孝祥','宋','宋词','song-ci','南歌子','[]','曾到蕲州不，人人说使君。',62,'宋词/ci.song.10000.json','["曾到蕲州不，人人说使君。", "使君才具合经纶。", "小试边城、早晚上星辰。", "佳节重阳近，清歌午夜新。", "举杯相属莫辞频。", "后日相思、我已是行人。"]'),
('song-ci-423','水调歌头','李处全','宋','宋词','song-ci','水调歌头','[]','明月浸瑶碧，河汉水交流。',114,'宋词/ci.song.10000.json','["明月浸瑶碧，河汉水交流。", "偏来照我，知我白发不胜愁。", "客里山中三载，枕上人间一梦，曾忆到瀛洲。", "矫首蓬壶路，两腋已飕飕。", "记扁舟，浮震泽，趁中秋。", "垂虹亭上，与客千里快凝眸。", "看剑引杯狂醉，饮水曲肱高卧，鹏鷃已同游。", "起舞三人耳，横笛唤沙鸥。"]'),
('song-ci-424','水调歌头','李处全','宋','宋词','song-ci','水调歌头','[]','落日暝云合，客子意如何。',114,'宋词/ci.song.10000.json','["落日暝云合，客子意如何。", "定知今日，封六巽二弄干戈。", "四望际天空阔，一叶凌涛掀舞，壮志未消磨。", "为向吴儿道，听我扣舷歌。", "我常欲，利剑戟，斩蛟鼍。", "胡尘未扫，指挥壮士挽天河。", "谁料半生忧患，成就如今老态，白发逐年多。", "对此貌无恐，心亦畏风波。"]'),
('song-ci-425','水调歌头','李处全','宋','宋词','song-ci','水调歌头','[]','春事已如许，柳眼早依依。',114,'宋词/ci.song.10000.json','["春事已如许，柳眼早依依。", "故园桃李何似，芳蕊想团枝。", "此地嵩高名里，信美元非吾土。", "清梦绕瀍洢。", "扶杖欲行乐，还使我心悲。", "对琴书，歌一阕，引千卮。", "昔曾击楫，今日投老叹吾衰。", "睡起推窗凝睇，失喜柔桑微绿，便拟作春衣。", "搔首长吟处，此意有谁知。"]'),
('song-ci-426','水调歌头','李处全','宋','宋词','song-ci','水调歌头','[]','微雨眼明处，春信著南枝。',114,'宋词/ci.song.10000.json','["微雨眼明处，春信著南枝。", "百花头上消息，为我赴襟期。", "松下凌霜古干，竹外横窗疏影，同是翠寒姿。", "唤取我曹赏，莫使俗流知。", "对风前，看雪后，总相宜。", "碧天如洗，何许羌笛月边吹。", "一段出群标格，合得水仙兄事，千古豫章诗。", "鼎鼐付佳实，终待梦秋时。"]'),
('song-ci-427','水调歌头','李处全','宋','宋词','song-ci','水调歌头','["\u897f\u6e56"]','飞雪已传信，端叶未分枝。',114,'宋词/ci.song.10000.json','["飞雪已传信，端叶未分枝。", "莫嫌开晚，前月曾付小春期。", "谁道梳风洗雨，不许调脂弄粉，容易涴天姿。", "眼界未多见，鼻观已先知。", "昔西湖，今北客，各从宜。", "要渠烂熳，趣得暖律为渠吹。", "犹记石亭攀折，浑似扬州观赏，清兴欲寻诗。", "三嗅不离手，如得和篇时。"]'),
('song-ci-428','水调歌头','李处全','宋','宋词','song-ci','水调歌头','[]','今夕定何夕，今夕岁还除。',114,'宋词/ci.song.10000.json','["今夕定何夕，今夕岁还除。", "团栾儿女，尽情灯火照围炉。", "但惜年从节换，便觉身随日老，踪迹尚沈浮。", "万事古如此，聊作旧桃符。", "任东风，吹缟鬓，戏臞儒。", "韶颜壮齿，背人去似隙中驹。", "杯酌犹倾腊酒，漏箭已传春夜，何处不歌呼。", "惟愿长穷健，命酹且欢娱。"]'),
('song-ci-429','水调歌头','李处全','宋','宋词','song-ci','水调歌头','[]','楼观数南国，烟雨压东州。',114,'宋词/ci.song.10000.json','["楼观数南国，烟雨压东州。", "溪山雄胜，天开图画肖瀛洲。", "我破瀛洲客梦，来剖仙洲符竹，乐岁又云秋。", "聊作幻师戏，肯遗后人愁。", "趁佳时，招我辈，共凝眸。", "君侯胸次邱壑，意匠付冥搜。", "刻日落成华栋，对月难并清景，千丈素光流。", "老子兴何极，小子趣觥筹。"]'),
('song-ci-430','满江红','李处全','宋','宋词','song-ci','满江红','[]','清晓高堂，春晚处、旧红新绿。',115,'宋词/ci.song.10000.json','["清晓高堂，春晚处、旧红新绿。", "耸曩昔、蟠桃初种，更并潭菊。", "强健老人松下鹤，森荣孙子霜中竹。", "看共持、寿斝祝期颐，倾醽醁。", "烘晴昼，炉烟馥。", "连永夜，笙歌簇。", "喜一时欢意，何人兼足。", "早愿诸甥成宅相，便从明岁开汤沐。", "向年年、今日度新腔，调仙曲。"]'),
('song-ci-431','临江仙','李处全','宋','宋词','song-ci','临江仙','[]','畴昔方壶游戏地，群仙步履相从。',70,'宋词/ci.song.10000.json','["畴昔方壶游戏地，群仙步履相从。", "明黄衫子御西风。", "佩环金错落，羽葆翠璁珑。", "骑鹄翩然归去路，吹箫横度青峰。", "夜深河汉冷秋容。", "前驱香十里，飘坠月轮东。"]'),
('song-ci-432','念奴娇','李处全','宋','宋词','song-ci','念奴娇','[]','一天春意，趁东皇幽赏，重飞端叶。',120,'宋词/ci.song.10000.json','["一天春意，趁东皇幽赏，重飞端叶。", "造物有心成伟观，来伴红蕖开彻。", "桂魄初圆，梅腮全放，节物俱奇绝。", "冷官门巷，望中北固楼堞。", "遐想蓬底高人，拥衾无寐，九曲长增结。", "我亦低窗翻蠹纸，失喜瑶花盈尺。", "拥鼻孤吟，搔头危坐，所欠惟佳客。", "须君来此，脸纹相对生缬。"]'),
('song-ci-433','满庭芳','李处全','宋','宋词','song-ci','满庭芳','[]','乳燕将雏，啼莺求友，江南梅子黄时。',118,'宋词/ci.song.10000.json','["乳燕将雏，啼莺求友，江南梅子黄时。", "欲晴还雨，烟外看成丝。", "迎袂风来梦陇，吹饼饵、香入书帷。", "行吟处，溪翁说我，不似去年衰。", "方池。", "荷出水，朱榴倚槛，粉箨穿篱。", "有吾曹我辈，把酒寻诗。", "醉去黑甜一枕，炉烟袅、花影斜晖。", "家山乐，南窗寄傲，唯有晦庵知。"]'),
('song-ci-434','鹧鸪天','李处全','宋','宋词','song-ci','鹧鸪天','[]','烟雨溟溟趁落成。',64,'宋词/ci.song.10000.json','["烟雨溟溟趁落成。", "只应天欲称佳名。", "万丝明灭青山映，匹素浓纤渌水萦。", "民亦乐，美能并。", "酒杯莫惜十分倾。", "要知社下平生志，觞政聊须为主盟。"]'),
('song-ci-435','鹧鸪天','李处全','宋','宋词','song-ci','鹧鸪天','[]','缥缈危楼百尺雄。',64,'宋词/ci.song.10000.json','["缥缈危楼百尺雄。", "淡烟疏雨暗帘栊。", "偶妨清赏中秋夕，为忆名言玉局翁。", "贤达意，古今同。", "凉天佳月会相逢。", "老蟾一跃三千丈，却唤姮娥驾阆风。"]'),
('song-ci-436','柳梢青','李处全','宋','宋词','song-ci','柳梢青','[]','九天圆月。',61,'宋词/ci.song.10000.json','["九天圆月。", "香尘碎玉，素涛翻雪。", "石乳香甘，松风汤嫩，一时三绝。", "清宵好尽欢娱，奈明日、扶头怎说。", "整顿颓山，殷勤春露，馀甘齿颊。"]'),
('song-ci-437','柳梢青','李处全','宋','宋词','song-ci','柳梢青','[]','馀甘齿颊。',61,'宋词/ci.song.10000.json','["馀甘齿颊。", "酒□半酣，漏声频促。", "月下传呼，风前掺别，无因留客。", "丁宁玉笋磨香，为料理、十分醒著。", "后会何时，前欢未尽，明朝重约。"]'),
('song-ci-438','朝中措','李处全','宋','宋词','song-ci','朝中措','[]','晦庵四至似天宽。',57,'宋词/ci.song.10000.json','["晦庵四至似天宽。", "生计有心田。", "闲弄炉薰茗碗，困寻纸帐蒲团。", "商山橘隐，须弥芥纳，容与湖天。", "谁笑先生贫窭，东篱无数金钱。"]'),
('song-ci-439','朝中措','李处全','宋','宋词','song-ci','朝中措','[]','薰风庭院燕双飞。',57,'宋词/ci.song.10000.json','["薰风庭院燕双飞。", "园柳啭黄鹂。", "是处蜂狂蝶乱，元来绿暗红稀。", "衫笼白苎，琴推绿绮，满眼新诗。", "好个江南风景，杜鹃犹自催归。"]'),
('song-ci-440','菩萨蛮','李处全','宋','宋词','song-ci','菩萨蛮','[]','杜鹃只管催归去。',52,'宋词/ci.song.10000.json','["杜鹃只管催归去。", "知渠教我归何处。", "故国泪生痕。", "那堪枕上闻。", "严装吾已具。", "泛宅吴中路。", "弭棹唤东邻。", "江东日暮云。"]'),
('song-ci-441','菩萨蛮','李处全','宋','宋词','song-ci','菩萨蛮','["\u897f\u6e56"]','晦庵老子修行久。',52,'宋词/ci.song.10000.json','["晦庵老子修行久。", "问禅金粟曾回首。", "截竹是禅机。", "吹破粟玉枝。", "西湖秋好处。", "承得昭阳露。", "香透月轮低。", "来薰打坐时。"]'),
('song-ci-442','菩萨蛮','李处全','宋','宋词','song-ci','菩萨蛮','[]','四时皆有司花女。',52,'宋词/ci.song.10000.json','["四时皆有司花女。", "杪秋犹见花如许。", "想得紫金丹。", "工夫造化间。", "春莺留弱羽。", "更渍蔷薇露。", "莫取落英餐。", "留供醉眼看。"]'),
('song-ci-443','浣溪沙','李处全','宋','宋词','song-ci','浣溪沙','[]','宋玉应当久断肠。',48,'宋词/ci.song.10000.json','["宋玉应当久断肠。", "满城风雨尽重阳。", "年年戏马忆吾乡。", "催促东篱金蕊放，佳人更绣紫萸囊。", "白衣才到共飞觞。"]'),
('song-ci-444','西江月','李处全','宋','宋词','song-ci','西江月','[]','窗户风薰端午，楼台月满中秋。',58,'宋词/ci.song.10000.json','["窗户风薰端午，楼台月满中秋。", "阴晴寒暑总无忧。", "几事不如重九。", "落帽何羞种种，看山都付悠悠。", "黄花已作醉乡游。", "梦觉黄花在手。"]'),
('song-ci-445','西江月','李处全','宋','宋词','song-ci','西江月','[]','婥婥妆楼红袖，亭亭将阃青油。',58,'宋词/ci.song.10000.json','["婥婥妆楼红袖，亭亭将阃青油。", "东皇天巧世无俦。", "定有司花妙手。", "十里香风晓霁，千家绮陌春游。", "竹西路转古扬州。", "歌吹只应如旧。"]'),
('song-ci-446','西江月','李处全','宋','宋词','song-ci','西江月','[]','南国一分春色，东窗八面光风。',58,'宋词/ci.song.10000.json','["南国一分春色，东窗八面光风。", "女兄欢笑酒尊同。", "满眼儿孙群从。", "但愿年逾百岁，何妨时醉千锺。", "朱颜绿发照青铜。", "要看如龙如凤。"]'),
('song-ci-447','生查子','李处全','宋','宋词','song-ci','生查子','[]','庭户小光中，帘幕秋光里。',48,'宋词/ci.song.10000.json','["庭户小光中，帘幕秋光里。", "曲沼绮疏横，几处新妆洗。", "红脸露轻匀，翠袖风频倚。", "鸾鉴不须开，自有窗前水。"]'),
('song-ci-448','生查子','李处全','宋','宋词','song-ci','生查子','[]','温柔属东西，和冷经三五。',48,'宋词/ci.song.10000.json','["温柔属东西，和冷经三五。", "几夜德星明，果应荀陈聚。", "分虎屈雄姿，展骥淹遐步。", "除诏已涂芝，便看朝天去。"]'),
('song-ci-449','减字木兰花','李处全','宋','宋词','song-ci','减字木兰花','[]','今年菊早。',52,'宋词/ci.song.10000.json','["今年菊早。", "想到重阳花正好。", "玉冷金寒。", "全似东篱挹露看。", "色庄香重。", "直与梅花堪伯仲。", "待唤渊明。", "三友相从盖为倾。"]'),
('song-ci-450','减字木兰花','李处全','宋','宋词','song-ci','减字木兰花','[]','谁将翡翠。',52,'宋词/ci.song.10000.json','["谁将翡翠。", "闲屑黄金摅巧思。", "缀就花钿。", "飞上秋云入鬓蝉。", "一枝斜倚。", "披拂香风多少意。", "午镜重匀。", "娇额妆成宫样新。"]'),
('song-ci-451','减字木兰花','李处全','宋','宋词','song-ci','减字木兰花','[]','更生观尽。',52,'宋词/ci.song.10000.json','["更生观尽。", "双璧蒹葭那敢并。", "四海无人。", "笑语从容许我亲。", "平生此客。", "复与太丘登醉白。", "病里颦眉。", "贪看惺惺骑马归。"]'),
('song-ci-452','相见欢','李处全','宋','宋词','song-ci','相见欢','[]','新凉襟袂冷然。',45,'宋词/ci.song.10000.json','["新凉襟袂冷然。", "乍晴天。", "风送谁家羌管、月便娟。", "云散尽，秋空碧，玉钩悬。", "洗耳时听三弄、等团圆。"]'),
('song-ci-453','江城子','李处全','宋','宋词','song-ci','江城子','[]','一番风雨一番凉。',86,'宋词/ci.song.10000.json','["一番风雨一番凉。", "炯秋光。", "又重阳。", "潇洒东篱，浑学汉宫妆。", "今日且须开口笑，花露袅，鬓云香。", "泼醅新取淡鹅黄。", "趁幽芳。", "趣飞觞。", "落帽当时，□发少年狂。", "万事破除惟有此，尘外客，醉中乡。"]'),
('song-ci-454','阮郎归','李处全','宋','宋词','song-ci','阮郎归','[]','佳人偏爱菊花天。',56,'宋词/ci.song.10000.json','["佳人偏爱菊花天。", "玉钗金附蝉。", "歌声缥缈紫云边。", "博山沈水烟。", "须斗酒，泛觥船。", "乃翁能百篇。", "高堂此会看年年。", "夜深人醉眠。"]'),
('song-ci-455','忆秦娥','李处全','宋','宋词','song-ci','忆秦娥','[]','春山寂。',56,'宋词/ci.song.10000.json','["春山寂。", "佳人凝笑山南陌。", "山南陌。", "东风寒浅，绛罗衫窄。", "阑干倚处云如幂。", "晚来雨过胭脂滴。", "胭脂滴。", "啼妆难劝，且须欢伯。"]'),
('song-ci-456','忆秦娥','李处全','宋','宋词','song-ci','忆秦娥','[]','莺花寂。',56,'宋词/ci.song.10000.json','["莺花寂。", "为渠游冶长安陌。", "长安陌。", "今朝风景，酒肠宽窄。", "锦茵闲把薰笼幂。", "嫩红倚绿娇如滴。", "娇如滴。", "古今高咏，老泉仙伯。"]'),
('song-ci-457','好事近','李处全','宋','宋词','song-ci','好事近','[]','香雪弄春妍，柳外黄昏池阁。',53,'宋词/ci.song.10000.json','["香雪弄春妍，柳外黄昏池阁。", "要看月华相映，卷东风帘幕。", "更倾壶酒伴芳姿，名字胜桑落。", "直与岭梅兄弟，是醍醐酥酪。"]'),
('song-ci-458','蓦山溪','李处全','宋','宋词','song-ci','蓦山溪','[]','梨花过雨，已是春强半。',102,'宋词/ci.song.10000.json','["梨花过雨，已是春强半。", "花恼欲颠狂，兴浑在、秋千架畔。", "搔头无语，斜日上帘栊，飞上下，语呢喃，又见双双燕。", "鱼吹细浪，镜面摇歌扇。", "籍草倒芳尊，亲香茵、落红千片。", "追奔蜗角，回首醉初醒，逢节物，且欢娱，莫待流年换。"]'),
('song-ci-459','卜算子','李处全','宋','宋词','song-ci','卜算子','[]','春事忆松江，江上花无数。',52,'宋词/ci.song.10000.json','["春事忆松江，江上花无数。", "一枕匆匆醉梦中，芳草臞庵路。", "携手度虹梁，洗眼看渔具。", "盐豆莼羹是处无，早买扁舟去。"]'),
('song-ci-460','卜算子','李处全','宋','宋词','song-ci','卜算子','[]','芍药斗新妆，杨柳飞轻雪。',52,'宋词/ci.song.10000.json','["芍药斗新妆，杨柳飞轻雪。", "著意留连不放春，已向东皇说。", "况是谪仙家，自有长生诀。", "方士呼来借玉蟾，要吸杯中月。"]'),
('song-ci-461','诉衷情','李处全','宋','宋词','song-ci','诉衷情','[]','疏烟明淡雨膏如。',54,'宋词/ci.song.10000.json','["疏烟明淡雨膏如。", "青入烧痕初。", "开到无言桃李，春事喜敷腴。", "随杖履，有琴书。", "酒盈壶。", "风前花下，睡起醒时，著我篮舆。"]'),
('song-ci-462','醉蓬莱','李处全','宋','宋词','song-ci','醉蓬莱','[]','政馀春眷眷，首夏骎骎，清和时候。',120,'宋词/ci.song.10000.json','["政馀春眷眷，首夏骎骎，清和时候。", "晓色曈昽，瑞霭凝轩牖。", "著子青梅，袅枝红药，物物俱情厚。", "绿倚朱弦，檀槽铁拨，华堂称寿。", "季父高怀，庆锺吾姊，富贵长年，自应兼有。", "更看诸郎，谢砌芝兰秀。", "蚤晚成名，雁行亲膝，无忌胜如舅。", "沆瀣朝霞，蓬莱弱水，酿为春酒。"]'),
('song-ci-463','贺新郎','李处全','宋','宋词','song-ci','贺新郎','[]','秋意生何许。',142,'宋词/ci.song.10000.json','["秋意生何许。", "对玉钩、微云避舍，素风吹暑。", "银汉桥成天路稳，乾鹊声声媚妩。", "送仙杖、年年须度。", "离合悲欢多少话，想今宵、缱绻难深诉。", "千古恨，无新故。", "聊须作意成欢绪。", "为佳时、金针戏把，翠觞频举。", "莫念匆匆轻掺袂，天上元无间阻。", "况好是、新凉庭户。", "倦客天涯磋老大，趁珠帘、绣额高楼处。", "乞些巧，调儿女。"]'),
('song-ci-464','贺新郎','李处全','宋','宋词','song-ci','贺新郎','[]','心事知谁许。',142,'宋词/ci.song.10000.json','["心事知谁许。", "政吾曹、摛辞弄翰，邀凉蠲暑。", "节物於人俱可喜，今夕渠偏媚妩。", "笑曝腹、书生风度。", "河鼓天孙非世俗，纵惊云、急雨休轻诉。", "忆倾盖，便如故。", "良辰欢意宽离绪。", "称仙家、瑶台缥缈，霓裳掀举。", "应想尘寰空怅望，月路谁曾隔阻。", "是处有、绮窗朱户。", "我爱五湖烟水阔，待扁舟，寻到搘机处。", "访婺女，共嬃女。"]'),
('song-ci-465','四和香・四犯令','李处全','宋','宋词','song-ci','四和香・四犯令','[]','香雪新苞偏胜韵。',60,'宋词/ci.song.10000.json','["香雪新苞偏胜韵。", "领袖催花信。", "华节良辰人有分。", "看士女、旛垂鬓。", "莫向春风寻旧恨。", "乐事随方寸。", "眉寿故应天不吝。", "浮大白、吾无闷。"]'),
('song-ci-466','玉楼春','李处全','宋','宋词','song-ci','玉楼春','[]','年光箭脱无留计。',64,'宋词/ci.song.10000.json','["年光箭脱无留计。", "才过立春还守岁。", "要知一岁已寻侬，听打个惊人喷嚏。", "椒盘荐寿休辞醉。", "坐听爆竹浑无寐。", "明朝末后饮屠苏，白发从渠相点缀。"]'),
('song-ci-467','南乡子','李处全','宋','宋词','song-ci','南乡子','[]','和气作春妍。',66,'宋词/ci.song.10000.json','["和气作春妍。", "以作寒归塞地天。", "岁月翩翩人老矣，华颠。", "胆冷更长自不眠。", "节物映椒盘。", "柏酒香浮白玉船。", "捧劝大家相祝愿，何言。", "但愿今年胜去年。"]'),
('song-ci-468','苏幕遮','韩仙姑','宋','宋词','song-ci','苏幕遮','[]','不忧贫，不念富。',76,'宋词/ci.song.10000.json','["不忧贫，不念富。", "大悟之人，开著波罗铺。", "内心真知无价宝，欲识真如，正照菩提路。", "贪爱心，须除去。", "清静法身，直是堪凭据。", "忍辱波罗为妙乐，服了一圆，万病都新愈。"]'),
('song-ci-469','朝中措','周颉','宋','宋词','song-ci','朝中措','[]','郧城清胜压湖湘。',57,'宋词/ci.song.10000.json','["郧城清胜压湖湘。", "人物镇相望。", "秀气谁符楚泽，建安诸子文章。", "东风得意，青云路稳，好去腾骧。", "要识登科次第，待看北斗光芒。"]'),
('song-ci-470','朝中措','王彭年','宋','宋词','song-ci','朝中措','[]','人才七泽盛三湘。',57,'宋词/ci.song.10000.json','["人才七泽盛三湘。", "前辈敢追望。", "惭愧史君劝驾，杯前重赐篇章。", "雷风断送，鱼龙变化，云路蜚骧。", "德意如何报称，短歌莫写毫芒。"]'),
('song-ci-471','朝中措','李伯虎','宋','宋词','song-ci','朝中措','[]','史君清德比清湘。',57,'宋词/ci.song.10000.json','["史君清德比清湘。", "妙政古相望。", "闲暇恩波万井，笑谈风月千章。", "殷勤劝驾，几人怀德，刻意胜骧。", "试问匣中长剑，也应增焕光芒。"]'),
('song-ci-472','水调歌头','丘崈','宋','宋词','song-ci','水调歌头','[]','一雁破空碧，秋满荻花洲。',114,'宋词/ci.song.10000.json','["一雁破空碧，秋满荻花洲。", "淮山淡扫，欲颦眉黛唤人愁。", "落日归云天外，目断清江无际，浩荡没轻鸥。", "有恨寄流水，无泪学羁囚。", "望石城，思东府，话西州。", "平芜千里，古来佳处几回秋。", "歌舞当年何在，罗绮一时同尽，梦幻两悠悠。", "杯到莫停手，唯酒可忘忧。"]'),
('song-ci-473','水调歌头','丘崈','宋','宋词','song-ci','水调歌头','[]','人物冠江左，正始有遗音。',114,'宋词/ci.song.10000.json','["人物冠江左，正始有遗音。", "谪仙风味，洒然那受一尘侵。", "倚马文章天与，霏屑谈辞云委，宣室为虚襟。", "小驻外台节，聊屈济时心。", "记长庚，曾入梦，恰而今。", "橙黄橘绿，可人风物是秋深。", "九日明朝佳节，得得天教好景，供与醉时吟。", "从此寿千岁，一岁一登临。"]'),
('song-ci-474','水调歌头','丘崈','宋','宋词','song-ci','水调歌头','[]','小队拥龙节，三度过鲈乡。',113,'宋词/ci.song.10000.json','["小队拥龙节，三度过鲈乡。", "烟波万顷，欸波绉湿斜阳。", "何处渔舟唱晚，最是芦花风断，欸乃一声长。", "矫首望空阔，逸兴坠微茫。", "笑尘缨，何日许，濯沧浪。", "天随甫里，相寻无处一凄凉。", "会把水光山色，收入烟蓑短艇，胜世作清狂。", "举酒属公子，富贵未渠央。"]'),
('song-ci-475','水调歌头','丘崈','宋','宋词','song-ci','水调歌头','[]','一叶下林表，秋色满蘅皋。',114,'宋词/ci.song.10000.json','["一叶下林表，秋色满蘅皋。", "江风吹雨初过，天宇一何高。", "蜡屐径来堂上，倚杖け然长啸，万里看云涛。", "逸兴浩无际，安得驾灵鳌。", "叹吾生，天地里，一秋毫。", "江山如传，古来阅尽几英豪。", "回首只今何在，举目依然风景，此意属吾曹。", "欲去重惆怅，松径冷萧骚。"]'),
('song-ci-476','水调歌头','丘崈','宋','宋词','song-ci','水调歌头','[]','彩舰驾飞鹢，帆影漾江乡。',114,'宋词/ci.song.10000.json','["彩舰驾飞鹢，帆影漾江乡。", "肥梅天气，一声横玉换新阳。", "惊起沙汀鸥鹭，点破暮天寒碧，极目楚天长。", "一抹残霞外，云断水茫茫。", "朔清风，歌白雪，和沧浪。", "枕流亭馆，昔年行处半荒凉。", "我欲骖风游戏，收拾烟波佳景，一一付词章。", "闻说洞天好，何处水中央。"]'),
('song-ci-477','满江红','丘崈','宋','宋词','song-ci','满江红','[]','驻马江头，聊自放、尘劳踪迹。',115,'宋词/ci.song.10000.json','["驻马江头，聊自放、尘劳踪迹。", "身渐老、尊前羞见，异乡风物。", "雪柳垂金旛胜小，钗头又报春消息。", "记去年、持酒觅新词，人疏隔。", "时序好，今犹昔。", "携赏处，空追忆。", "都如梦才觉，悄然难觅。", "且饮不须论许事，从今煞有佳天色。", "但官闲、有酒便嬉游，愁无益。"]'),
('song-ci-478','满江红','丘崈','宋','宋词','song-ci','满江红','[]','玉宇无尘，斜阳外、江楼伫立。',115,'宋词/ci.song.10000.json','["玉宇无尘，斜阳外、江楼伫立。", "人正远、骑鲸南去，笑言难挹。", "冰雪生寒烟瘴冷，海山著处恩波湿。", "问碧门、金阕待君来，何时入。", "犹自有，新篇什。", "应念我，相思急。", "满乌丝挥遍，麝煤香浥。", "尊酒相逢佳□□，十年一梦长川吸。", "想上都、风月未盟寒，追良集。"]'),
('song-ci-479','满江红','丘崈','宋','宋词','song-ci','满江红','[]','十载重游，愧好在、吴中父老。',115,'宋词/ci.song.10000.json','["十载重游，愧好在、吴中父老。", "官事里、空然痴绝，竟何曾了。", "赖有平生知己地，全胜末路依刘表。", "竟此身、还复雁门踦，宁论早。", "篷仙语，开朕兆。", "郇翰洒，增荣耀。", "倚先声风动，了然家晓。", "翘馆每烦尘想□，宾筵更著红妆绕。", "算从前、得此慰初心，於人少。"]'),
('song-ci-480','满江红','丘崈','宋','宋词','song-ci','满江红','[]','冠盖吴中，羡来往、风流二老。',115,'宋词/ci.song.10000.json','["冠盖吴中，羡来往、风流二老。", "谈笑处、清风满座，倡酬不了。", "琪树相鲜崑阆里，玉山高并云烟表。", "叹□时、顿有古来无，功名早。", "膺帝眷，符梦兆。", "为国镇，腾光耀。", "更宁容秀野，醉眠清晓。", "麟组已联方面重，衮衣行接天香绕。", "许畸人、巾履奉英游，荣多少。"]'),
('song-ci-481','满江红','丘崈','宋','宋词','song-ci','满江红','[]','楚甸云收，歌舞地、依然江渚。',115,'宋词/ci.song.10000.json','["楚甸云收，歌舞地、依然江渚。", "嗟往事、豪华无限，梦回何许。", "翠被那知思玉度，绣袿谩说为行雨。", "悄不禁、俯仰一凄凉，成千古。", "吴蜀会，襟喉处。", "据胜势，开天府。", "著诗书元帅，谈笑尊俎。", "步障月明翻鼓吹，华榱雾湿披窗户。", "把胜游、都与旧风光，湔尘土。"]'),
('song-ci-482','满江红','丘崈','宋','宋词','song-ci','满江红','[]','平楚苍然，烟霭外、飞鸿冥灭。',115,'宋词/ci.song.10000.json','["平楚苍然，烟霭外、飞鸿冥灭。", "身老矣、登临感慨，几时当彻。", "痛饮从教吹帽落，悲歌莫击壶边缺。", "算人生、任运复何为，伤情切。", "功名事，休谩说。", "渠有命，谁工拙。", "且随宜斗健，强酬佳节。", "九节从今知几度，试看镜里头如雪。", "向醉中、赢取万缘空，真蝉脱。"]'),
('song-ci-483','洞仙歌','丘崈','宋','宋词','song-ci','洞仙歌','[]','一番好景，近莺花时候。',107,'宋词/ci.song.10000.json','["一番好景，近莺花时候。", "才过收灯便晴昼。", "正熊罴、占梦日，戏彩称觞，当此际，须信人间未有。", "光华分瑞节，粉署兰台，谁出如公望郎右。", "气如虹，才吐凤，指掌功名，馀事也，千载犹当不朽。", "待辟国、清边取封侯，看肘后、黄金印悬如斗。"]'),
('song-ci-484','洞仙歌','丘崈','宋','宋词','song-ci','洞仙歌','[]','江城梅柳，惯得春先处。',105,'宋词/ci.song.10000.json','["江城梅柳，惯得春先处。", "催趁风光上歌舞。", "见九衢、车马流水如龙，喧笑语，罗绮香尘载路。", "欢娱多暇日，尊俎风流，重见承平旧官府。", "有多少、佳丽事，坠珥遗簪，芳径里，瑟瑟珠玑翠羽。", "好惜取、韶华醉连宵，更莫待、收灯酒阑人去。"]'),
('song-ci-485','洞仙歌','丘崈','宋','宋词','song-ci','洞仙歌','[]','□□春□，□画□□处。',105,'宋词/ci.song.10000.json','["□□春□，□画□□处。", "十里红莲照歌舞。", "望鳌山天际，宝篆翻空，看未了，涌出珠宫贝宇。", "锦江桥那畔，罗绮重重，曲巷深坊暗香度。", "玉相辉，花并艳，明月随人，归去也，零落珠玑翠羽。", "先如许、风光更元宵，算却好、图将凤城夸去。"]'),
('song-ci-486','洞仙歌','丘崈','宋','宋词','song-ci','洞仙歌','[]','花中尤物，欲赋无佳句。',105,'宋词/ci.song.10000.json','["花中尤物，欲赋无佳句。", "深染燕脂浅含露。", "被春寒无赖，不放全开，才半吐，翻与留连妙处。", "人间称绝色，倾国倾城，试问太真似花否。", "最娉婷，偏艳冶，百媚千娇，谁道许，须要能歌解舞。", "算费尽、春工到开时，甚却付、连宵等闲风雨。"]'),
('song-ci-487','洞仙歌','丘崈','宋','宋词','song-ci','洞仙歌','[]','丰肌腻体，雅淡仍娇贵。',104,'宋词/ci.song.10000.json','["丰肌腻体，雅淡仍娇贵。", "不与群芳竞姝丽。", "向琼林珠殿，独占春风，仙仗里，曾奉三宫燕喜。", "低回如有恨，失意含羞，乐事繁华竟谁记。", "应怜我，空老去，无句酬伊，吟未就，不觉东风又起。", "镇独立黄昏怯轻寒，这情绪、年年共花憔悴。"]'),
('song-ci-488','沁园春','丘崈','宋','宋词','song-ci','沁园春','[]','雨趣轻寒，风作秋声，燕归雁来。',139,'宋词/ci.song.10000.json','["雨趣轻寒，风作秋声，燕归雁来。", "动天涯羁思，登山临水，惊心节物，极目烟埃。", "客里逢君，才同一笑，何遽言归如此哉。", "别离久，算不应兴尽，却棹船回。", "主人下榻高斋。", "更点检笙歌频宴开。", "便留连不到，迎春见柳，也须小驻，度腊观梅。", "花上盈盈，闺中脉脉，应念胡麻正好栽。", "从教去，正危阑望断，小倚徘徊。"]'),
('song-ci-489','沁园春','丘崈','宋','宋词','song-ci','沁园春','[]','匏系弥年，江北江南，羡君去来。',139,'宋词/ci.song.10000.json','["匏系弥年，江北江南，羡君去来。", "笑山横南浦，朝来爽致，文书堆案，胸次生埃。", "放旷如君，拘縻如我，试问人生谁乐哉。", "真难学，是得留且住，欲去须回。", "何时竹屋茅斋。", "去相傍为邻三径开。", "撰小窗临水，危亭当巘，随宜有竹，著处须梅。", "坐读黄庭，手援紫藟，一寸丹田时自栽。", "当馀暇，更与君来往，林下徘徊。"]'),
('song-ci-490','千秋岁','丘崈','宋','宋词','song-ci','千秋岁','[]','梅妆竹外。',87,'宋词/ci.song.10000.json','["梅妆竹外。", "未洗唇红退。", "酥脸腻，檀心碎。", "临溪闲自照，爱雪春犹带。", "沙路晓，亭亭浅立人无对。", "似恨谁能会。", "迟见江头盖。", "和鼎事，终应在。", "落残知未免，韵胜何曾改。", "牵醉梦，随香欲渡三山海。"]'),
('song-ci-491','千秋岁','丘崈','宋','宋词','song-ci','千秋岁','[]','征鸿天外。',87,'宋词/ci.song.10000.json','["征鸿天外。", "风急惊飞退。", "云彩重，窗声碎。", "初凝铺径絮，渐卷随车带。", "凝望处，巫山秀耸寒相对。", "高卧传都会。", "茅屋倾冠盖。", "空往事，今谁在。", "梅梢春意动，泽国年华改。", "楼上好，与君浩荡浮银海。"]'),
('song-ci-492','千秋岁','丘崈','宋','宋词','song-ci','千秋岁','[]','窥檐窗外。',87,'宋词/ci.song.10000.json','["窥檐窗外。", "酒力冲寒退。", "风絮乱，琼瑶碎。", "凌波争缭绕，点舞相萦带。", "应惬当，凝香燕寝佳人对。", "恰与花时会。", "小阻寻芳盖。", "犹自得，春多在。", "日烘梅柳竞，翠入山林改。", "但只恐，别离恨远如云海。"]'),
('song-ci-493','汉宫春','丘崈','宋','宋词','song-ci','汉宫春','[]','横笛吹梅，记南楼夜月，疏蕊纤枝。',118,'宋词/ci.song.10000.json','["横笛吹梅，记南楼夜月，疏蕊纤枝。", "香尘软红自暖，不怕寒欺。", "人归梦悄，怅凭阑、密约深期。", "身渐老，风流纵在，逢花那似当时。", "东阁占春宜早，甚开迟也似，雪屋疏篱。", "须公彩毫度曲，锦帐题诗。", "多应见我，怪尊前、华发其谁。", "烦道与，巡檐共笑，元是旧日相知。"]'),
('song-ci-494','汉宫春','丘崈','宋','宋词','song-ci','汉宫春','[]','闻说瓢泉，占烟霏空翠，中著精庐。',118,'宋词/ci.song.10000.json','["闻说瓢泉，占烟霏空翠，中著精庐。", "旁连吹台燕榭，人境清殊。", "犹疑未足，称主人、胸次恢疏。", "天自与，相攸佳处，除今禹会应无。", "选胜卧龙东畔，望篷莱对起，岩壑屏如。", "秋风夜凉弄笛，明月邀予。", "三英笑粲，更吴天、不隔莼鲈。", "新度曲，银钩照眼，争看阿素工书。"]'),
('song-ci-495','水龙吟','丘崈','宋','宋词','song-ci','水龙吟','[]','蕊珠仙籍标名，绛纱覆玉云霞里。',124,'宋词/ci.song.10000.json','["蕊珠仙籍标名，绛纱覆玉云霞里。", "銮坡凤掖，丝絇鸣佩，甘泉近侍。", "濯柳临春，饤梨照座，绝尘风味。", "记青蒲、夜半论兵，万人惊诵回天意。", "麟组遥临万里。", "谈笑处、江山增丽。", "遐冲坐折，风流馀事，唯应燕喜。", "新筑沙堤，暂占熊梦，恰经长至。", "过佳辰献寿，双旌便好，作朝天计。"]'),
('song-ci-496','念奴娇','丘崈','宋','宋词','song-ci','念奴娇','[]','烛花渐暗，似梦来非梦，今夕何夕。',120,'宋词/ci.song.10000.json','["烛花渐暗，似梦来非梦，今夕何夕。", "帘幕生香人醉里，家住深深密密。", "松客难为，独留无计，此意谁知得。", "相看无语，可怜心绪如织。", "缓辔踏月归来，空馀襟袖，有多情脂泽。", "浅笑轻颦追想处，眼底如今历历。", "著意新词，於人好语，过后应难必。", "今宵酒醒，断肠人正愁寂。"]'),
('song-ci-497','扑蝴蝶','丘崈','宋','宋词','song-ci','扑蝴蝶','[]','鸣鸠乳燕。',92,'宋词/ci.song.10000.json','["鸣鸠乳燕。", "春在梨花院。", "重门镇掩。", "沈沈帘不卷。", "纱窗红日三竿，睡鸭馀香一线。", "佳眠悄无人唤。", "谩消遣。", "行云无定，楚雨难凭梦魂断。", "清明渐近，天涯人正远。", "尽教闲了秋千，觑著海棠开遍。", "难禁旧愁新怨。"]'),
('song-ci-498','祝英台・祝英台近','丘崈','宋','宋词','song-ci','祝英台・祝英台近','[]','聚春工，开绝艳，天巧信无比。',95,'宋词/ci.song.10000.json','["聚春工，开绝艳，天巧信无比。", "旧日京华，应也只如此。", "等闲一尺娇红，燕脂微点，宛然印、昭阳玉指。", "最好是。", "乐岁台府官闲，风流剩欢意。", "痛饮连宵，花也为人醉。", "可堪银烛烧残，红妆归去，任春在、宝钗云髻。"]'),
('song-ci-499','江城梅花引','丘崈','宋','宋词','song-ci','江城梅花引','["\u897f\u6e56"]','轻煤一曲染霜纨。',110,'宋词/ci.song.10000.json','["轻煤一曲染霜纨。", "小屏山。", "有无间。", "宛是西湖，雪后未晴天。", "水外几家篱落晚，半开关。", "有梅花、傲峭寒。", "渐看。", "渐远。", "水弥漫。", "小舟轻，去又还。", "野桥断岸，隐萧寺、□出晴峦。", "忆得孤山，山下竹溪前。", "佳致不妨随处有，小窗闲，与词人、伴醉眠。"]'),
('song-ci-500','西河','丘崈','宋','宋词','song-ci','西河','[]','清似水。',125,'宋词/ci.song.10000.json','["清似水。", "不了眼中供泪。", "今宵忍听唱阳关，暮云千里。", "可堪客里送行人，家山空老春荠。", "道别去、如许易。", "离合定非人意。", "几年回首望龙门，近才御李。", "也知追诏有来时，匆匆今见归骑。", "整弓刀，徒御喜。", "举离觞、饮釂无味。", "端的慰人愁悴。", "想天心，注倚方深，应是日日传宣公来未。"]'),
('song-ci-501','夜合花','丘崈','宋','宋词','song-ci','夜合花','[]','雨过凉生，风来香远，柳塘池馆清幽。',122,'宋词/ci.song.10000.json','["雨过凉生，风来香远，柳塘池馆清幽。", "圆荷万柄，芙蓉困倚轻柔。", "暮霞映，日初收。", "更满意、绿密红稠。", "是牵情处，低回照影，特地娇羞。", "惆怅好景难酬。", "慰家山梦绕，十顷新秋。", "庭空吏散，依然兴在沧州。", "未容短棹轻舟。", "谩赢得、终日迟留。", "笑空归去，篮舆路转，月上西楼。"]'),
('song-ci-502','垂丝钓','丘崈','宋','宋词','song-ci','垂丝钓','[]','夕烽戍鼓。',81,'宋词/ci.song.10000.json','["夕烽戍鼓。", "悲凉江岸淮浦。", "雾隐孤城，水荒沙聚。", "人共语。", "尽向来胜处。", "谩怀古。", "问柳津花渡。", "露桥夜月，吹箫人在何许。", "缭嫱望篽。", "粉黛成黄土。", "惟有江东注。", "都无虏。", "似旧时得否。"]'),
('song-ci-503','黄河清','丘崈','宋','宋词','song-ci','黄河清','[]','鼓角清雄占云祲。',120,'宋词/ci.song.10000.json','["鼓角清雄占云祲。", "喜边尘、今度还静。", "一线乍添，长觉皇州日永。", "楼外崇牙影转，拥千骑、欢声万井。", "太平官府人初见，梦熊三占佳景。", "皇恩夜出天闱，云章粲、凤鸾飞动相映。", "宝带万钉，与作今朝佳庆。", "勋业如斯得也，况整顿、江淮大定。", "这回恰好，归朝去、共调金鼎。"]'),
('song-ci-504','蓦山溪','丘崈','宋','宋词','song-ci','蓦山溪','[]','风传芳信，晓色便清霁。',102,'宋词/ci.song.10000.json','["风传芳信，晓色便清霁。", "帘幕护春寒，篆香温、笙簧韵美。", "使华容与，星动帝王州，花上脸，柳边眉，竞报占熊喜。", "欢娱好是，玉塞无尘起。", "鞭计小迟留，要长折、遐冲万里。", "传闻有诏，宣室待归来，醽醁满，叵罗深，莫负春葱指。"]'),
('song-ci-505','鹧鸪天','丘崈','宋','宋词','song-ci','鹧鸪天','[]','怀抱环奇懒叩阍。',64,'宋词/ci.song.10000.json','["怀抱环奇懒叩阍。", "朝阳独赋远人村。", "即看飞下芝封诏，会见趣归金马门。", "今夕饮，拼濡裙。", "一时尊俎尽诗人。", "唯馀阿买真才劣，醉后犹能写八分。"]'),
('song-ci-506','鹧鸪天','丘崈','宋','宋词','song-ci','鹧鸪天','[]','陆海蓬壶自有山。',64,'宋词/ci.song.10000.json','["陆海蓬壶自有山。", "光风霁月未应悭。", "但将歌舞酬佳节，却信阴晴是等闲。", "花照夜，烛烘盘。", "明年公更酒肠宽。", "奉陪黄伞传柑宴，莫望红妆拥座欢。"]'),
('song-ci-507','鹧鸪天','丘崈','宋','宋词','song-ci','鹧鸪天','[]','准拟关门度一秋。',64,'宋词/ci.song.10000.json','["准拟关门度一秋。", "强扶衰病起相酬。", "不辞酩酊还吹帽，自笑鬅鬙怯露头。", "江日晚，更迟留。", "争传五马足风流。", "论车载酒浑闲事，著笼藏花说未休。"]'),
('song-ci-508','鹧鸪天','丘崈','宋','宋词','song-ci','鹧鸪天','[]','两两维舟近柳堤。',64,'宋词/ci.song.10000.json','["两两维舟近柳堤。", "菱歌迤逦过前溪。", "曲中自诉衷肠事，岸上行人那得知。", "金齿屐，翠云篦。", "女萝为带蕙为衣。", "惜花贪折归时晚，急桨相呼入翠微。"]'),
('song-ci-509','鹧鸪天','丘崈','宋','宋词','song-ci','鹧鸪天','[]','玳瑁宴中见绿珠。',64,'宋词/ci.song.10000.json','["玳瑁宴中见绿珠。", "淡然高韵胜施朱。", "揉兰雾縠蔷薇浅，半露冰肌玉不如。", "餐秀色，味肤腴。", "轻红端合与为奴。", "只愁宴罢翻成恨，赢得偏怜不似初。"]'),
('song-ci-510','夜行船','丘崈','宋','宋词','song-ci','夜行船','[]','水满平湖香满路。',68,'宋词/ci.song.10000.json','["水满平湖香满路。", "绕重城、藕花无数。", "小艇红妆，疏帘轻盖，烟柳画桥斜渡。", "恣乐追凉忘日暮。", "箫鼓动、月明人去。", "犹有清歌，随风迢递，声在芰荷深处。"]'),
('song-ci-511','夜行船','丘崈','宋','宋词','song-ci','夜行船','[]','一舸鸱夷云水路。',68,'宋词/ci.song.10000.json','["一舸鸱夷云水路。", "贪游戏、悄忘尘数。", "明月长随，清风满载，那向急流争渡。", "邂逅占星来已暮。", "芝封待、却催归处。", "倚玉蒹葭，论文尊俎，回首笑谈何处。"]'),
('song-ci-512','夜行船','丘崈','宋','宋词','song-ci','夜行船','[]','飞舄朝天云作路。',68,'宋词/ci.song.10000.json','["飞舄朝天云作路。", "长安近、更无程数。", "梧竹当年，丝纶弈世，咫尺凤池平渡。", "青眼相逢何太暮。", "眉黄透、却愁君去。", "官事无多，丰年有暇，莫负赏心佳处。"]'),
('song-ci-513','夜行船','丘崈','宋','宋词','song-ci','夜行船','[]','万柄荷花红绕路。',68,'宋词/ci.song.10000.json','["万柄荷花红绕路。", "锦连空、望无层数。", "照水旌旗，临风鼓吹，行遍月桥烟渡。", "堪笑年华今已暮。", "身西上、梦魂东去。", "一曲亭边，五云门外，犹记最花多处。"]'),
('song-ci-514','临江仙','丘崈','宋','宋词','song-ci','临江仙','[]','天上玉卮称万寿，人间湛露初匀。',70,'宋词/ci.song.10000.json','["天上玉卮称万寿，人间湛露初匀。", "种萱堂上阅青春。", "薰风频送喜，同日拜丝纶。", "班在蕊珠仙缀立，等闲历遍燕秦。", "紫皇先付与佳名。", "宜家更宜国，宜子又宜孙。"]'),
('song-ci-515','感皇恩','丘崈','宋','宋词','song-ci','感皇恩','[]','时节近中秋，桂花天气。',81,'宋词/ci.song.10000.json','["时节近中秋，桂花天气。", "忆得熊罴梦呈瑞。", "向来三度，恨被一官萦系。", "今朝称寿，也休辞醉。", "斑衣戏彩，薄罗初试。", "华发双亲剩欢喜。", "功名荣贵，未要匆匆深计。", "一杯先要祝，千百岁。"]'),
('song-ci-516','蝶恋花','丘崈','宋','宋词','song-ci','蝶恋花','[]','梅子著花当献寿。',70,'宋词/ci.song.10000.json','["梅子著花当献寿。", "得得天工，有意还知否。", "教在岁寒双雪后。", "长年不羡松筠茂。", "莫厌杯深歌舞奏。", "约略丝纶，正是来时候。", "富贵明年公自有。", "天香公烛黄封酒。"]'),
('song-ci-517','蝶恋花','丘崈','宋','宋词','song-ci','蝶恋花','[]','鼓吹东方天欲晓。',70,'宋词/ci.song.10000.json','["鼓吹东方天欲晓。", "打彻伊州，梅柳都开了。", "尽道鄞江春许早。", "使君未到春先到。", "号令只凭花信报。", "旗垒精明，家世临淮妙。", "遥想明年元夕好。", "玉人更著华灯照。"]'),
('song-ci-518','蝶恋花','丘崈','宋','宋词','song-ci','蝶恋花','[]','逼砌筠窗围小院。',70,'宋词/ci.song.10000.json','["逼砌筠窗围小院。", "日照花枝，疏影重重见。", "金鸭无风香自暖。", "腊寒才比春寒浅。", "画景温温烘笔砚。", "闲把安西，六纸都临遍。", "茗碗不禁幽梦远。", "鹊来唤起斜阳晚。"]'),
('song-ci-519','一翦梅','丘崈','宋','宋词','song-ci','一翦梅','[]','潇洒佳人淡淡妆。',72,'宋词/ci.song.10000.json','["潇洒佳人淡淡妆。", "特地凌寒，秀出孤芳。", "雪为肌体练为裳。", "韵处天姿，不御铅黄。", "古样铜壶湿篆章。", "浅浸横斜，净几明窗。", "何妨三弄点苔苍。", "但有疏枝，依旧清香。"]'),
('song-ci-520','天仙子','丘崈','宋','宋词','song-ci','天仙子','[]','畏暑只嫌秋较晚。',80,'宋词/ci.song.10000.json','["畏暑只嫌秋较晚。", "不道玉楼人渐远。", "此情那解却清凉，肠欲断。", "愁无限。", "安得冰壶还照眼。", "妙舞蹁跹歌宛转。", "走遍京华何处见。", "清眠无梦到西州，馀香浅。", "银钩软。", "唯仗锦书聊自遣。"]'),
('song-ci-521','朝中措','丘崈','宋','宋词','song-ci','朝中措','[]','晚风斜日折梅花。',57,'宋词/ci.song.10000.json','["晚风斜日折梅花。", "楼外卷残霞。", "领略一城春气，华灯十万人家。", "轻衫短帽，风前趁马，月下随车。", "道个小来脚定，那人笑隔笼纱。"]'),
('song-ci-522','朝中措','丘崈','宋','宋词','song-ci','朝中措','[]','几回相与叹高才。',57,'宋词/ci.song.10000.json','["几回相与叹高才。", "忽报驭风来。", "谁道亟朝天阕，更能同上春台。", "主人早晚，班联玉笋，行听连催。", "湖上饱赓新唱，思堂快泻深杯。"]'),
('song-ci-523','朝中措','丘崈','宋','宋词','song-ci','朝中措','[]','尊前宾主角多才。',57,'宋词/ci.song.10000.json','["尊前宾主角多才。", "亦许我同来。", "诗思竞翻三峡，酒狂欲拗连台。", "身闲有限，莫辞光景，刻烛相催。", "沙路即看联辔，上林趁赏流杯。"]'),
('song-ci-524','菩萨蛮','丘崈','宋','宋词','song-ci','菩萨蛮','[]','壶边击断歌无节。',52,'宋词/ci.song.10000.json','["壶边击断歌无节。", "山川一带伤情切。", "依旧石头城。", "夕阳天外明。", "行人谁是侣。", "遗唱今何许。", "对酒转愁多。", "愁多奈酒何。"]'),
('song-ci-525','菩萨蛮','丘崈','宋','宋词','song-ci','菩萨蛮','[]','秋声夜到秋香园。',52,'宋词/ci.song.10000.json','["秋声夜到秋香园。", "重帘拭卷都开遍。", "只似旧时香。", "更添些子黄。", "绮窗人共赋。", "犹忆分香句。", "别后几回秋。", "见花空复愁。"]'),
('song-ci-526','菩萨蛮','丘崈','宋','宋词','song-ci','菩萨蛮','[]','云林带水山横阁。',52,'宋词/ci.song.10000.json','["云林带水山横阁。", "故人去尽添萧索。", "反照射微茫。", "临分愁夕阳。", "传柑当令节。", "连璧朝天阕。", "还有雁西飞。", "慰人新别离。"]'),
('song-ci-527','西江月','丘崈','宋','宋词','song-ci','西江月','[]','恰好轻篷短棹，绝胜锦缆牙樯。',58,'宋词/ci.song.10000.json','["恰好轻篷短棹，绝胜锦缆牙樯。", "一声横笛起微茫。", "十里红莲步障。", "小待山头吐月，何妨说剑杯长。", "更看风露洗湖光。", "水底金盘滉漾。"]'),
('song-ci-528','西江月','丘崈','宋','宋词','song-ci','西江月','[]','明日又还重九，黄昏小雨疏风。',58,'宋词/ci.song.10000.json','["明日又还重九，黄昏小雨疏风。", "菊英萸糁一尊同。", "付与今宵号梦。", "寒意梧桐叶上，客愁画角声中。", "小楼何日却从容。", "千里此情应共。"]'),
('song-ci-529','梅弄影','丘崈','宋','宋词','song-ci','梅弄影','[]','雨晴风定。',58,'宋词/ci.song.10000.json','["雨晴风定。", "一任春寒逞。", "要勒群芳未醒。", "不废梅花，晚来妆面靓。", "曲阑斜凭。", "水栏临清镜。", "翠竹箫骚相映。", "付与幽人，巡池看弄影。"]'),
('song-ci-530','诉衷情','丘崈','宋','宋词','song-ci','诉衷情','[]','东风罨岸进船难。',54,'宋词/ci.song.10000.json','["东风罨岸进船难。", "酒醒篆香残。", "不堪客里无绪，那更晚来寒。", "思往事，耿无眠。", "掩屏山。", "夜深人静，何处一声，月子弯弯。"]'),
('song-ci-531','诉衷情','丘崈','宋','宋词','song-ci','诉衷情','[]','素衣苍狗不成妍。',54,'宋词/ci.song.10000.json','["素衣苍狗不成妍。", "何意妒蝉娟。", "不知高处难掩，终自十分圆。", "涵万象，独当天。", "照无边。", "乾坤呈露，何况人间，大地山川。"]'),
('song-ci-532','诉衷情','丘崈','宋','宋词','song-ci','诉衷情','[]','芙蓉深径小肩舆。',54,'宋词/ci.song.10000.json','["芙蓉深径小肩舆。", "相并语徐徐。", "红妆著处迎笑，遮路索踟蹰。", "锦步障，绣储胥。", "绕重湖。", "更添月照，人面花枝，疑在蓬壶。"]'),
('song-ci-533','诉衷情','丘崈','宋','宋词','song-ci','诉衷情','[]','十分风味似诗人。',55,'宋词/ci.song.10000.json','["十分风味似诗人。", "有些子太清生。", "只应最嫌俗子，消瘦却盈盈。", "风乍静，雪初晴。", "月微明。", "泊然疏淡，莫是无情，作个关情。"]'),
('song-ci-534','锦帐春','丘崈','宋','宋词','song-ci','锦帐春','[]','翠竹如屏，浅山如画。',70,'宋词/ci.song.10000.json','["翠竹如屏，浅山如画。", "小池面、危桥一跨。", "著棕亭临水，宛然郊野。", "竹篱茅舍。", "好是天寒，倍添幽雅。", "正雪意、垂垂欲下。", "更朦胧月影，弄明初夜。", "梅花动也。"]'),
('song-ci-535','谒金门','丘崈','宋','宋词','song-ci','谒金门','[]','风又雨。',53,'宋词/ci.song.10000.json','["风又雨。", "吹面落花红舞。", "把酒不禁春思苦。", "别离闻杜宇。", "叠嶂楼头佳处。", "犹想襞笺容与。", "思入云山便好语。", "莫辞频寄取。"]'),
('song-ci-536','谒金门','丘崈','宋','宋词','song-ci','谒金门','[]','槐阴绿。',53,'宋词/ci.song.10000.json','["槐阴绿。", "帘卷翠屏山曲。", "照眼冰壶寒并玉。", "赐衣便雾縠。", "熊梦又惊初卜。", "好在掖垣梧竹。", "应讶人归犹未速。", "已颁新诏墨。"]'),
('song-ci-537','谒金门','丘崈','宋','宋词','song-ci','谒金门','[]','罗袖薄。',53,'宋词/ci.song.10000.json','["罗袖薄。", "玉臂镂花金约。", "起晚欠伸莲步弱。", "倚床娇韵恶。", "独自青楼珠箔。", "怎向日长花落。", "门掩东风春寂寞。", "误人瞋喜鹊。"]'),
('song-ci-538','谒金门','丘崈','宋','宋词','song-ci','谒金门','[]','花雨润。',53,'宋词/ci.song.10000.json','["花雨润。", "烟锁玉炉香韵。", "笑度华年春不尽。", "寿觞寒食近。", "甲子才周一瞬。", "争羡珠颜青鬓。", "咫尺朝元仙路稳。", "碧云新有信。"]'),
('song-ci-539','好事近','丘崈','宋','宋词','song-ci','好事近','[]','空涧落鸣泉，千骑雨霖衣铁。',53,'宋词/ci.song.10000.json','["空涧落鸣泉，千骑雨霖衣铁。", "金奏欲终人醉，有玉声清越。", "夜深纤手怯轻寒，馀韵寄愁绝。", "玉树梦回何处，但满庭霜月。"]'),
('song-ci-540','好事近','丘崈','宋','宋词','song-ci','好事近','[]','整整一冬晴，雨后不论朝夕。',53,'宋词/ci.song.10000.json','["整整一冬晴，雨后不论朝夕。", "麦陇救得一半，莫妨他寒食。", "试看天气定乘除，宽更待三日。", "桃李且须宁耐，有无边春色。"]'),
('song-ci-541','浣溪沙','丘崈','宋','宋词','song-ci','浣溪沙','[]','铁锁星桥永夜通。',48,'宋词/ci.song.10000.json','["铁锁星桥永夜通。", "万家帘幕度香风。", "俊游人在笑声中。", "罗绮十行眉黛绿，银花千炬簇莲红。", "座中争看黑头公。"]'),
('song-ci-542','浣溪沙','丘崈','宋','宋词','song-ci','浣溪沙','[]','胜子幡儿袅鬓云。',48,'宋词/ci.song.10000.json','["胜子幡儿袅鬓云。", "钗头绝唱旧曾闻。", "江城喜见又班春。", "拂柳和风初有信，欺梅残雪已无痕。", "只应笑语作春温。"]'),
('song-ci-543','浪淘沙','丘崈','宋','宋词','song-ci','浪淘沙','[]','潇洒无湖仙。',64,'宋词/ci.song.10000.json','["潇洒无湖仙。", "踏遍尘寰。", "吟哦长忆两松闲。", "邂逅天涯还一笑，璧合珠连。", "风采照衰残。", "妙语冷然。", "妓围香暖簇金蝉。", "端为故人情未减，醉玉颓山。"]'),
('song-ci-544','定风波','丘崈','宋','宋词','song-ci','定风波','[]','月殿移根入帝乡。',73,'宋词/ci.song.10000.json','["月殿移根入帝乡。", "风流犹是旧时妆。", "猩血染成丹杏脸。", "浓点。", "郁金笼就赭衣黄。", "浪说锦城元自少。", "不道。", "只今何啻五枝芳。", "试问司花谁是主。", "传语。", "且烦都与十分香。"]'),
('song-ci-545','卜算子','丘崈','宋','宋词','song-ci','卜算子','[]','翠被怯轻寒，花气撩幽梦。',52,'宋词/ci.song.10000.json','["翠被怯轻寒，花气撩幽梦。", "梦蹑飞云驾彩鸾，惊觉花枝动。", "宿酒未全醒，屋角闻晴哢。", "爱著荼シ彻骨香，嗅了还重□。"]'),
('song-ci-546','柳梢青','丘崈','宋','宋词','song-ci','柳梢青','[]','风佩珊珊。',61,'宋词/ci.song.10000.json','["风佩珊珊。", "云屏曲曲，愁绝春悭。", "无奈馀寒。", "半醒宿酒，御夹成单。", "深沈院落人闲。", "凭阑处、眉颦黛残。", "彩笔慵拈。", "新声微度，兴入云山。"]'),
('song-ci-547','点绛唇','丘崈','宋','宋词','song-ci','点绛唇','[]','花落花开，等闲不管流年度。',50,'宋词/ci.song.10000.json','["花落花开，等闲不管流年度。", "旧游何处。", "浅立空凝伫。", "惊拍栏干，忍见春将暮。", "凭风絮。", "为人飞去。", "散作愁无数。"]'),
('song-ci-548','醉花阴','丘崈','宋','宋词','song-ci','醉花阴','[]','碧玉槎桠金粟小。',62,'宋词/ci.song.10000.json','["碧玉槎桠金粟小。", "山路惊秋老。", "倒倚湿寒烟，似怯秋风，阁泪啼清晓。", "铜壶冷浸宜深窈。", "人试新妆巧。", "云鬓一枝斜，小阁幽窗，是处都香了。"]'),
('song-ci-549','愁倚阑・春光好','丘崈','宋','宋词','song-ci','愁倚阑・春光好','[]','风雨骤，妒花黄。',52,'宋词/ci.song.10000.json','["风雨骤，妒花黄。", "忽斜阳。", "急手打开君会否，是伊凉。", "深深密密传觞。", "似差胜、落帽清狂。", "满引休辞还醉倒，却何妨。"]'),
('song-ci-550','如梦令','丘崈','宋','宋词','song-ci','如梦令','[]','门外绮罗入绣。',40,'宋词/ci.song.10000.json','["门外绮罗入绣。", "堂上华灯入昼。", "领略一番春，共醉连宵歌酒。", "今后。", "今后。", "如此遨头少有。"]'),
('song-ci-551','如梦令','丘崈','宋','宋词','song-ci','如梦令','[]','小小峰峦对起。',40,'宋词/ci.song.10000.json','["小小峰峦对起。", "芳树重重相倚。", "清溜绕阶除，聊备一池春水。", "游戏。", "游戏。", "适意随缘足矣。"]'),
('song-ci-552','太常引','丘崈','宋','宋词','song-ci','太常引','[]','憎人虎豹守天关。',62,'宋词/ci.song.10000.json','["憎人虎豹守天关。", "嗟蜀道、十分难。", "说与沐猴冠。", "这富贵、於人怎谩。", "忘形尊俎，能言桃李，日日在东山。", "不醉有馀欢。", "唱好个、风流谢安。"]'),
('song-ci-553','南歌子','朱晞颜','宋','宋词','song-ci','南歌子','[]','影落三秋月，寒生六月霜。',62,'宋词/ci.song.10000.json','["影落三秋月，寒生六月霜。", "是谁幻出玉篔筜。", "乞与一枝和雪、钓漓湘。", "劲节依琳馆，虚心漏草堂。", "笔端元自有雌黄。", "疑是化龙蜚到、葛仙旁。"]'),
('song-ci-554','沁园春','吕胜己','宋','宋词','song-ci','沁园春','[]','月晃西窗，风掀斗帐，晓来梦回。',140,'宋词/ci.song.10000.json','["月晃西窗，风掀斗帐，晓来梦回。", "见满川惊鹭，长空瑞鹤，联翩来下，翔舞徘徊。", "旋放金磐承积块，更轻撼琼壶撩冻澌。", "毡帏小，近宝炉兽炭，沈水兰煤。", "寒威。", "酒力相欺。", "荐绿蚁霜螯左右持。", "问岁岁祯祥，如何中断，年年梅月，因甚愆期。", "上绀碧楼，城高百尺，看白玉虬龙奔四围。", "纷争罢，正残鳞败甲，天上交飞。"]'),
('song-ci-555','醉桃源・阮郎归','吕胜己','宋','宋词','song-ci','醉桃源・阮郎归','[]','山翁可是爱登台。',56,'宋词/ci.song.10000.json','["山翁可是爱登台。", "看云日几回。", "恨无语似谪仙才。", "空教云去来。", "思往事，引深杯。", "长歌感壮怀。", "霜风晚下扫阴霾。", "天心宝鉴开。"]'),
('song-ci-556','醉桃源・阮郎归','吕胜己','宋','宋词','song-ci','醉桃源・阮郎归','[]','马蹄西路赏春妍。',56,'宋词/ci.song.10000.json','["马蹄西路赏春妍。", "重来十五年。", "好山如带水如环。", "红楼罨画闲。", "人易老，景如前。", "停杯俯逝川。", "归舟回首望云烟。", "秦人隔洞天。"]'),
('song-ci-557','醉桃源・阮郎归','吕胜己','宋','宋词','song-ci','醉桃源・阮郎归','[]','去年手种十株梅。',56,'宋词/ci.song.10000.json','["去年手种十株梅。", "而今犹未开。", "山翁一日走千迥。", "今朝蝶也来。", "高树杪，暗香微。", "悭香越恼怀。", "更烧银烛引春回。", "英英露粉腮。"]'),
('song-ci-558','蝶恋花','吕胜己','宋','宋词','song-ci','蝶恋花','["\u897f\u6e56"]','墙角栽梅分两下。',70,'宋词/ci.song.10000.json','["墙角栽梅分两下。", "夹竹穿松，巧傍柴门亚。", "不似西湖明月夜。", "展开一片江南画。", "老子寻芳心已罢。", "为爱孤高，结约如莲社。", "清静界中观物化。", "憧憧门外驰车马。"]'),
('song-ci-559','蝶恋花','吕胜己','宋','宋词','song-ci','蝶恋花','[]','天际行云红一缕。',70,'宋词/ci.song.10000.json','["天际行云红一缕。", "无尽青山，江水悠悠去。", "更上层楼凭远处。", "凄凉今古悲三楚。", "心事多端谁共语。", "酒醒愁来，望望家何所。", "薄宦漂零成久旅。", "天涯却羡鸿遵渚。"]'),
('song-ci-560','蝶恋花','吕胜己','宋','宋词','song-ci','蝶恋花','[]','姑射真仙蓬海会。',70,'宋词/ci.song.10000.json','["姑射真仙蓬海会。", "驭气乘龙，作意游方外。", "冬后翦花飞素彩。", "腊前陨璞抛团块。", "幂幂锦云相映带。", "川谷林峦，混一乾坤大。", "白玉装成全世界。", "江湖点染微瑕颣。"]'),
('song-ci-561','蝶恋花','吕胜己','宋','宋词','song-ci','蝶恋花','[]','屈指瓜期犹渺渺。',70,'宋词/ci.song.10000.json','["屈指瓜期犹渺渺。", "羡子征鞍，去上长安道。", "到得故园春正好。", "桃腮杏脸迎门笑。", "闻道难兄登显要。", "雁子云宵，花萼应同调。", "旧恨新愁须拼了。", "功名趁取方年少。"]'),
('song-ci-562','蝶恋花','吕胜己','宋','宋词','song-ci','蝶恋花','[]','眼约心期常未足。',70,'宋词/ci.song.10000.json','["眼约心期常未足。", "邂逅今朝，暂得论心曲。", "忽堕鲛珠红簌簌。", "双眸翦水明如烛。", "可恨匆匆归去速。", "去去行云，望断凄心目。", "何似当初情未熟。", "免教添得愁千斛。"]'),
('song-ci-563','蝶恋花','吕胜己','宋','宋词','song-ci','蝶恋花','[]','天色沈沈云色赭。',70,'宋词/ci.song.10000.json','["天色沈沈云色赭。", "风扰阴寒，浩荡吹平野。", "万斛珠玑天弃舍。", "长空撒下鸣鸳瓦。", "玉女凝愁金阕下。", "褪粉残妆，和泪轻挥洒。", "欲降尘凡飙驭驾。", "翩翩白凤先来也。"]'),
('song-ci-564','长相思','吕胜己','宋','宋词','song-ci','长相思','[]','体夭夭。',44,'宋词/ci.song.10000.json','["体夭夭。", "步飘飘。", "绶带金泥缕绛绡。", "珑璁趁步摇。", "浅霞消。", "两峰遥。", "斜插层楼金系腰。", "花羞人面娇。"]'),
('song-ci-565','长相思','吕胜己','宋','宋词','song-ci','长相思','[]','展颦蛾。',44,'宋词/ci.song.10000.json','["展颦蛾。", "抹流波。", "并插玲珑碧玉梭。", "松分两髻螺。", "晓霜和。", "冻轻呵。", "拍罢阳春白雪歌。", "偎人春意多。"]'),
('song-ci-566','长相思','吕胜己','宋','宋词','song-ci','长相思','[]','冒寒吹。',44,'宋词/ci.song.10000.json','["冒寒吹。", "访琼姬。", "行到青山遇玉肌。", "凝情欲待谁。", "山疏篱。", "手同携。", "踏月随香清夜归。", "乘欢拨冻醅。"]'),
('song-ci-567','浣溪沙','吕胜己','宋','宋词','song-ci','浣溪沙','[]','浅著铅华素净妆。',48,'宋词/ci.song.10000.json','["浅著铅华素净妆。", "翩跹翠袖拂云裳。", "傍人作意捧金觞。", "曲度清悲云冉冉，花飞零乱月茫茫。", "梦回人去似高唐。"]'),
('song-ci-568','浣溪沙','吕胜己','宋','宋词','song-ci','浣溪沙','[]','直系腰围鹤间霞。',48,'宋词/ci.song.10000.json','["直系腰围鹤间霞。", "双垂项帕凤穿花。", "新妆全学内人家。", "惠性芳心谁得似，饶嗔□恶也还他。", "只消凡事与饶些。"]'),
('song-ci-569','清平乐','吕胜己','宋','宋词','song-ci','清平乐','[]','红尘久住。',54,'宋词/ci.song.10000.json','["红尘久住。", "仙驭凌波去。", "本似行云无定处。", "那更腊残风雨。", "瑶芳片片轻飞。", "但留青子栾枝。", "孤负岁寒幽意，如今却与春宜。"]'),
('song-ci-570','清平乐','吕胜己','宋','宋词','song-ci','清平乐','[]','灵心暗属。',54,'宋词/ci.song.10000.json','["灵心暗属。", "髻垒黄金粟。", "寂静虚堂情不足。", "微步徘徊山麓。", "蕊珠宫里新妆。", "生香全似瑶芳。", "应为莺花留恋，人间暂歇鸾凤。"]'),
('song-ci-571','促拍满路花','吕胜己','宋','宋词','song-ci','促拍满路花','[]','名花无影迹，寒气日凄凉。',102,'宋词/ci.song.10000.json','["名花无影迹，寒气日凄凉。", "人间千万树，歇芬芳。", "紫微宫女，仙驭降霓裳。", "名在仙班簿，不属尘凡，洞天密锁云窗。", "遗珰连宝珥，人间识天香。", "凝寒承雨露，傲冰霜。", "凌仙仙子，邂逅水云乡。", "更约南枝友，游遍江南，共归三岛扶桑。"]');
